import React, { useMemo, useState, useEffect, useRef, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";

// ── UI primitives ─────────────────────────────────────────────────────────────
function Card({ className = "", children }) {
  return <div className={`rounded-[28px] border ${className}`}>{children}</div>;
}
function CardContent({ className = "", children }) {
  return <div className={className}>{children}</div>;
}
function Progress({ value = 0, color = "bg-blue-500", height = "h-2" }) {
  return (
    <div className={`w-full overflow-hidden rounded-full bg-slate-200 ${height}`}>
      <motion.div
        className={`h-full ${color} rounded-full`}
        animate={{ width: `${Math.max(0, Math.min(100, value))}%` }}
        transition={{ duration: 0.4, ease: "easeOut" }}
      />
    </div>
  );
}
function Input({ className = "", ...props }) {
  return (
    <input
      className={`w-full border px-4 py-2.5 rounded-2xl outline-none focus:ring-2 focus:ring-blue-300 text-sm ${className}`}
      {...props}
    />
  );
}

