const QUESTION_BANK = [
  // ── CALM: Kinematics ──────────────────────────────────────────────────────
  q(1001,"Kinematics","calm","Easy",10,"What does forward kinematics compute from a set of joint variables?",["End-effector pose in Cartesian space from joint coordinates.","Required joint torques to maintain a desired end-effector pose.","Optimal joint trajectory that minimises total energy consumption.","Sensor covariance associated with each joint angle reading."],0,"Joints are the input, end-effector pose is the output.","Forward kinematics maps joint angles to the position and orientation of the end effector using a chain of homogeneous transforms.","An industrial arm uses FK every control cycle to know exactly where its gripper is before issuing a new motion command."),
  q(1002,"Kinematics","calm","Easy",10,"Which algebraic property uniquely characterises a valid 3D rotation matrix?",["Columns are mutually orthonormal and determinant equals positive one.","All entries are non-negative and each row sums to exactly one.","The matrix trace equals twice the cosine of the rotation angle.","The matrix is symmetric and all its eigenvalues are positive."],0,"R^T R = I and det(R) = +1 together define SO(3).","A rotation matrix R belongs to SO(3): orthonormal columns preserve lengths and angles, and det(R) = +1 distinguishes proper rotations from reflections.","Camera-to-robot-base calibration verifies estimated rotation matrices satisfy this property before use in any geometric computation."),
  q(1003,"Kinematics","calm","Easy",10,"What four geometric quantities do Denavit-Hartenberg parameters encode per joint?",["Link length, link twist, joint offset, and joint angle.","Link mass, joint stiffness, actuator torque, and link length.","Focal length, joint offset, angular velocity, and damping ratio.","Link twist, gear ratio, sensor gain, and joint angle value."],0,"Two distances and two angles describe one link-joint pair.","DH parameters (a, alpha, d, theta) systematically describe the geometry between consecutive joint frames, enabling a compact transformation chain for any serial manipulator.","KUKA and ABB robot controllers use DH tables to compute forward kinematics from encoder readings in real time."),
  q(1004,"Kinematics","calm","Easy",10,"Why can a 6-DOF robot arm have up to sixteen distinct IK solutions for one end-effector pose?",["Geometric ambiguities at shoulder, elbow, and wrist each allow two valid configurations.","Six joints each independently contribute up to three distinct angle solutions.","The workspace contains sixteen symmetric reachable sub-regions by construction.","Sixteen distinct sign combinations exist across the six joint angle variables."],0,"Elbow-up vs down, wrist-flip vs not — binary choices multiply to 16.","Shoulder, elbow, and wrist joints each present a binary geometric choice; their combinations yield up to 2^3 = 8 or 16 solutions depending on robot geometry.","Industrial robot controllers store a preferred solution branch so the arm never makes unexpected large-angle transitions between programmed moves."),
  q(1005,"Kinematics","calm","Easy",10,"What physical relationship does the manipulator Jacobian matrix encode?",["Instantaneous mapping from joint velocities to end-effector velocity twist.","Static mapping from joint torques to end-effector wrench magnitudes.","Second-order relationship between joint angles and workspace position.","Probabilistic mapping from sensor noise to joint velocity uncertainty."],0,"x_dot = J(q) * q_dot — joint rates produce proportional Cartesian rates.","The Jacobian J(q) linearly relates the joint velocity vector q_dot to the end-effector velocity twist x_dot; its transpose maps Cartesian wrenches back to joint torques.","Real-time velocity controllers compute J(q) every millisecond to convert desired Cartesian velocities into joint commands for smooth motion."),
  q(1006,"Kinematics","calm","Easy",10,"How does a prismatic joint differ kinematically from a revolute joint?",["Prismatic joints produce pure translation along an axis; revolute joints produce pure rotation about an axis.","Prismatic joints rotate about a fixed point; revolute joints translate along a variable axis.","Prismatic joints have bounded travel while revolute joints are always continuous.","Prismatic joints change link twist in DH tables; revolute joints change link length."],0,"One slides, one spins — translation vs rotation is the key difference.","A prismatic joint contributes translation d along its axis in the DH chain; a revolute joint contributes rotation theta about its axis. Both are 1-DOF joints.","SCARA robots combine revolute shoulder and elbow joints with a prismatic vertical axis for fast, precise pick-and-place tasks."),
  q(1007,"Kinematics","calm","Medium",15,"What mathematical condition defines a kinematic singularity in a manipulator?",["The Jacobian loses full row rank, making some Cartesian velocities unachievable.","The inertia matrix becomes diagonal, decoupling all joint dynamics completely.","All joint angles simultaneously reach their mechanical limit boundaries.","The end effector exits the outer boundary of the dexterous workspace."],0,"det(JJ^T) = 0 signals rank loss and lost Cartesian motion directions.","At a singularity, rank(J) drops below the task dimension, meaning some Cartesian directions cannot be generated regardless of how large joint velocities become.","Near a wrist singularity, a tiny Cartesian reorientation command demands unbounded joint rates, causing industrial robots to decelerate or halt automatically."),
  q(1008,"Kinematics","calm","Medium",15,"What distinguishes the dexterous workspace from the reachable workspace?",["Dexterous workspace: all end-effector orientations achievable; reachable: at least one orientation possible.","Dexterous workspace: only high-speed motions are allowed; reachable: all speeds are permitted.","Dexterous workspace: restricted to prismatic joints; reachable: includes all joint types.","Dexterous workspace: excludes only singularities; reachable: excludes only the robot base."],0,"Dexterous means full orientation freedom, not just positional reach.","The reachable workspace contains all positions the end effector can reach in at least one orientation; the dexterous workspace is the subset where every orientation is achievable at each point.","Six-DOF arms are designed so the dexterous workspace fully covers the intended task volume, preventing orientation-limited configurations during assembly."),
  q(1009,"Kinematics","calm","Medium",15,"Which rotation representation avoids the gimbal-lock singularity of Euler angles?",["Unit quaternions, which represent SO(3) on a 3-sphere without coordinate singularities.","Axis-angle vectors, which also develop singularities at rotations of 2-pi radians.","3x3 rotation matrices, which share the same topological issues as Euler angles.","Homogeneous coordinates, which are defined only for pure positional transforms."],0,"Quaternions use four numbers to avoid the three-angle coordinate singularity.","Euler angles lose a degree of freedom when two rotation axes align (gimbal lock). Unit quaternions parameterise SO(3) on S^3 without this topological issue.","Aerospace and UAV flight controllers use quaternion-based attitude estimation to avoid gimbal lock during aggressive manoeuvres at large pitch angles."),
  q(1010,"Kinematics","calm","Medium",15,"Why must composing two rigid-body transforms use 4x4 matrix multiplication rather than addition?",["The second translation must be rotated by the first frame's orientation before being added.","4x4 matrices store more numerical precision than separate 3x4 component matrices.","Addition is mathematically undefined for non-square matrix sub-blocks in general.","The determinant must remain non-zero for all valid rigid transformation matrices."],0,"T1 * T2 rotates the second translation by the first rotation before summing.","The product T1*T2 correctly rotates the translation part of T2 by the rotation of T1 before summing, which component-wise addition fundamentally cannot achieve.","Chaining DH transforms link by link exploits this property to build the complete FK transform as a single matrix product sequence."),
  q(1011,"Kinematics","calm","Medium",15,"What solution does the Jacobian pseudoinverse provide for a redundant manipulator?",["The minimum joint-velocity-norm solution that achieves the desired end-effector velocity.","The maximum payload solution that satisfies all Cartesian velocity constraints.","The unique exact inverse solution at configurations very close to a singularity.","The minimum energy trajectory between two arbitrarily specified end-effector poses."],0,"J-dagger minimises ||q_dot|| among all q_dot satisfying x_dot = J*q_dot.","The Moore-Penrose pseudoinverse J† = J^T(JJ^T)^{-1} provides the minimum-norm joint velocity solution and admits null-space components for secondary task objectives.","7-DOF arms use J† plus null-space gradient projection to avoid joint limits while continuously tracking a Cartesian reference trajectory."),
  q(1012,"Kinematics","calm","Hard",20,"In the product-of-exponentials formulation, what does each exp(xi_hat * theta_i) term represent?",["A full SE(3) rigid-body transform generated by rotating joint i about its screw axis by theta_i.","A local DH approximation linearised about the zero-angle configuration of joint i.","The covariance propagation matrix for joint angle uncertainty at link i.","A diagonal scaling matrix encoding link mass and inertia contributions at joint i."],0,"Each exponential is a complete screw motion — rotation and translation on one axis.","Each exp(xi_hat*theta) is an element of SE(3) derived from the joint's screw axis xi in the world frame at the zero configuration; FK is their ordered product applied to the home transform M.","The POE formula is used in the Lynch-Park Modern Robotics textbook and avoids the frame-assignment conventions required by DH parameters."),
  q(1013,"Kinematics","calm","Hard",20,"What does the null space of the Jacobian physically represent for a redundant robot?",["Joint velocity directions that produce zero end-effector motion and enable internal reconfiguration.","The complete set of singular configurations where the robot loses a degree of freedom.","Joint velocity directions that maximise end-effector speed for a given joint torque budget.","The subspace of all joint angles that exceed their mechanical joint travel limits."],0,"Null(J) contains q_dot vectors that map to zero task-space velocity — invisible to the task.","For n > m DOF, dim(Null(J)) = n - rank(J) > 0; these internal motions reconfigure the robot without disturbing the end-effector pose or velocity.","7-DOF arms like the KUKA LBR iiwa use null-space gradient projection to avoid joint limits and self-collision while holding a fixed end-effector grasp pose."),
  q(1014,"Kinematics","calm","Hard",20,"Why is the Jacobian condition number a more informative manipulability measure than det(J) alone?",["Condition number captures worst-case directional amplification via sigma_max/sigma_min, revealing near-singularities det(J) misses.","Condition number is always exactly one for any non-redundant robot at any configuration.","Condition number applies only to square Jacobians, making it strictly more general than det(J).","Condition number equals the trace of the joint-space inertia matrix at the current pose."],0,"sigma_min approaching zero is the true danger signal — det(J) alone misses directional risk.","det(J) can be small even far from singularity due to unit scaling; sigma_min from SVD directly measures worst-case Cartesian velocity amplification for a unit-norm joint velocity vector.","Trajectory planners for surgical robots minimise the Jacobian condition number to ensure uniform dexterity and prevent erratic motion near singular configurations."),
  q(1015,"Kinematics","calm","Hard",20,"What does Chasles' theorem state about any rigid-body displacement in 3D space?",["Every rigid displacement equals a rotation about and translation along a single screw axis.","Every rigid displacement decomposes uniquely into exactly three sequential Euler rotations.","Every rigid displacement requires exactly six independent scalar parameters to describe.","Screw theory applies only to planar mechanisms and is invalid for spatial rigid bodies."],0,"One screw axis — simultaneous rotation and translation — describes any 3D rigid motion.","Chasles' theorem guarantees that any rigid-body displacement is equivalent to a pure screw: rotation theta about an axis plus translation pitch*theta along that same axis.","The product-of-exponentials FK formula is built directly on this theorem, representing each joint as a screw motion in the world frame."),

  // ── CALM: Control ─────────────────────────────────────────────────────────
  q(1016,"Control","calm","Easy",10,"What specific steady-state problem does the integral term in PID control solve?",["It eliminates persistent tracking error caused by constant disturbances or gravity loads.","It amplifies the derivative signal to improve high-frequency disturbance rejection.","It scales proportional gain dynamically based on the measured system bandwidth.","It predicts future error values ahead of time to reduce motion overshoot."],0,"Integral accumulates error until the constant bias is cancelled exactly — zero steady-state error.","The integral term accumulates tracking error over time, growing until the bias from any constant disturbance or model offset is exactly cancelled, which neither P nor D can achieve alone.","A joint controller without integral action permanently lags its target under gravity loading; adding integral action drives steady-state position error to exactly zero."),
  q(1017,"Control","calm","Easy",10,"What stability information does the Nyquist criterion extract from the open-loop response?",["The number of closed-loop right-half-plane poles, inferred from encirclements of the minus-one point.","The minimum sampling rate required to prevent aliasing in a digital controller implementation.","The maximum achievable PID gains before the actuator enters hard saturation limits.","The closed-loop bandwidth achievable with a specified phase margin design target."],0,"Clockwise encirclements of -1 count unstable closed-loop poles.","The Nyquist criterion counts net clockwise encirclements of the -1 point; zero encirclements for a stable open-loop system means the closed-loop system is also stable.","Loop-shaping control design uses the Nyquist plot alongside Bode plots to verify sufficient gain and phase margins for robust stability."),
  q(1018,"Control","calm","Easy",10,"What does gain margin quantify in a feedback control system?",["The multiplicative factor by which open-loop gain can increase before closed-loop instability.","The maximum joint torque the controller can safely command to its actuator.","The maximum communication delay tolerable before the feedback loop goes unstable.","The ratio of the proportional gain to the derivative gain at the nominal design point."],0,"Gain margin is the safety buffer above gain = 1 at the phase-crossover frequency.","Gain margin = 1/|G(j*omega_pc)| at the frequency where open-loop phase = -180 degrees; a minimum of 6 dB (factor of 2) is a standard robust design target.","Robot force controllers are designed with generous gain margins because unmodelled contact stiffness effectively increases loop gain unpredictably during interaction."),
  q(1019,"Control","calm","Easy",10,"Why do precision robot motion controllers combine feedforward and feedback terms?",["Feedforward cancels predictable dynamics proactively; feedback corrects unpredicted residual errors.","Feedforward eliminates sensors entirely by relying on the system model for state information.","Feedforward increases integral gain to improve steady-state disturbance rejection speed.","Feedforward guarantees global stability independently of all model inaccuracies."],0,"FF handles the known part, FB corrects what the model inevitably missed.","A model-based feedforward (e.g. computed torque from inverse dynamics) reduces the error the feedback loop must correct, permitting lower feedback gains and better stability margins.","High-speed robot welding and CNC controllers use inverse-dynamics feedforward to achieve sub-millimetre path accuracy at fast traverse rates."),
  q(1020,"Control","calm","Easy",10,"Why does PD control produce non-zero steady-state error under a constant gravitational load?",["PD has no integral term to accumulate and cancel the constant torque offset required to hold position.","PD always overshoots more than PID, causing it to settle at a displaced equilibrium.","PD control is inherently unstable whenever any constant gravitational loading is present.","PD cannot track step reference commands unless an additional derivative pre-filter is added."],0,"Constant disturbance demands constant correction — only the integral term provides that.","A constant gravity torque needs a constant correction; the proportional term only provides correction proportional to error, requiring a permanent non-zero position error to sustain the needed corrective torque.","Robot arm joint controllers use gravity compensation feedforward or integral action specifically to eliminate this gravitational sag from their steady-state response."),
  q(1021,"Control","calm","Medium",15,"What causes integral windup and why is it dangerous in robot actuator control?",["Actuator saturation prevents error correction while the integrator keeps accumulating, causing large overshoot on release.","Excessive derivative gain causes the integrator state to grow without any bound.","Integral windup is the desired accumulation of correction action when the robot is near its setpoint.","Measurement noise enters the integral branch, gradually corrupting the accumulated error state."],0,"The actuator is clipped at its limit but the integrator has no idea — it keeps growing.","When the actuator saturates it cannot correct the error; the integrator keeps accumulating, storing a large value that drives the output far past the setpoint once saturation eventually ends.","Anti-windup schemes (clamping or back-calculation) are standard in all industrial robot joint controllers to prevent large position overshoots after the robot starts moving from rest."),
  q(1022,"Control","calm","Medium",15,"In state-space x_dot = Ax + Bu, what does full rank of the controllability matrix imply?",["Every state can be driven to any target value in finite time using the available control input.","All system outputs can be perfectly measured without noise using the available sensors.","The system is asymptotically stable even without any control input being applied.","All eigenvalues of A already lie in the open left half of the complex plane."],0,"Full rank means no state is hidden from the input — the controller has full authority.","If rank([B AB A^2B ...]) = n, every state is reachable from the origin; modes outside the controllability matrix column span cannot be moved by any linear state feedback.","Verifying controllability is the mandatory first step before applying pole placement or LQR design to any robot joint or vehicle dynamics model."),
  q(1023,"Control","calm","Medium",15,"What does Lyapunov's direct method prove about a nonlinear dynamical system?",["Existence of a positive-definite V with V_dot at most zero proves stability without solving ODEs.","Stability of the local linearisation is sufficient to prove global stability of the full nonlinear system.","The method applies only to linear time-invariant systems with constant coefficient matrices.","Stability is guaranteed whenever the largest real eigenvalue of the state matrix A is negative."],0,"V is a generalised energy — if it never increases the system cannot diverge from equilibrium.","V acts as a generalised energy function; V_dot <= 0 ensures trajectories never move to higher-energy regions, proving Lyapunov stability without integrating the differential equations.","Passivity-based controllers for robot manipulators use Lyapunov analysis to prove stability without linearising the full nonlinear coupled dynamics."),
  q(1024,"Control","calm","Medium",15,"What does the separation principle state about linear observer-based control design?",["Observer and controller gains can be independently designed; closed-loop poles are their union.","Separating proportional and derivative gains into two stages always stabilises any plant.","The observer must always be fully designed and validated before any controller design begins.","Integral action must always be placed downstream of the observer in the closed-loop signal path."],0,"Design the observer for estimation, the controller for regulation — completely independently.","For LTI systems, closed-loop eigenvalues equal the union of the controller poles and observer poles, enabling independent Riccati or pole-placement designs for each subsystem.","LQG control (LQR controller + Kalman filter observer) is the canonical application of the separation principle in robotic state estimation and control."),
  q(1025,"Control","calm","Medium",15,"What is the receding-horizon principle that makes MPC a feedback controller despite optimising open-loop?",["Solve a finite-horizon optimisation each step, apply only the first control, then shift and repeat.","Extend the prediction horizon by one step each cycle until the terminal state is reached.","Replace the dynamic model with a direct sensor feedback signal at each new time step.","Use the time-integral of predicted future error as the MPC cost function minimised each step."],0,"Plan ahead, act only on the first step, then replan with fresh state measurements.","MPC solves an open-loop optimal control problem over a horizon at each timestep, executes only the first input, then re-solves with updated state measurements, combining optimality with implicit feedback robustness.","Legged robot MPC controllers replan contact sequences and CoM trajectories at 100-200 Hz using this principle to handle unexpected terrain disturbances in real time."),
  q(1026,"Control","calm","Hard",20,"Why does collocated sensor-actuator placement guarantee passivity and unconditional stability in flexible structures?",["Collocated pairs produce transfer functions with alternating poles and zeros, making the plant passive for any positive gain.","Collocated sensors are intrinsically more accurate than remote sensors at all operating frequencies.","Non-collocated control is unstable only in the high-frequency range above the first resonance mode.","Collocated placement eliminates the need for any model-based feedforward compensation entirely."],0,"Alternating poles and zeros from collocation is the passivity signature — positive gain always stabilises.","A collocated velocity-force pair produces a positive-real (passive) transfer function with alternating pole-zero interlacing, guaranteeing closed-loop stability for any positive gain controller by passivity composition.","Flexible-joint robot arms place joint torque sensors at the motor output to maintain collocation, avoiding the spillover instability that plagues non-collocated flexible structure control."),
  q(1027,"Control","calm","Hard",20,"How does H-infinity control differ from LQR in its fundamental assumption about disturbances?",["H-infinity minimises worst-case L2-bounded disturbance amplification; LQR minimises expected quadratic cost under Gaussian noise.","H-infinity assumes zero disturbances and optimises pure reference tracking performance only.","H-infinity requires full state feedback while LQR can operate exclusively from output measurements.","H-infinity and LQR solve identical Riccati equations that differ only in their cost weighting matrices."],0,"H-inf is a minimax game against the worst-case adversary; LQR is an average-case stochastic problem.","H-infinity minimises the worst-case energy gain from disturbance to output (the H-inf norm of the closed-loop transfer function), treating disturbances adversarially rather than statistically.","Robust force controllers for industrial robots use H-infinity synthesis to handle worst-case contact stiffness variations that LQR-based designs cannot explicitly account for."),
  q(1028,"Control","calm","Hard",20,"In impedance control for physical human-robot interaction, what quantity is directly regulated?",["The dynamic relationship between end-effector displacement and contact force, shaped as a mass-spring-damper.","The absolute Cartesian position of the end effector along a predefined reference trajectory.","The end-effector acceleration profile independently of any applied external contact forces.","The time-integral of contact force to limit cumulative mechanical energy transfer to humans."],0,"Impedance is Z(s) = F(s)/X_dot(s) — you regulate how force relates to position deviation.","Impedance control specifies the desired dynamic relationship Z(s) between contact force and end-effector deviation, allowing the robot to feel compliant or stiff to external physical interaction as required.","Collaborative robots (cobots) use impedance control to feel soft when pushed by a human but stiff when executing a precision assembly insertion task."),
  q(1029,"Control","calm","Hard",20,"Why does pure communication time delay degrade phase margin and can cause closed-loop instability?",["The delay contributes phase lag of minus omega times tau that grows unboundedly with frequency.","Time delay effectively increases the open-loop gain, pushing the system toward instability.","Time delay shifts all closed-loop poles uniformly leftward, actually improving stability margins.","Delay affects only the integral branch of the controller, not the proportional or derivative paths."],0,"Delay = e^{-s*tau} adds -omega*tau phase that accumulates unboundedly with frequency.","A pure delay e^{-s*tau} is all-pass with phase angle -omega*tau; at the gain-crossover frequency this phase loss directly reduces phase margin, potentially consuming it entirely.","Teleoperated surgical robots operating over network links must explicitly model and compensate communication latency to maintain stable force feedback control."),
  q(1030,"Control","calm","Hard",20,"Why does a flexible-joint robot require two coupled dynamic subsystems rather than a single rigid model?",["Joint elasticity couples separate motor-side and link-side dynamics, doubling state dimension and introducing resonance modes.","Flexible joints require independent friction models on the motor shaft and the link output separately.","Two subsystems model prismatic and revolute joints in the kinematic chain independently.","One subsystem models heavy proximal links and another models the lightweight distal links."],0,"Elastic spring between motor and link creates two state variables per joint instead of one.","A torsional spring between motor and link introduces motor angle, link angle, and their velocities as separate state variables; this creates joint resonance modes absent in rigid models and requires two-DOF controllers.","DLR and KUKA research arms with harmonic drive joints explicitly model flexible-joint dynamics to suppress resonance during high-bandwidth force control operations."),

  // ── CALM: SLAM & Estimation ───────────────────────────────────────────────
  q(1031,"SLAM & Estimation","calm","Easy",10,"What makes SLAM fundamentally harder than localisation with a known map?",["Both the robot pose and the map are unknown simultaneously, creating a tightly coupled inference problem.","SLAM requires GPS infrastructure while standard localisation works without any external reference.","SLAM is restricted to 2D planar environments while full localisation operates in 3D space.","SLAM eliminates the loop closure step by maintaining a globally consistent map at all times."],0,"In localisation you know the map; in SLAM you must build it and localise simultaneously.","In localisation, map uncertainty is absent; in SLAM, errors in the pose estimate corrupt the map and map errors corrupt the pose estimate — they are inseparably coupled in the full posterior.","Mobile robots exploring unknown buildings rely on EKF-SLAM or graph-SLAM because no prior map exists and both pose and map must be estimated from sensor data alone."),
  q(1032,"SLAM & Estimation","calm","Easy",10,"What role does loop closure play in a SLAM pose graph?",["It adds a measurement constraint that corrects accumulated drift when a revisited place is recognised.","It terminates the estimation process once the robot returns exactly to its starting pose.","It removes low-confidence landmark observations to progressively reduce graph memory consumption.","It forces the prior distribution over pose to reset to a uniform distribution at each cycle."],0,"Recognising a previously seen place adds a long-range correction edge to the pose graph.","Without loop closure, odometric drift accumulates indefinitely; a detected revisit adds a pose constraint that allows the graph optimiser to redistribute the accumulated error across the entire trajectory.","In large-scale outdoor SLAM, a single loop closure detected after a kilometre of travel can reduce total map error from metres to centimetres after pose graph optimisation."),
  q(1033,"SLAM & Estimation","calm","Easy",10,"What is the innovation in a Kalman filter and what role does it play in the update step?",["The difference between actual and predicted measurements that drives the state correction toward truth.","The total accumulated odometry error integrated since the filter was last initialised at startup.","The time derivative of the state covariance matrix computed between consecutive prediction steps.","The change in landmark positions detected by comparing two consecutive map update steps."],0,"Innovation = z - H*x_hat_minus — it quantifies how surprising the measurement was.","The innovation y = z - H*x_hat^- quantifies how much the actual measurement deviates from the prediction; the Kalman gain K then weights how much of this surprise is used to correct the state estimate.","In LiDAR-based localisation, a large innovation on a specific range beam signals either a new obstacle or a localisation error, triggering a targeted state correction update."),
  q(1034,"SLAM & Estimation","calm","Easy",10,"Why is the Extended Kalman Filter only a first-order approximation for nonlinear systems?",["It linearises nonlinear functions via Jacobians evaluated at the current estimate, discarding higher-order terms.","It expands the state vector to explicitly include all nonlinear coupling terms at each time step.","It draws Monte Carlo samples from the state distribution to propagate uncertainty approximately.","It applies Bayes' rule exactly after discretising the continuous state space into a fine grid."],0,"EKF takes a single tangent-plane approximation at the current mean estimate — first order only.","EKF computes Jacobians F = df/dx and H = dh/dx at x_hat to linearise the dynamics and observation models; this first-order Taylor approximation accumulates error when the true functions are strongly curved.","UKF and particle filters were developed specifically to reduce this linearisation error in highly nonlinear systems like long-range mobile robot pose estimation."),
  q(1035,"SLAM & Estimation","calm","Easy",10,"What is the primary advantage of a particle filter over a Kalman filter for robot localisation?",["It represents arbitrary non-Gaussian and multimodal probability distributions over robot state.","It is always faster to compute than any variant of the Kalman filter for all state dimensions.","It requires no motion model whatsoever to propagate the belief distribution forward in time.","It permanently eliminates the need for resampling under any level of measurement noise."],0,"Particles make no Gaussian assumption — they can represent any shape of belief distribution.","Particles are weighted samples from the full posterior; unlike the KF, they can represent multimodal distributions such as an ambiguous position in a geometrically symmetric corridor.","Global localisation — the kidnapped robot problem — requires particles because the initial belief is uniform over the entire map, a distribution impossible to represent with a Kalman filter."),
  q(1036,"SLAM & Estimation","calm","Medium",15,"In factor graph SLAM, what do the variable nodes and factor nodes each represent?",["Variables represent unknown poses and landmarks; factors encode probabilistic constraints from measurements.","Variables represent raw sensor readings; factors encode the robot joint angle configurations used.","Variables represent occupancy grid cells; factors encode sensor noise covariance matrices.","Variables represent control inputs applied; factors encode Jacobians of the observation model."],0,"Unknowns are variable nodes; probabilistic evidence linking them are factor nodes.","Variable nodes hold the unknowns to be estimated (robot poses, landmark positions); factor nodes encode the probabilistic relationships (odometry factors, observation factors) constraining those variables.","iSAM2 represents the full SLAM problem as a factor graph and updates it incrementally using a Bayes tree, enabling real-time estimation on ground robots and UAVs."),
  q(1037,"SLAM & Estimation","calm","Medium",15,"Why does the information matrix in large-scale graph-SLAM have a sparse structure?",["Each measurement factor links only nearby poses or landmarks, creating few non-zero off-diagonal entries.","Every pose directly observes every other pose in the graph, making the matrix fully dense.","The information matrix is always strictly diagonal for any 3D SLAM formulation whatsoever.","Sparse structure arises only when exactly one sensing modality is used throughout the mission."],0,"Local observations only connect nearby nodes — most node pairs share no measurement at all.","In a typical robot trajectory, each sensor reading links only the current pose to nearby landmarks; the resulting information matrix has a banded or sparse block structure that sparse Cholesky solvers exploit efficiently.","g2o and GTSAM exploit this sparsity to solve pose graph optimisation problems with thousands of nodes in real time on standard computing hardware."),
  q(1038,"SLAM & Estimation","calm","Medium",15,"What does the Mahalanobis distance measure in the data association step of SLAM?",["The covariance-normalised distance between an observation and a predicted measurement for consistent gating.","The Euclidean distance between the current robot pose and the nearest stored map landmark.","The number of standard deviations separating the new pose estimate from the prior distribution.","The L2 norm of the innovation vector divided by the total number of observation dimensions."],0,"Mahalanobis is a covariance-weighted distance — it accounts for the shape of uncertainty.","d^2 = y^T S^{-1} y where S is the innovation covariance; this normalises the residual by its uncertainty, so a noisy measurement with high covariance is not penalised as harshly as a precise one.","Nearest-neighbour data association in EKF-SLAM uses a Mahalanobis gate to reject candidate landmark matches that are statistically too far from the predicted measurement."),
  q(1039,"SLAM & Estimation","calm","Medium",15,"Why does LiDAR odometry degrade severely in long featureless corridors or tunnels?",["The scan-matching Hessian becomes ill-conditioned along the corridor axis, making that direction unobservable.","LiDAR returns are absorbed by smooth walls, reducing point cloud density below the ICP minimum.","The ICP point cloud buffer overflows in long corridors, triggering an automatic pose state reset.","Geometric symmetry causes the SLAM system to generate spurious false loop closures along the corridor."],0,"Along a featureless axis the Hessian eigenvalue approaches zero — motion is unobservable there.","ICP and NDT scan-matching minimise a cost whose Hessian encodes geometric constraint; in a symmetric corridor the Hessian is rank-deficient along the translation axis, leaving that component of motion unobservable.","LOAM and LIO-SAM detect degenerate directions by analysing Hessian eigenvalues and fuse IMU data to constrain the unobservable directions during corridor navigation."),
  q(1040,"SLAM & Estimation","calm","Hard",20,"How does the Unscented Transform improve on EKF linearisation for propagating uncertainty?",["It propagates deterministic sigma points capturing mean and covariance to third-order accuracy through the nonlinear function.","It replaces Jacobian computation with numerically computed finite-difference gradient approximations.","It draws random samples from the prior distribution and weights them by the measurement likelihood.","It applies Bayes' rule exactly by computing a closed-form integral over the nonlinear transformation."],0,"Sigma points are chosen deterministically to match the input distribution up to third order.","The UT selects 2n+1 sigma points that exactly encode the input mean and covariance; propagating them through the nonlinear function and recomputing statistics captures second-order effects that Jacobian linearisation misses entirely.","UKF-based visual-inertial odometry achieves significantly lower drift than EKF formulations on platforms with highly nonlinear IMU pre-integration models."),
  q(1041,"SLAM & Estimation","calm","Hard",20,"Why does particle resampling cause sample impoverishment and how do modern filters mitigate it?",["Resampling duplicates high-weight particles, collapsing diversity; MCMC rejuvenation or roughening steps restore it.","Resampling always improves diversity by drawing fresh independent samples from the prior distribution.","Impoverishment only becomes a real problem when the particle count drops below ten total particles.","It is mitigated by artificially inflating measurement noise covariance after each resampling step."],0,"After resampling many particles are identical clones — the filter loses spread and diversity.","After resampling, many particles are exact duplicates of the highest-weight ones; MCMC kernel steps (resample-move) or regularisation perturbations restore diversity without changing the marginal distribution.","Rao-Blackwellised particle filters exploit conditional independence to reduce required particle count, partially avoiding impoverishment by analytically marginalising the map variables."),
  q(1042,"SLAM & Estimation","calm","Hard",20,"What excitation condition must monocular visual-inertial odometry satisfy for metric scale to become observable?",["The platform must undergo non-degenerate translational acceleration and rotation so IMU and camera jointly constrain scale.","The camera must observe at least three non-collinear stationary landmarks during the first second.","The IMU must be factory-calibrated to sub-milligravity precision before any motion is attempted.","The system must begin from a precisely known pose with a pre-built metric landmark map available."],0,"Pure rotation gives no scale — translational acceleration is essential for scale observability.","Under pure rotation, both monocular geometry and IMU data are scale-ambiguous; translational acceleration along a non-degenerate axis coupled with known gravitational acceleration makes metric scale observable.","VIO systems like VINS-Mono perform an excitation sequence during initialisation to ensure scale converges before navigation begins."),
  q(1043,"SLAM & Estimation","calm","Hard",20,"How does the MAP estimate in Bayesian SLAM differ from the maximum likelihood estimate?",["MAP maximises the posterior by including the prior over poses and landmarks; ML ignores the prior entirely.","MAP maximises the measurement likelihood alone; ML maximises the full joint posterior distribution.","Both are identical in all respects when the prior distribution is chosen to be uninformative.","MAP is computed only for landmark positions while ML is computed only for robot pose estimates."],0,"MAP = likelihood times prior; ML = likelihood only — the prior is the crucial difference.","MAP = argmax p(x|z) = argmax p(z|x)*p(x); ML = argmax p(z|x), discarding the prior term. The prior regularises MAP, preventing overfitting to noisy or sparse measurements.","Graph-SLAM with odometry factors solves MAP inference; the odometry prior prevents the optimiser from placing landmarks in physically implausible locations to explain noisy observations."),
  q(1044,"SLAM & Estimation","calm","Hard",20,"Why does adding loop closure edges increase the density of the information matrix in EKF-SLAM?",["Each loop closure links distant pose nodes directly, adding non-zero off-diagonal blocks that propagate through the matrix.","Loop closures reduce uncertainty and therefore make the information matrix increasingly diagonal.","Information matrix density is strictly independent of the number of loop closures incorporated.","Loop closures only add new diagonal blocks corresponding to newly constrained landmark positions."],0,"Loop closure links node i and node j — that creates a (i,j) off-diagonal entry that fills in.","A loop closure between pose i and pose j creates a non-zero information block at position (i,j); through the EKF update equations this propagates to all correlated nodes, increasing global matrix fill-in.","This O(n^2) fill-in is a core reason EKF-SLAM is computationally impractical for large maps; sparse approximations selectively neglect small information entries to maintain tractability."),
  q(1045,"SLAM & Estimation","calm","Hard",20,"How does factor graph inference jointly solve localisation and mapping in graph-SLAM?",["All pose and landmark variables are jointly optimised by minimising the sum of squared factor residuals over the full graph.","Localisation and mapping are solved alternately in separate EM-style expectation and maximisation steps.","The factor graph solves only the mapping subproblem; localisation is handled by a separate EKF.","Factor graph inference requires a precisely known initial pose to prevent the graph from becoming under-constrained."],0,"All variables and all constraints live in one graph — one joint MAP solve handles both simultaneously.","The factor graph encodes p(X,L|Z) as a product of factors; minimising the negative log posterior is equivalent to a nonlinear least-squares problem over all pose and landmark variables simultaneously.","GTSAM and g2o solve this joint optimisation using sparse QR or Cholesky factorisation, enabling large-scale online SLAM on autonomous vehicles and UAVs."),

  // ── CALM: Dynamics ────────────────────────────────────────────────────────
  q(1046,"Dynamics","calm","Easy",10,"In the Euler-Lagrange robot equation, what physical forces does the term C(q,q_dot)*q_dot represent?",["Centripetal and Coriolis forces that arise purely from the joint velocity interactions.","Gravitational potential energy forces acting on each individual link at the current configuration.","Viscous friction torques at each joint that oppose the current direction of joint velocity.","The product of the inertia matrix multiplied by the desired joint acceleration trajectory."],0,"C*q_dot encodes velocity-squared centripetal and cross-velocity Coriolis coupling terms.","C(q,q_dot) contains Christoffel symbols of the second kind; the product C*q_dot captures centripetal forces from single joint velocities and Coriolis coupling forces from pairs of joint velocities.","During fast robot arm motions, C*q_dot can reach tens of Newton-metres and must be included in feedforward torque computation for accurate trajectory tracking."),
  q(1047,"Dynamics","calm","Easy",10,"What structural property of the robot inertia matrix M(q) makes it invertible at every configuration?",["M(q) is symmetric and positive definite for all q, guaranteeing a positive determinant everywhere.","M(q) is always perfectly diagonal for any serial-chain robot regardless of its configuration.","M(q) is configuration-independent and equals the sum of all individual link inertia tensors.","The determinant of M(q) equals the total robot mass at every joint angle configuration."],0,"Positive definite implies all eigenvalues are positive, hence det > 0 — always invertible.","M(q) encodes kinetic energy as T = 0.5*q_dot^T*M(q)*q_dot; positive definiteness ensures T > 0 for any non-zero q_dot, and symmetry follows from the reciprocity of inertia coupling between joint pairs.","Computed-torque control inverts M(q) at every control cycle; positive definiteness guarantees this inverse always exists and the resulting control law remains well-defined."),
  q(1048,"Dynamics","calm","Easy",10,"What does the skew-symmetry of (M_dot - 2C) enable in robot dynamics stability proofs?",["It proves the robot is a passive system, since x_dot^T*(M_dot/2 - C)*x_dot equals zero identically.","It proves the Coriolis matrix C is always identically zero for any planar two-link robot.","It shows the gravity gradient vector is always orthogonal to the Coriolis matrix C.","It proves the inertia matrix M(q) is completely independent of joint velocity at all configurations."],0,"Skew-symmetry means net power from Coriolis forces is zero — the passivity proof pivots on this.","Since M_dot = C + C^T, the matrix (M_dot/2 - C) is skew-symmetric; any vector pre- and post-multiplied by a skew-symmetric matrix gives zero, proving passivity of the robot dynamics.","Adaptive controllers for robots with unknown parameters exploit this passivity property to prove stability without requiring exact knowledge of M, C, or the gravity vector g."),
  q(1049,"Dynamics","calm","Easy",10,"Why is Newton-Euler recursion preferred over the Lagrangian method for real-time inverse dynamics?",["Newton-Euler uses O(n) forward-backward recursion while the Lagrangian symbolic expansion scales as O(n^4).","Newton-Euler is always numerically more accurate than the Lagrangian method for all joint counts.","Newton-Euler eliminates Coriolis and gravity terms entirely, simplifying the computation significantly.","Newton-Euler applies only to serial-chain robots, making it faster due to reduced branching logic."],0,"O(n) recursive sweeps beat symbolic O(n^4) Lagrangian expansion dramatically for speed.","The Newton-Euler algorithm makes one outward pass computing velocities and accelerations, then one inward pass computing forces and torques — both O(n) — while Lagrangian symbolic form grows combinatorially.","Real-time computed-torque and model-predictive controllers on high-DOF arms use Newton-Euler via Pinocchio or RBDL to compute inverse dynamics in under a millisecond."),
  q(1050,"Dynamics","calm","Medium",15,"Why does the robot inertia matrix M(q) change with joint configuration even though no masses change?",["The second moments of mass about each joint axis change as the geometric arrangement of links changes.","The gravitational field direction rotates relative to the robot base frame as the joints move.","Joint friction coefficients vary with the angle of bearing contact at each individual joint.","Motor back-EMF constants change with the rotor angular velocity at each joint during motion."],0,"Inertia is about mass distribution relative to rotation axes — geometry changes that distribution.","M(q) encodes second moments of mass of all downstream links about each joint axis; rotating an upstream joint changes the moment arms of all distal masses, altering every entry in M.","A robot arm fully extended can have three to five times more distal inertia than when fully tucked, dramatically changing required joint torques for the same desired acceleration profile."),
  q(1051,"Dynamics","calm","Medium",15,"How does static friction (stiction) differ from kinetic Coulomb friction in robot joint dynamics?",["Static friction resists motion up to a higher break-away threshold; kinetic friction acts during sliding at a lower level.","Coulomb friction increases proportionally with sliding velocity; static friction is constant regardless.","Static friction is modelled as a linear spring storing elastic energy; Coulomb friction as a linear dashpot.","Both friction types are identical in magnitude but are applied over different ranges of joint velocity."],0,"Stiction holds the joint still until break-away; kinetic friction then resists sliding at a lower level.","Static friction must exceed the break-away torque before motion begins; once sliding starts, kinetic Coulomb friction provides a lower, approximately velocity-independent resistive torque.","Precision robot assembly suffers from stiction-induced position errors of 0.1-1 degree at joint reversals; dithering signals or disturbance observers are used to mitigate this effect."),
  q(1052,"Dynamics","calm","Medium",15,"How does the principle of virtual work relate joint torques to end-effector contact forces?",["Equating virtual work in joint and task spaces yields tau = J^T * F, mapping Cartesian wrenches to joint torques.","Virtual work states that internal constraint forces perform zero net work for holonomic constraints.","The principle determines the minimum-energy joint trajectory between two end-effector poses.","It equates instantaneous kinetic energy to potential energy along any dynamically feasible trajectory."],0,"delta_W = tau^T delta_q = F^T delta_x, so tau = J^T * F follows from the chain rule.","The virtual displacement delta_x = J*delta_q links joint and Cartesian virtual displacements; equating virtual work done by joint torques and end-effector forces yields the Jacobian transpose force mapping.","Cartesian force control uses tau = J^T * F_desired to apply precise contact forces at the end effector without requiring explicit force sensor inversion."),
  q(1053,"Dynamics","calm","Hard",20,"What does the operational-space inertia Lambda = (J M^{-1} J^T)^{-1} physically represent?",["The effective inertia experienced by Cartesian-space forces and accelerations applied at the end effector.","The joint-space inertia matrix projected onto the six Cartesian coordinate directions.","The covariance of end-effector position errors assuming independent Gaussian joint angle noise.","The geometric inverse of the manipulability ellipsoid at the current robot configuration."],0,"Lambda is the mass the end effector appears to have when you push it in Cartesian space.","Lambda maps Cartesian forces to Cartesian accelerations: F = Lambda*x_ddot + mu + p, decoupling the six task-space directions and enabling independent Cartesian-axis impedance control.","Khatib's operational-space controller uses Lambda to design Cartesian impedance and force controllers for humanoid robots interacting with objects and humans simultaneously."),
  q(1054,"Dynamics","calm","Hard",20,"Why does rigid-body impact dynamics require an impulsive force model rather than a continuous force model?",["Contact forces are infinite in magnitude over an infinitesimal duration; only their time-integral (impulse) is finite and meaningful.","Impact forces are exactly zero because kinetic energy is perfectly conserved in all rigid-body collisions.","Continuous force models apply to soft compliant contacts only; impulsive models apply to stiff contacts.","Impact dynamics is only relevant for aerial vehicles and never arises in ground-based manipulation."],0,"Rigid contact means zero contact duration — force spikes to infinity but impulse remains finite.","For rigid bodies, contact duration approaches zero while contact force approaches infinity; the physically meaningful quantity is the impulse J = integral(F dt), governed by the coefficient of restitution.","Legged robot controllers model foot touchdown as an impulsive event, using instantaneous velocity jump equations to update joint states at the moment of ground contact."),
  q(1055,"Dynamics","calm","Hard",20,"Why is the manipulator equation said to be linear in the inertial parameters?",["It factors as Y(q,q_dot,q_ddot)*pi = tau where Y is a known regressor and pi is the parameter vector.","All terms in the equation are linear functions of the joint angle vector q itself.","The inertia matrix M(q) is always configuration-independent, making all terms trivially linear.","Gravity g(q) is linear in q and this linearity propagates through the full Euler-Lagrange derivation."],0,"Rewrite dynamics as Y*pi — Y depends only on measured motion; pi holds the physical parameters.","Every term in the dynamics can be expressed as a linear combination of ten inertial parameters per link (mass, first moments, second moments); the regressor Y contains only measured or desired kinematic quantities.","Adaptive robot controllers estimate pi online from measured torques and motion, updating the feedforward model in real time without knowing exact link masses or centre-of-mass locations."),
  q(1056,"Dynamics","calm","Hard",20,"What does the Centroidal Dynamics Model capture and why is it used in legged robot MPC?",["Total linear and angular momentum of the whole robot about its CoM, abstracted from joint-level detail.","Individual contact forces at each foot modelled using linearised Coulomb friction cone constraints.","The full Newton-Euler equations projected onto a reduced spring-loaded inverted pendulum model.","Gravitational potential energy of the robot centre of mass used exclusively for static balance analysis."],0,"Centroidal dynamics sums all momenta into 6 scalars — fast enough for real-time MPC optimisation.","The centroidal model represents aggregate linear momentum (m*v_CoM) and angular momentum (L) about the CoM; their rates equal the net contact wrench, enabling fast MPC without full multibody simulation.","MIT Cheetah and ANYmal compute centroidal MPC contact force plans at 200-400 Hz, then resolve them to joint torques via a whole-body controller running at a lower level."),

  // ── CALM: Perception ──────────────────────────────────────────────────────
  q(1057,"Perception","calm","Easy",10,"What physical process does the pinhole camera model mathematically describe?",["Perspective projection of 3D world points onto a 2D image plane through a single focal point.","Orthographic projection of 3D forces onto 2D torque components via a Jacobian matrix.","Depth recovery from defocus blur using the known lens aperture and focal length values.","Mapping of world points to robot joint angles via the inverse kinematic chain."],0,"All rays pass through a single focal point and intersect a flat image plane behind it.","The pinhole model uses the intrinsic matrix K = [f 0 cx; 0 f cy; 0 0 1] to project a homogeneous 3D point to a 2D pixel via perspective division, assuming a thin lens and negligible distortion.","Camera calibration with a checkerboard pattern recovers K and radial/tangential distortion coefficients needed to correct raw images before any geometric reconstruction."),
  q(1058,"Perception","calm","Easy",10,"What constraint does epipolar geometry impose on stereo image correspondence search?",["A point in one image must correspond to a point lying on a specific epipolar line in the other image.","A point in one image corresponds to the pixel with the minimum intensity difference in the other.","The disparity between matched points is constrained to be strictly non-negative in all geometries.","Camera rotation between frames is constrained to lie within the epipolar plane boundary."],0,"Epipolar lines reduce 2D correspondence search to a 1D line search in the second image.","The fundamental matrix F relates corresponding points as x'^T F x = 0; the line F*x is the epipolar line in image 2, reducing stereo matching from a 2D area search to a 1D line search.","Stereo camera rectification aligns epipolar lines with image rows, enabling fast row-parallel disparity computation in real-time depth estimation for autonomous vehicles."),
  q(1059,"Perception","calm","Easy",10,"Why is RANSAC preferred over global least-squares for geometric model fitting in robot vision?",["RANSAC fits models to random minimal subsets, identifying inlier consensus sets that outliers cannot corrupt.","RANSAC always runs faster than least-squares regardless of dataset size or outlier fraction.","RANSAC requires no prior geometric model, making it applicable to arbitrary feature distributions.","RANSAC produces exact solutions with guaranteed global optimality for small point-set sizes."],0,"Even a few outliers collapse least-squares; RANSAC finds the inlier consensus robustly.","RANSAC randomly samples the minimum number of points to fit the model, scores all points against it, and iterates; outliers rarely appear in the minimum sample, so the inlier set is found despite high outlier fractions.","Visual odometry pipelines use RANSAC on feature matches to estimate the essential matrix, rejecting dynamic object matches that would corrupt the ego-motion estimate."),
  q(1060,"Perception","calm","Easy",10,"What two design choices make SIFT descriptors invariant to scale changes and image rotation?",["Scale-space extrema detection for scale invariance and dominant orientation normalisation for rotation invariance.","Pixel intensity normalisation by image mean and variance for both scale and rotation invariance.","Binary pixel pair comparisons at multiple radii providing scale and rotation invariance together.","3D volumetric convolutions whose separable structure cancels both scale and orientation changes."],0,"DoG pyramid handles scale; dominant gradient orientation angle handles rotation.","SIFT detects keypoints at scale-space extrema of Difference-of-Gaussian responses, then computes a dominant orientation from a local gradient histogram to normalise the descriptor against rotation.","Wide-baseline stereo matching and structure-from-motion pipelines rely on SIFT because it maintains reliable matching across large viewpoint, scale, and lighting changes."),
  q(1061,"Perception","calm","Medium",15,"What is the physical distinction between intrinsic and extrinsic camera parameters?",["Intrinsics describe the camera internal optics; extrinsics describe the camera pose relative to the world.","Intrinsics are estimated per scene; extrinsics are fixed permanently at manufacturing time.","Extrinsics encode lens distortion coefficients; intrinsics encode the camera-to-robot transform.","Intrinsics and extrinsics are interchangeable components of the same unified projection matrix."],0,"Intrinsics are inside the camera; extrinsics are outside — where the camera sits in the world.","The intrinsic matrix K encodes how 3D camera-frame rays map to pixel coordinates (focal length, principal point, skew); the extrinsic matrix [R|t] encodes the camera's 6-DOF pose in the world frame.","Multi-camera sensor suites on autonomous vehicles require precise extrinsic calibration to fuse observations from different cameras into a consistent world-frame point cloud."),
  q(1062,"Perception","calm","Medium",15,"How does an occupancy grid represent scene uncertainty differently from a raw point cloud?",["Each grid cell stores an occupancy probability updated via a Bayesian filter; a point cloud stores geometry without uncertainty.","Occupancy grids are always denser in memory than equivalent-resolution point clouds.","Point clouds encode uncertainty as per-point covariance ellipsoids; occupancy grids have no uncertainty model.","Occupancy grids work only in 2D planar environments; point clouds are required for any 3D scene."],0,"Cells have probabilities fusing multiple noisy observations; points are deterministic measurements.","Each occupancy cell maintains log-odds updated with each sensor reading using a probabilistic inverse sensor model; this naturally handles false detections, missed detections, and varying sensor noise.","ROS Navigation Stack uses 2D occupancy grids to represent free and occupied space for path planning, with ray-casting updates from 2D laser scans at each timestep."),
  q(1063,"Perception","calm","Medium",15,"What inductive bias does self-attention in Vision Transformers provide compared to convolution?",["Self-attention captures global pairwise dependencies between all image patches without locality constraints.","Self-attention selects the most relevant camera from a multi-camera array for each inference step.","Self-attention applies a learned edge detector to each patch before extracting semantic features.","Self-attention normalises patch intensities globally to achieve lighting invariance across the image."],0,"Attention has no built-in locality — every patch can attend to every other patch globally.","CNNs enforce local spatial computation through fixed receptive fields; ViT self-attention computes a weighted sum over all tokens, allowing each patch to directly incorporate context from any other patch regardless of distance.","Robot manipulation policies trained on ViT backbones generalise better across different table configurations because global context helps disambiguate object identity from non-local scene cues."),
  q(1064,"Perception","calm","Hard",20,"Why is metric scale fundamentally unobservable from monocular image geometry alone?",["A uniformly scaled scene produces an identical monocular image sequence, making scale algebraically unidentifiable.","Scale ambiguity affects only cameras undergoing pure rotation with no translational motion component.","The camera focal length directly encodes absolute metric scale after standard calibration procedures.","Metric scale can always be recovered from the homography between two consecutive image frames."],0,"Double all depths and halve the translation — every image pixel remains identical.","Perspective projection is invariant to simultaneous scaling of scene depths and camera translations; without additional metric information (known baseline, IMU, or object size) the scale factor is unobservable from images alone.","Monocular SLAM systems like ORB-SLAM3 estimate scale up to an unknown factor; fusing IMU measurements in a monocular-inertial configuration recovers the metric scale."),
  q(1065,"Perception","calm","Hard",20,"What is the aperture problem in optical flow estimation and what assumption resolves it locally?",["Only the flow component normal to an edge is observable locally; the tangential component is invisible through a small aperture.","Wide camera apertures produce motion blur that prevents any optical flow computation from succeeding.","Local flow estimation fails because pixel noise dominates the small spatial gradient magnitudes.","The aperture problem limits flow estimation only to the depth component along the optical axis."],0,"A moving edge through a small window looks the same for any tangential velocity — only normal flow is visible.","Within a small image region, an edge moving at any tangential velocity produces identical local image changes; only the component normal to the edge is locally constrained.","Lucas-Kanade assumes constant flow within a local patch and solves an overdetermined system, using the surrounding neighbourhood to resolve the tangential ambiguity."),
  q(1066,"Perception","calm","Hard",20,"Why do voxel-based 3D object detectors accept lower spatial resolution as a computational trade-off?",["Voxelisation converts irregular sparse points into a regular 3D grid that enables efficient sparse 3D convolution operations.","Voxel methods increase effective resolution by computing the average of all points in each cell.","Voxel representations are used exclusively for 2D projections of sparse 3D point clouds.","Voxelisation converts the 3D detection problem into a 1D token sequence for transformer processing."],0,"Irregular sparse points cannot use standard convolution — voxels make the spatial grid regular.","Raw point clouds have irregular spatial distribution unsuitable for CNN convolution; voxelisation quantises 3D space into a regular grid where sparse 3D convolutions run efficiently, at the cost of sub-voxel resolution.","VoxelNet and its successors (PointPillars, CenterPoint) achieve real-time 3D detection on autonomous vehicle hardware by voxelising LiDAR point clouds at 5-10 cm resolution."),
  q(1067,"Perception","calm","Hard",20,"How does domain randomisation address the visual appearance gap in sim-to-real transfer?",["Randomising rendering parameters forces the model to learn features invariant to appearance variations.","Domain randomisation fails because physics simulators cannot accurately model gravitational effects.","It reduces dataset size by removing redundant near-duplicate rendered images during collection.","The technique is only useful when the real-world deployment environment is known in advance."],0,"Train on hundreds of random appearances so the real world is just one more variation in the distribution.","By randomising textures, lighting, object poses, and sensor noise during simulation, the trained model sees the real world as one more sample from a broad distribution it has already encountered.","OpenAI's Dexterous Hand project trained entirely on randomised simulation and deployed directly on hardware, demonstrating successful sim-to-real transfer without any real-world training data."),
  q(1068,"Perception","calm","Hard",20,"Why does instance segmentation require a fundamentally different architecture than semantic segmentation?",["Instance segmentation must separate individual objects of the same class, requiring per-region mask prediction heads.","Semantic segmentation requires full 3D scene understanding, making it architecturally more complex.","Instance segmentation is simpler because bounding box proxies replace pixel-level mask prediction.","The architectural difference is only in the loss function; the network backbone is identical in both."],0,"Semantic labels pixels with a class; instance additionally separates car 1 from car 2 from car 3.","Semantic segmentation assigns a class label per pixel; instance segmentation must additionally separate individual objects, requiring region proposal generation, per-instance feature pooling, and dedicated mask heads.","Mask R-CNN extends Faster R-CNN with a parallel mask branch on each region proposal, enabling pixel-level instance masks for robot manipulation scene understanding."),

  // ── CALM: Machine Learning ────────────────────────────────────────────────
  q(1069,"Machine Learning","calm","Easy",10,"What does the bias-variance tradeoff describe in model selection?",["High bias means underfitting (too simple); high variance means overfitting (too complex); the tradeoff minimises total test error.","Bias measures training speed and variance measures the prediction accuracy on test data.","Adding more training data always simultaneously increases both bias and variance together.","It describes the tradeoff between model interpretability and computational cost at inference."],0,"Underfitting vs overfitting — bias and variance pull in opposite directions across model complexity.","Expected test error = bias^2 + variance + irreducible noise; model complexity shifts the balance between these terms, and optimal complexity minimises their sum.","Cross-validation finds the model complexity that minimises total test error by evaluating generalisation on held-out data."),
  q(1070,"Machine Learning","calm","Easy",10,"Why does batch normalisation improve training of deep networks?",["It normalises layer inputs to zero mean and unit variance, reducing internal covariate shift and allowing higher learning rates.","It randomly drops neurons during training to prevent co-adaptation between layer units.","It averages gradients over mini-batches to reduce stochastic gradient descent noise.","It constrains weights to a unit sphere at each step, preventing gradient explosion."],0,"Normalising activations smooths the loss landscape and makes optimisation more stable.","By keeping activations in a normalised range, BatchNorm reduces the internal covariate shift between layers, making the loss landscape smoother and allowing significantly higher stable learning rates.","BatchNorm also acts as a mild regulariser, sometimes replacing dropout in modern deep learning architectures."),
  q(1071,"Machine Learning","calm","Easy",10,"How do LSTM gating mechanisms address the vanishing gradient problem in vanilla RNNs?",["LSTM gates allow gradients to flow across many timesteps via additive cell-state updates, avoiding exponential decay.","LSTM eliminates recurrence entirely by replacing it with pure feedforward connections.","LSTM uses larger hidden state vectors which inherently prevent gradient decay by volume.","LSTM applies layer normalisation at each step to rescale gradients back to unit norm."],0,"Additive cell-state updates allow gradients to flow back through many steps without multiplying.","In vanilla RNNs, gradients multiply the recurrent weight matrix at each step, causing exponential decay; LSTM's additive cell state updates provide a highway for gradients to flow across many timesteps without decay.","Transformers have largely replaced LSTMs in NLP, but LSTMs still appear in embedded robotics controllers with limited computation budgets."),
  q(1072,"Machine Learning","calm","Easy",10,"What is the role of the kernel function in a support vector machine?",["It implicitly maps inputs to a high-dimensional feature space, enabling linear separation of nonlinearly separable data.","It filters training examples below the margin threshold to reduce the support vector set.","It defines the hinge loss function used to penalise misclassified training points.","It dynamically sets the learning rate schedule during the SVM dual optimisation."],0,"K(x,x') = phi(x)^T phi(x') computes a high-dimensional dot product without forming phi explicitly.","The kernel trick computes K(x,x') = phi(x)^T phi(x') without explicitly forming the high-dimensional feature map phi, enabling SVMs to operate in infinite-dimensional spaces efficiently.","RBF kernels enable infinite-dimensional feature spaces for robot grasp quality classification with complex nonlinear decision boundaries."),
  q(1073,"Machine Learning","calm","Easy",10,"What does the softmax function accomplish in a neural network classifier?",["It converts raw logit scores into a probability distribution over classes that sums to exactly one.","It normalises input features to zero mean before the forward pass through the network.","It applies a hard threshold, mapping each logit to a binary value of zero or one.","It computes the analytical gradient of the cross-entropy loss with respect to logits."],0,"Logits to probability simplex — differentiable and valid probability distribution always.","softmax(z_i) = exp(z_i) / sum(exp(z_j)); it is differentiable everywhere and produces a valid probability distribution over all classes summing to one.","Used with cross-entropy loss for multi-class robot perception tasks like object category classification or semantic segmentation."),
  q(1074,"Machine Learning","calm","Medium",15,"How do L1 and L2 regularisation differ in their effect on learned model weights?",["L1 induces sparsity by driving some weights to exactly zero; L2 shrinks all weights toward zero without sparsity.","L1 penalises the sum of squared weights; L2 penalises the sum of absolute weight values.","Both produce identical solutions for any convex loss function with bounded parameters.","L2 causes weight explosion during training; L1 prevents explosion by zero-clipping weights."],0,"L1 penalty corner at zero creates exact zeros (sparse); L2 smooth minimum keeps all weights small.","The L1 penalty sub-gradient at zero includes zero, creating exact sparsity; the L2 penalty has a smooth minimum above zero, shrinking all weights toward but not to zero.","Feature selection in robot proprioceptive learning uses L1; weight-decay regularisation for deep networks typically uses L2."),
  q(1075,"Machine Learning","calm","Medium",15,"Why does dropout act as implicit ensemble learning during training?",["Each forward pass randomly masks different units, training a different sub-network; testing averages over all.","Dropout permanently removes the least-useful neurons to reduce final model parameter count.","Dropout randomly shuffles input features each step to prevent co-adaptation between layers.","Dropout samples weights from a Gaussian prior distribution at each forward pass."],0,"Random sub-networks form an exponentially large ensemble; scaled test-time weights approximate their average.","With p drop probability there are 2^n possible sub-networks; weight scaling at test time approximates the geometric mean of their predictions, giving implicit ensemble behaviour.","Dropout is most beneficial for large fully connected layers in robot perception networks trained on limited data."),
  q(1076,"Machine Learning","calm","Medium",15,"How does the attention mechanism in transformers differ from convolution in terms of inductive bias?",["Attention captures global pairwise dependencies between all tokens; convolution enforces local translation equivariance.","Attention is a special case of convolution with a dynamically learned kernel size.","Convolution computes global context over the full image; attention operates only locally.","Both have identical inductive biases but attention is simply slower to train at scale."],0,"Attention has no built-in locality bias — every token can attend to every other token.","CNNs assume local features suffice and are translation-equivariant; transformers make no such assumption, learning which tokens to attend to from data, enabling global context at every layer.","Transformers need more data to learn spatial structure but generalise better across diverse deployment environments than CNNs."),
  q(1077,"Machine Learning","calm","Hard",20,"Why does knowledge distillation allow a smaller student to approach teacher performance?",["The student learns from soft probability distributions (dark knowledge) encoding inter-class similarities invisible in hard labels.","The student copies teacher weight tensors directly, reducing the effective parameter count.","Distillation works because the student uses a significantly higher learning rate than the teacher.","The teacher provides additional labelled data at inference time that the student did not train on."],0,"Soft targets at temperature T > 1 reveal class relationships hidden in hard one-hot labels.","Hinton's dark knowledge: at temperature T > 1, the teacher's softmax reveals that, say, 'truck' is more similar to 'car' than to 'bird' — structural information that hard labels completely discard.","Mobile robot perception systems use knowledge distillation to deploy large accurate teacher models as compact student models on edge hardware with limited compute budgets."),
  q(1078,"Machine Learning","calm","Hard",20,"What does the Neural Tangent Kernel (NTK) reveal about infinitely wide neural networks?",["In the infinite-width limit, gradient descent on neural networks becomes equivalent to kernel regression with a fixed NTK.","Infinitely wide networks always overfit their entire training dataset perfectly without exception.","NTK theory proves that weight initialisation uniquely determines the final trained network.","The NTK proves deeper networks always outperform wider networks on any given task."],0,"Infinite width means weights barely move during training — the network linearises around initialisation.","As width approaches infinity, weights barely move during gradient descent and the network behaves as a linear model in the NTK feature space, enabling exact analysis of training dynamics.","NTK theory illuminates why overparameterised networks generalise despite achieving zero training error — a long-standing theoretical puzzle."),
  q(1079,"Machine Learning","calm","Hard",20,"What is the lottery ticket hypothesis and what does it imply for network pruning?",["Dense networks contain sparse sub-networks (winning tickets) that when retrained from their original initialisation match full network accuracy.","Any randomly initialised network will eventually win any given classification task with enough training.","Pruning should always be performed before training to identify the optimal sparse sub-network.","Weight magnitude alone is sufficient to determine which individual parameters are most important."],0,"Winning sparse sub-networks exist at initialisation — find them, prune the rest, and retrain.","Frankle and Carlin showed that winning tickets identified by magnitude pruning combined with weight rewinding reach full accuracy at a fraction of the total parameters.","This motivates efficient sparse training methods for deploying accurate perception models on resource-constrained embedded robot hardware."),
  q(1080,"Machine Learning","calm","Hard",20,"Why does contrastive self-supervised learning require negative pairs or architectural asymmetry to prevent collapse?",["Without negatives, the trivial constant-output solution minimises contrastive loss; negatives or asymmetry break this symmetry.","A sufficiently large learning rate prevents the network from converging to a constant output.","Batch normalisation alone prevents representation collapse by normalising all embeddings to unit norm.","Collapse is prevented by replacing the InfoNCE contrastive loss with a mean-squared error objective."],0,"Without negatives, constant output trivially minimises the loss — symmetry must be broken somehow.","Without negative pairs, minimising the contrastive objective has a trivial solution where all embeddings are identical; negative pairs push different-sample representations apart, breaking this degeneracy.","BYOL avoids negatives by using an asymmetric slow-moving momentum encoder and a predictor head, breaking symmetry architecturally instead of with explicit negatives."),

  // ── CALM: Linear Algebra ──────────────────────────────────────────────────
  q(1081,"Linear Algebra","calm","Easy",10,"What does the rank of a matrix physically represent in a robot Jacobian?",["The number of independent task-space directions that can be actuated from the current configuration.","The number of non-zero eigenvalues multiplied by the matrix determinant.","The total number of elements stored across all rows and columns of the matrix.","The ratio of the largest to the smallest entry in the matrix."],0,"Rank = dimension of the column space — how many independent Cartesian directions are controllable.","Rank equals dim(col space); in a Jacobian, rank tells how many independent Cartesian directions can be actuated; rank loss at a singularity means some directions become uncontrollable.","Checking the Jacobian rank before issuing a Cartesian motion command is standard practice in industrial robot controllers to prevent singularity-induced instabilities."),
  q(1082,"Linear Algebra","calm","Easy",10,"What does the SVD A = U*Sigma*V^T reveal about a linear map geometrically?",["Orthonormal input directions (V), scaling factors (Sigma), and orthonormal output directions (U).","It factorises A into eigenvalues regardless of whether A is square or rectangular.","It converts A to a diagonal matrix but only when A is symmetric positive definite.","It directly finds the matrix inverse of A without requiring Gaussian elimination."],0,"Input principal axes (V), scaling (Sigma), output principal axes (U) — full geometry of the map.","Columns of V are the input principal directions; singular values in Sigma are their scaling magnitudes; columns of U are the corresponding output directions, fully characterising the geometry of the linear map.","SVD underlies pseudoinverse computation, principal component analysis, rank determination, and near-singularity analysis in robot Jacobians."),
  q(1083,"Linear Algebra","calm","Easy",10,"When is the Moore-Penrose pseudoinverse A-dagger used instead of A-inverse?",["When A is non-square or singular; A-dagger gives the minimum-norm least-squares solution.","Only when A is symmetric positive definite and square at the same time.","When A has more rows than columns and a unique exact solution exists.","A-dagger is only used for diagonal matrices with some zero diagonal entries."],0,"Non-square or singular matrices need the pseudoinverse — it minimises norm and residual simultaneously.","A-dagger = V*Sigma-dagger*U^T minimises ||Ax - b||^2 and among all such minimisers also minimises ||x||, providing the minimum-norm least-squares solution.","Over-determined inverse kinematics uses A-dagger to find the minimum joint-velocity solution when the Jacobian is non-square."),
  q(1084,"Linear Algebra","calm","Easy",10,"What does positive definiteness of a matrix M mean for the quadratic form x^T M x?",["It is strictly positive for all non-zero x, defining a proper energy or metric on the vector space.","All individual entries of M are positive real numbers without exception.","M has at least one positive eigenvalue among all of its eigenvalues.","M is a valid rotation matrix belonging to the special orthogonal group SO(n)."],0,"x^T M x > 0 for all non-zero x — it behaves like a genuine energy function.","Positive definiteness ensures x^T M x > 0 for all non-zero x, guaranteeing M defines a valid inner product; this is essential for robot inertia matrices and Lyapunov functions.","The robot inertia matrix M(q) is always symmetric positive definite, guaranteeing kinetic energy is always positive and M is always invertible."),
  q(1085,"Linear Algebra","calm","Easy",10,"What does the Cayley-Hamilton theorem state and why is it useful in matrix exponential computation?",["Every matrix satisfies its own characteristic polynomial, enabling matrix powers to be reduced to lower degree.","All eigenvalues of any valid rotation matrix lie exactly on the complex unit circle.","Every invertible matrix possesses a unique symmetric positive-definite square root.","The trace of any matrix equals the sum of its singular values rather than its eigenvalues."],0,"A satisfies p_A(A) = 0 — this truncates infinite series to finite polynomial expressions.","For an n x n matrix, A^n can be expressed as a linear combination of I, A, ..., A^{n-1}; this truncates the matrix exponential series, enabling closed-form computation.","The Rodrigues rotation formula uses Cayley-Hamilton to express SO(3) matrix exponentials as a finite polynomial in the skew-symmetric axis matrix."),
  q(1086,"Linear Algebra","calm","Medium",15,"How does a high condition number affect numerical solution accuracy in robotics computations?",["Small input perturbations cause large output changes, making linear system solutions numerically unreliable.","Condition number measures how close the matrix is to being orthogonal.","A condition number of exactly one indicates that the matrix is singular.","High condition number guarantees faster convergence of iterative linear solvers."],0,"cond(A) amplifies numerical errors — small data errors cause proportionally larger solution errors.","cond(A) = sigma_max / sigma_min; the relative error in the solution is bounded by cond(A) times the relative error in the input data.","Ill-conditioned Jacobians near robot singularities cause unreliable velocity commands; damped least-squares adds regularisation to keep cond(J) bounded."),
  q(1087,"Linear Algebra","calm","Medium",15,"Why is solving the normal equations A^T A x = A^T b numerically inferior to QR decomposition?",["Squaring A doubles its condition number, amplifying numerical errors; QR applied to A directly is more stable.","The normal equations are numerically unstable only when the right-hand side vector b contains zero entries.","A^T A is always singular, making the normal equations fundamentally unsolvable in general.","Numerical instability arises only when A has strictly more columns than rows."],0,"cond(A^T A) = cond(A)^2 — squaring the matrix doubles the precision problem.","Computing A^T A loses half the significant bits in floating-point arithmetic; QR decomposition applied directly to A avoids this squaring and is numerically far more stable.","Least-squares sensor calibration and system identification in robotics prefer QR or SVD solvers over normal equations for reliable numerical results."),
  q(1088,"Linear Algebra","calm","Medium",15,"What is the Schur complement and why does it appear in Kalman filter covariance updates?",["It enables block matrix inversion without inverting the full matrix, making covariance updates efficient.",  "It is the sum of all diagonal blocks in a block-partitioned symmetric matrix.",  "It is used only for symmetric indefinite matrices in constrained estimation problems.",  "Schur complements are equivalent to eigenvalue decomposition for block-diagonal matrices."],0,"Block elimination via the Schur complement avoids inverting the full large covariance matrix.","The Schur complement (A - BD^{-1}C) allows block matrix inversion; in the Kalman update, the innovation covariance S = HPH^T + R and the state covariance P update both exploit this structure.","Sparse EKF variants use Schur complements to update only the relevant sub-blocks of a large SLAM state covariance matrix, maintaining computational tractability."),
  q(1089,"Linear Algebra","calm","Hard",20,"How does PCA use eigenvectors of the covariance matrix for dimensionality reduction?",["It projects data onto eigenvectors with the largest eigenvalues, capturing maximum variance in fewer dimensions.","PCA finds eigenvectors of the raw data matrix itself rather than of the covariance matrix.","PCA uses the left singular vectors of the data matrix, which differ from covariance eigenvectors.","PCA projects data onto the null space of the covariance matrix to remove redundant dimensions."],0,"Top eigenvectors = directions of greatest variance — projecting onto them preserves the most information.","Cov = U*Lambda*U^T; projecting data onto the top k columns of U retains the k directions of greatest variance, providing the optimal linear dimensionality reduction in the least-squares sense.","Robot proprioception data is often compressed via PCA before training a neural control policy, reducing input dimensionality and improving generalisation."),
  q(1090,"Linear Algebra","calm","Hard",20,"Why must optimisation on the SO(3) manifold use Riemannian methods rather than Euclidean gradient descent?",["SO(3) is a curved manifold; Euclidean updates leave the manifold by violating R^T R = I.","SO(3) is a flat manifold but numerical issues accumulate requiring Riemannian correction steps.","Euclidean gradient descent on SO(3) always converges but only to local minima.","SO(3) can be isometrically embedded in R^6, making Euclidean methods fully valid."],0,"Curved manifold: adding a small matrix to a rotation matrix produces a non-rotation.","Adding epsilon to R generally yields a matrix that is not in SO(3); retraction steps (SVD re-projection, Cayley map, or exponential map) are required to project back onto the manifold after each gradient step.","Rotation averaging in multi-view SLAM uses Riemannian optimisation on SO(3) to find the mean rotation consistent with all relative rotation observations."),
  q(1091,"Linear Algebra","calm","Hard",20,"What does the Perron-Frobenius theorem guarantee for positive matrices in multi-robot coordination?",["A positive square matrix has a unique dominant real eigenvalue with a corresponding all-positive eigenvector.","All eigenvalues of any valid rotation matrix lie exactly on the complex unit circle.","The theorem applies only to strictly diagonal positive matrices with no off-diagonal entries.","Every stochastic matrix with positive entries is guaranteed to be invertible."],0,"Unique dominant positive eigenvalue with positive eigenvector guarantees power-iteration convergence.","Perron-Frobenius guarantees a unique largest real eigenvalue rho > 0 with a corresponding strictly positive eigenvector; all other eigenvalues have strictly smaller absolute value.","Consensus algorithms in multi-robot systems rely on this theorem to guarantee that repeated application of the communication matrix drives all agents to the same agreed state."),
  q(1092,"Linear Algebra","calm","Hard",20,"Why is LU decomposition preferred over repeated Gaussian elimination for multiple right-hand sides?",["A = LU is factorised once in O(n^3); each subsequent solve costs only O(n^2) via forward and backward substitution.","LU decomposition is always numerically more stable than Gaussian elimination for all matrix types.","LU factorisation requires no pivoting and is guaranteed to succeed for any invertible matrix.","LU is preferred exclusively for symmetric positive definite matrices and no others."],0,"Factorise A once; then each new right-hand side costs only O(n^2) substitution — amortise the O(n^3) cost.","Repeated control loops that solve the same inertia matrix system M(q)*tau = f as q changes slowly benefit enormously from cached LU factors; only the O(n^2) substitution step is needed each cycle.","Robot dynamics libraries store and reuse factorised inertia matrices across consecutive control cycles to reduce computational burden."),
  q(1093,"Linear Algebra","calm","Hard",20,"How does the Kronecker product enable vectorisation of matrix equations in robot learning and control?",["vec(AXB) = (B^T tensor A) vec(X) converts matrix equations into standard linear systems solvable by any linear solver.","The Kronecker product computes the element-wise (Hadamard) product of two matrices of the same size.","It combines two rotation matrices into a single compact 6-DOF rigid body transform.","Kronecker products apply only when both matrices are square and have identical dimensions."],0,"vec(AXB) = (B^T tensor A) vec(X) — matrix equations become linear in the vectorised unknown.","Many system identification and structured regression problems in robotics are linear in parameter matrices; the Kronecker product makes the linear structure explicit, enabling standard least-squares solvers.","Used in tensor regression, covariance estimation, and Gaussian process hyperparameter learning for robot dynamics identification."),

  // ── CALM: Probability ─────────────────────────────────────────────────────
  q(1094,"Probability","calm","Easy",10,"How is Bayes' theorem applied in robot state estimation?",["It computes the posterior P(state|obs) proportional to the likelihood times the prior over the state.","It computes the joint probability of two statistically independent events occurring together.","It states that the prior and posterior distributions are always Gaussian by assumption.","It applies only when the state space is finite and discrete rather than continuous."],0,"Posterior proportional to likelihood times prior — this update rule is the foundation of all recursive filters.","Bayes: P(x|z) ∝ P(z|x)*P(x); the Bayesian update is the foundation of all recursive state estimators: Kalman filter, particle filter, and occupancy grid filter all implement this rule.","P(x|z) is the posterior pose distribution given sensor reading z; the Kalman filter computes this update analytically for linear Gaussian systems."),
  q(1095,"Probability","calm","Easy",10,"What does the Markov property state in the context of robot state estimation?",["The future state is conditionally independent of the history given the current state.","All states in the sequence are mutually statistically independent of each other.","The robot state is always Gaussian distributed regardless of the nonlinear dynamics model.","Measurement noise is assumed to be white, zero-mean Gaussian at all timesteps."],0,"Past is irrelevant given present state — the current state summarises all relevant history.","P(x_{t+1}|x_t, x_{t-1}, ...) = P(x_{t+1}|x_t); this conditional independence enables recursive memoryless Bayesian filters that only need to maintain and update the current belief.","Most robot motion models satisfy the Markov property by augmenting the state vector to include velocity and bias terms."),
  q(1096,"Probability","calm","Easy",10,"What does the entropy of a probability distribution measure?",["The average uncertainty or information content of the distribution over its support.","The mean value of the distribution weighted by the variance of the distribution.","The squared L2 distance between the distribution and a reference Gaussian distribution.","The number of bits required to store the distribution parameters in memory."],0,"High entropy = high uncertainty spread; low entropy = concentrated, certain distribution.","H(X) = -sum p(x) log p(x); high entropy means the distribution is spread over many values (high uncertainty); low entropy means it is concentrated at a few values (low uncertainty).","Entropy minimisation is used in active robot perception to select actions that maximally reduce uncertainty about the map or object state."),
  q(1097,"Probability","calm","Easy",10,"What distinguishes aleatoric from epistemic uncertainty in robot learning?",["Aleatoric uncertainty is irreducible data noise; epistemic uncertainty is reducible model uncertainty from limited data.","Aleatoric uncertainty comes from the model structure; epistemic comes from measurement noise.","Both types are identical in nature and can both be reduced by collecting more training data.","Epistemic uncertainty only appears in explicitly Bayesian neural network architectures."],0,"Data noise is aleatoric (irreducible); model ignorance is epistemic (reducible with more data).","Aleatoric: inherent sensor noise or stochasticity that cannot be reduced by collecting more data; epistemic: model uncertainty that shrinks as training data increases and covers the input space better.","Safety-critical robots quantify both to make reliable decisions — only epistemic uncertainty can be reduced by active data collection."),
  q(1098,"Probability","calm","Easy",10,"What does the law of total probability compute and why is it used in state estimation?",["P(A) = sum P(A|B_i)*P(B_i) over a partition, marginalising out a hidden variable from the joint.","It computes probabilities of all events in a sample space and verifies they sum to more than one.","It computes the conditional probability of two dependent events occurring simultaneously.","It proves the expected value of any distribution equals its most probable mode value."],0,"Marginalise by summing over the hidden variable — this is the prediction step in any Bayes filter.","By summing or integrating over all values of a conditioning variable, total probability collapses the joint into a marginal.","Bayes filter prediction: p(x_t|z_{1:t-1}) = integral p(x_t|x_{t-1}) p(x_{t-1}|z_{1:t-1}) dx_{t-1} uses the law of total probability."),
  q(1099,"Probability","calm","Medium",15,"Why is KL divergence asymmetric and what does KL(P||Q) specifically measure?",["KL(P||Q) = E_P[log P/Q] measures the expected log-ratio under P; P and Q play distinct roles.","KL divergence is symmetric; KL(P||Q) always equals KL(Q||P) for any two distributions.","KL(P||Q) measures the entropy of the mixture distribution (P+Q)/2 at the midpoint.","KL divergence equals the squared Euclidean distance between the means of P and Q."],0,"D_KL(P||Q) = E_P[log P/Q] penalises regions where P is concentrated but Q is not.","Asymmetry: KL(P||Q) penalises where P has probability mass but Q does not (infinite penalty if support of P exceeds Q); KL(Q||P) penalises the opposite direction.","VAE training minimises KL(q(z|x)||p(z)), encouraging the approximate posterior to remain close to the prior while fitting the data."),
  q(1100,"Probability","calm","Medium",15,"What is the Cramer-Rao lower bound and why is it important for evaluating sensor fusion algorithms?",["It sets a lower bound on the variance of any unbiased estimator equal to the inverse of the Fisher information matrix.","It specifies the minimum number of samples required to produce a statistically consistent estimate.","It bounds the maximum likelihood estimate from above for Gaussian noise distributions.","It states that the posterior variance is always strictly larger than the prior variance after observing data."],0,"No unbiased estimator can achieve variance below (Fisher info)^{-1} — it sets the fundamental limit.","CRLB = J^{-1} where J is the Fisher information matrix; no unbiased estimator can have covariance smaller than this bound.","The Kalman filter achieves the CRLB for linear Gaussian systems; comparing other fusion estimators to the CRLB reveals their statistical efficiency."),
  q(1101,"Probability","calm","Hard",20,"How does Gaussian process regression handle model uncertainty differently from parametric regression?",["GP regression maintains a full posterior distribution over functions, providing calibrated uncertainty at every prediction point.","GP uses a fixed parameterised function form and provides no uncertainty estimate at test points.","GP regression requires strictly more training data than neural networks to achieve equivalent accuracy.","GP regression is mathematically identical to Bayesian linear regression with a fixed feature map."],0,"GP is non-parametric — the posterior is a distribution over functions, not just point estimates.","A GP is defined by a mean function and covariance kernel; conditioning on observed data gives a posterior GP with calibrated uncertainty intervals at every unobserved input point.","Safe robot motion planners use GP-based uncertainty to slow down or avoid regions of state space where the dynamics model is uncertain or poorly observed."),
  q(1102,"Probability","calm","Hard",20,"Why does the curse of dimensionality cause particle filters to fail in high-dimensional state spaces?",["The number of particles required to represent the posterior with fixed accuracy grows exponentially with dimension.","Particle filters are less affected by high dimensionality than any variant of the Kalman filter.","High dimensionality causes particle weights to become uniform, which paradoxically improves estimation.","The curse only affects grid-based histogram filters and not Monte Carlo particle-based filters."],0,"In d dimensions you need O((1/epsilon)^d) particles to achieve resolution epsilon — exponential cost.","In d dimensions, covering the state space to resolution epsilon needs O((1/epsilon)^d) particles; a full 6-DOF pose in 12D (with velocity) requires astronomically many particles for reliable coverage.","Rao-Blackwellisation exploits conditional independence to analytically marginalise some dimensions, reducing the effective dimensionality that requires particle representation."),
  q(1103,"Probability","calm","Hard",20,"What property of exponential family distributions makes Bayesian updating tractable in closed form?",["They have conjugate priors so the posterior remains in the same distributional family after each Bayesian update.","They have zero entropy, making the posterior deterministic after observing just one data point.","All exponential family distributions have Gaussian marginal distributions by the central limit theorem.","They automatically satisfy the Markov property, simplifying sequential Bayesian updates."],0,"Conjugate priors give closed-form posteriors — natural parameters update by simple addition.","For an exponential family likelihood, the conjugate prior update reduces to incrementing the natural parameters: tractable, exact, and computationally O(1) per observation.","Kalman filter exploits Gaussian conjugacy; Dirichlet-categorical exploits Dirichlet conjugacy; both enable exact closed-form Bayesian updates."),
  q(1104,"Probability","calm","Hard",20,"How does the EM algorithm handle latent variables in robot learning problems?",["E-step computes the expected complete-data log-likelihood under current parameters; M-step maximises it; iterate.","E-step draws random samples from the prior distribution; M-step performs one gradient update step.","EM directly maximises the marginal likelihood without ever introducing latent variables.","EM is only applicable to probabilistic models with strictly Gaussian latent variable distributions."],0,"Alternate between computing expected complete-data likelihood (E) and maximising it (M) until convergence.","EM monotonically increases the marginal likelihood by introducing a lower bound via Jensen's inequality; E-step tightens the bound, M-step maximises it.","Gaussian mixture models for robot obstacle clustering, hidden Markov models for gesture recognition, and motion primitive libraries all use EM for parameter estimation."),
  q(1105,"Probability","calm","Hard",20,"What does calibration mean for a probabilistic classifier and how is Expected Calibration Error measured?",["A calibrated classifier's predicted confidence p matches the true empirical accuracy among all inputs with predicted confidence p.","Calibration means the classifier achieves the highest possible accuracy on a held-out test set.","A calibrated model achieves equal precision and recall across all output classes.","Calibration measures the correlation coefficient between predicted probabilities and true binary labels."],0,"Confidence 0.8 should mean 80% accuracy in that confidence bucket — not more, not less.","ECE = sum_m |acc(B_m) - conf(B_m)| * |B_m|/n measures the weighted gap between average confidence and accuracy across M equal-width confidence bins.","Robot safety systems rely on well-calibrated uncertainty estimates to correctly decide when to trigger fallback behaviours based on perception confidence thresholds."),

  // ── CALM: Manipulators ────────────────────────────────────────────────────
  q(1106,"Manipulators","calm","Easy",10,"What is the distinction between position control and force control in robotic manipulation?",["Position control regulates end-effector geometry; force control regulates contact forces at the interface.","Force control is a special case of position control implemented with inverted gain signs.","Position control is used for free-space motion; force control is only used when the robot is stationary.","Both are implemented identically but use different physical sensors for their feedback signal."],0,"Position = where is the gripper; force = how hard is it pushing — completely different objectives.","In free space, position control drives the end effector to a target pose; in contact, force control regulates the interaction wrench, preventing excessive force that would damage the workpiece or robot.","Hybrid position/force controllers independently regulate position in unconstrained Cartesian directions and force in contact-constrained directions simultaneously."),
  q(1107,"Manipulators","calm","Easy",10,"What does the dexterity ellipsoid of a manipulator geometrically represent?",["The set of end-effector velocities achievable with a unit joint-velocity norm, showing directional bias.","The total volume of the reachable workspace bounded by all mechanical joint limits.","The set of end-effector forces achievable for a unit joint torque norm at the current pose.","The region around the end effector within which compliant contact forces can be applied."],0,"Dexterity ellipsoid = {J*v : ||v|| <= 1} — its shape reveals directional velocity bias.","The dexterity ellipsoid is the image of the unit joint velocity ball under the Jacobian map; elongated ellipsoids indicate preferred motion directions; a sphere indicates isotropic dexterity.","Manipulability measure w = sqrt(det(J*J^T)) summarises the ellipsoid volume as a scalar for trajectory planning."),
  q(1108,"Manipulators","calm","Easy",10,"What is the primary benefit of resolved-rate motion control for a robot manipulator?",["It directly specifies end-effector velocity in Cartesian space and computes joint rates via the pseudoinverse.","It eliminates the need for any forward kinematics computation in the control loop.","It guarantees minimum joint torques for all possible Cartesian motion commands.","It solves the full inverse kinematic problem analytically for arbitrary end-effector poses."],0,"Cartesian velocity command goes in; J-dagger maps it to joint rates in real time.","Resolved-rate control: q_dot = J-dagger * x_dot_desired; Cartesian velocity commands are intuitive for teleoperation and task-space control without solving the full IK problem at each step.","Teleoperated robotic surgery systems use resolved-rate control to map surgeon hand movements directly to instrument tip velocities."),
  q(1109,"Manipulators","calm","Medium",15,"How does the task-priority hierarchical framework handle conflicting objectives in redundant manipulators?",["Higher-priority tasks are satisfied exactly; lower-priority tasks are projected into the null space of all higher tasks.","All objectives are combined into a single scalar weighted cost and optimised jointly.","Task priorities are randomly reassigned at each control timestep to avoid local minima.","Higher-priority tasks receive larger feedback gains but can still be partially violated."],0,"Strict hierarchy via null-space projection: primary task first, secondary task in whatever remains.","tau = tau_1 + N_1^T*(tau_2 + N_2^T*(tau_3 + ...)); N_i is the null-space projector of all tasks ranked above task i, ensuring higher-priority tasks are never affected.","Whole-body controllers for humanoid robots use this framework to simultaneously manage balance, arm manipulation, gaze direction, and joint limit avoidance in a strict priority order."),
  q(1110,"Manipulators","calm","Medium",15,"What distinguishes force closure from grasp quality in robot grasp planning?",["Force closure is binary (stable or not); grasp quality measures the margin or robustness of that closure.","Force closure means the grasp is collision-free; quality measures the approach velocity at contact.","Both terms are synonymous and interchangeable throughout the grasp planning literature.","Force closure requires only point contacts; grasp quality is only defined for surface contacts."],0,"Closure is a yes/no property; quality is a continuous measure of how robustly that closure holds.","Force closure means no external wrench can be applied that the grasp cannot resist; quality metrics like the largest inscribed sphere in the grasp wrench space measure how robust the grasp is to perturbations.","Higher grasp quality scores predict that grasps will succeed under larger external disturbances during object transport or manipulation."),
  q(1111,"Manipulators","calm","Hard",20,"How does the wrist singularity of a 6-DOF spherical-wrist robot manifestly affect motion?",["When the middle wrist joint is at 0 or 180 degrees, two wrist axes align, collapsing orientation DOF and causing unbounded joint rates.","Wrist singularity occurs when all six joint angles simultaneously equal zero.","It manifests as complete loss of all three rotational degrees of freedom at the end effector.","Wrist singularity only affects robots with at least one prismatic joint in the kinematic chain."],0,"Middle wrist at 0 or 180 degrees makes joints 4 and 6 coplanar — one orientation DOF is lost.","With the middle wrist joint at 0 degrees, joints 4 and 6 have parallel rotation axes, reducing wrist orientation DOF from 3 to 2; tiny Cartesian orientation changes then require huge joint rates.","Robot path planners avoid wrist singularity by routing trajectories through configurations where the middle wrist joint stays away from 0 and 180 degrees."),
  q(1112,"Manipulators","calm","Hard",20,"What does the selection matrix S accomplish in hybrid position/force control?",["S decomposes the task space into force-controlled constrained directions and position-controlled unconstrained directions.","S scales impedance gains to achieve smooth force transitions at the moment of initial contact.","S selects which individual joints are torque-controlled versus position-controlled.","S enables or disables the integral action in the force feedback controller at contact."],0,"S projects the task into contact-constrained (force) and contact-free (position) orthogonal subspaces.","The contact constraint Jacobian defines which Cartesian directions are kinematically constrained; S decomposes the task into these subspaces for independent and simultaneous position and force regulation.","Robotic grinding, polishing, and peg-in-hole insertion use hybrid control with S computed from the workpiece surface normal at the contact point."),
  q(1113,"Manipulators","calm","Hard",20,"Why does dynamic manipulability differ fundamentally from kinematic manipulability?",["Dynamic manipulability accounts for inertia tensor and joint torque limits; kinematic manipulability considers only velocity and geometry.","Dynamic manipulability is simply kinematic manipulability scaled by the joint stiffness matrix.","Dynamic manipulability is only defined for robots with strictly more than six degrees of freedom.","Both measures are mathematically equivalent for robots with uniform mass distribution across all links."],0,"Kinematic: velocity ellipsoid from J; dynamic: acceleration ellipsoid from J, M, and torque limits.","The dynamic manipulability ellipsoid is {J*M^{-1}*tau : ||tau|| <= tau_max}, incorporating the inertia matrix and actuator torque limits; it characterises achievable Cartesian accelerations rather than velocities.","Trajectory planners exploit dynamic manipulability to plan motions that exploit high-acceleration directions for faster task execution."),
  q(1114,"Manipulators","calm","Hard",20,"How do compliant motion strategies exploit environmental constraints in robotic assembly tasks?",["Controlled stiffness and damping allow contact forces to guide motion geometrically rather than act as disturbances.","Maximum stiffness resists all contact forces during the entire insertion process.","Compliant strategies reduce all actuator forces to zero whenever contact is detected.","Environmental contact constraints are actively avoided throughout the entire compliant motion."],0,"Controlled compliance makes the constraint itself a guide — the environment helps position the part.","RCC (Remote Centre of Compliance) devices and active impedance control allow contact forces to correct small misalignments; the environment's geometry guides the part into position rather than fighting the contact.","Robotic peg-in-hole assembly with RCC devices achieves reliable insertion with alignment errors up to several millimetres without requiring sub-millimetre positioning accuracy."),
  q(1115,"Manipulators","calm","Hard",20,"Why does the Jacobian transpose gradient method converge unreliably near kinematic singularities?",["Near singularities, degenerate Jacobian directions have near-zero eigenvalues that amplify IK position errors.","J^T always converges to the correct solution regardless of the robot configuration.","J^T avoids singularity issues entirely because it never requires any matrix inversion step.","J^T converges reliably for position tasks but fails exclusively for orientation tracking tasks."],0,"Near singularity the gradient landscape is highly anisotropic — J^T cannot compensate for ill-conditioned curvature.","While J^T avoids explicit matrix inversion unlike J-dagger, the gradient-descent-like update step becomes highly ill-conditioned near singularities because the landscape is nearly flat in degenerate Jacobian directions.","Damped least squares (Levenberg-Marquardt regularisation) adds lambda*I to J^T*J, bounding the effective gain and providing singularity-robust Cartesian IK solutions."),

  // ── CALM: Computation ─────────────────────────────────────────────────────
  q(1116,"Computation","calm","Easy",10,"What architectural feature distinguishes a GPU from a CPU for deep learning inference?",["GPUs have thousands of simple SIMD cores optimised for data-parallel matrix operations; CPUs have fewer but more complex cores.","GPUs have larger individual caches and higher single-thread clock frequencies than CPUs.","CPUs are faster than GPUs for all robotics workloads without exception.","GPUs operate exclusively on integer data types; CPUs natively handle floating-point."],0,"Thousands of SIMD cores enable massive data parallelism — perfect for matrix and tensor operations.","Modern GPUs have thousands of CUDA cores optimised for FP16/FP8 tensor operations; CPUs have 16-64 complex out-of-order cores designed for serial and branching tasks.","Robot perception stacks run CNNs and transformer inference on GPU while planning, control, and middleware run on CPU concurrently in separate processes."),
  q(1117,"Computation","calm","Easy",10,"What is the purpose of Direct Memory Access (DMA) in embedded robot control systems?",["DMA transfers data between peripherals and memory without CPU involvement, freeing the CPU for control computation.","DMA doubles the effective processor clock speed for computation-intensive control tasks.","DMA is a memory protection mechanism preventing peripheral hardware from accessing program code.","DMA replaces the operating system task scheduler for real-time multi-task switching."],0,"CPU-free peripheral data transfer — sensors stream to RAM while the CPU runs the control algorithm.","DMA allows IMU, encoder, ADC, and communication peripheral data to stream directly into RAM; the CPU executes the control algorithm simultaneously without polling or interrupt overhead.","High-frequency motor controllers use DMA to stream encoder data at 100 kHz while the CPU runs the control loop at 10 kHz with deterministic timing."),
  q(1118,"Computation","calm","Easy",10,"What distinguishes throughput from latency in a robot perception pipeline?",["Throughput measures frames processed per second; latency measures the delay from sensor capture to decision output.","Throughput and latency are mathematically inverse of each other for all pipelined compute systems.","Latency is simply the mathematical inverse of throughput expressed in frames per second.","Throughput measures memory bandwidth utilisation; latency measures raw computation time."],0,"Throughput = rate; latency = per-sample delay — high throughput does not imply low latency.","High throughput with high latency means many frames are simultaneously in the pipeline; a self-driving car needs low latency (fast response) even if throughput is moderate.","A 10 Hz detection update loop may pipeline frames achieving high throughput while each individual frame takes 300 ms end-to-end latency."),
  q(1119,"Computation","calm","Medium",15,"Why does neural network weight quantisation reduce inference latency on edge robot hardware?",["INT8 or INT4 weights reduce memory footprint and enable faster integer SIMD operations than FP32.","Quantisation removes non-essential network layers, directly reducing total computation required.","Quantisation increases the effective weight precision, making the network faster to converge.","It replaces convolution with cross-correlation, which is computationally significantly cheaper."],0,"Smaller weights fit better in cache; integer SIMD executes faster than floating-point SIMD.","FP32 to INT8 reduces model size 4x; NPUs on devices like Coral Edge TPU execute INT8 ops at peak throughput orders of magnitude higher than FP32 on the same silicon area.","TensorRT and TFLite quantise robot vision models for sub-10 ms real-time inference on Jetson and Coral edge hardware."),
  q(1120,"Computation","calm","Medium",15,"What is the difference between preemptive and cooperative multitasking in a real-time robot OS?",["Preemptive: the OS can interrupt any task at any time; cooperative: tasks voluntarily yield CPU control.","Cooperative scheduling is always faster because it avoids context-switch overhead entirely.","Preemptive scheduling is only available on multicore processor architectures.","Both models guarantee the same worst-case response latency for all task priority levels."],0,"Preemptive forces context switch instantly; cooperative waits for voluntary yield — deadline risk.","Preemptive RTOS (FreeRTOS, Xenomai) can preempt any running task when a higher-priority task becomes ready, guaranteeing bounded worst-case response time for high-priority control tasks.","Motor control loops require preemptive scheduling to meet microsecond-level deadlines; a cooperative system risks missing those deadlines if a lower-priority task runs too long."),
  q(1121,"Computation","calm","Hard",20,"Why does Amdahl's law fundamentally limit the speedup of parallelising a robot perception pipeline?",["The non-parallelisable serial fraction s sets an upper bound of 1/s on total speedup regardless of processor count.","Amdahl's law only applies to GPU parallelism and not to CPU multicore parallelism.","Adding more processors always delivers linear speedup proportional to processor count.","Amdahl's law bounds memory bandwidth utilisation, not computational throughput."],0,"Serial bottleneck caps speedup at 1/s — infinite cores cannot exceed this fundamental limit.","Speedup = 1/(s + (1-s)/N); if 10% of the pipeline is serial, maximum possible speedup is 10x even with infinite parallel cores.","Pre-processing and post-processing serial steps in perception pipelines (e.g. data loading, NMS) often bottleneck GPU-accelerated neural inference, capping the achievable speedup."),
  q(1122,"Computation","calm","Hard",20,"How does the ONNX format benefit robot deployment across heterogeneous hardware platforms?",["ONNX provides a hardware-agnostic intermediate representation allowing models to be compiled for any target accelerator.","ONNX compresses neural network weights using lossless encoding for edge hardware deployment.","ONNX is a runtime engine that executes neural networks faster than TensorFlow or PyTorch natively.","ONNX automatically converts neural networks into optimised C code for MCU deployment."],0,"Train once in any framework, export to ONNX, compile for any target — hardware portability.","An ONNX model can be compiled by TensorRT (NVIDIA), OpenVINO (Intel), CoreML (Apple), or TFLite (ARM) for optimal hardware utilisation without rewriting the model.","Robot stacks typically train in PyTorch, export to ONNX, then compile for the target deployment platform whether Jetson, Coral, or a custom FPGA accelerator."),
  q(1123,"Computation","calm","Hard",20,"Why does neuromorphic computing offer potential advantages for event-driven robot perception?",["Spiking neural networks process only when input events arrive, matching event cameras with orders-of-magnitude lower power.","Neuromorphic chips run standard deep learning models faster than GPUs for all workloads.","Neuromorphic computing eliminates the need for digital-to-analogue conversion in sensor hardware.","Intel Loihi is faster than GPUs specifically for dense matrix operations in convolutional networks."],0,"Event-driven spikes match asynchronous event camera output — compute only when something changes.","Loihi's spike-based computation is activated only when input spikes arrive; idle power is near zero, and event-camera data arrives asynchronously matching the neuromorphic processing model naturally.","Research systems combining event cameras with Loihi chips demonstrate sub-millisecond obstacle detection at microwatt power levels for micro-UAV collision avoidance."),
  q(1124,"Computation","calm","Hard",20,"What is time-sensitive networking (TSN) and why is it important for distributed real-time robot control?",["TSN (IEEE 802.1 standards) adds deterministic latency guarantees and priority-based preemption to Ethernet.","TSN is a wireless communication protocol specifically designed to reduce RF interference in multi-robot environments.","TSN replaces CAN bus entirely by providing higher bandwidth without any latency guarantees.","TSN is a software-only scheduling algorithm for coordinating tasks on single-board computers."],0,"Standard Ethernet is best-effort; TSN adds determinism making it suitable for control traffic.","TSN adds credit-based shaping (802.1Qav), frame preemption (802.1Qbu), and time synchronisation (802.1AS) to standard Ethernet, guaranteeing bounded latency for control messages alongside best-effort traffic.","Industrial robot cells and autonomous vehicle compute networks use TSN to synchronise perception, planning, and actuation over a single Ethernet network with deterministic timing."),
  q(1125,"Computation","calm","Hard",20,"Why does the memory wall problem disproportionately affect sparse robot computation tasks like graph search?",["Sparse data structures cause irregular memory access patterns with poor cache locality, making memory bandwidth the bottleneck.","The memory wall only affects dense matrix operations in neural network convolution layers.","Sparse computation is inherently faster than dense computation regardless of memory access patterns.","Graph search is compute-bound rather than memory-bound because each node evaluation is arithmetically complex."],0,"Irregular graph pointer-chasing destroys cache locality — memory bandwidth becomes the bottleneck.","Dense neural network layers access memory sequentially (cache-friendly); graph edges point to arbitrary memory locations causing frequent cache misses, stalling the processor waiting for DRAM.","Hardware graph processing units (GPUs with hardware texture caches, GraphCore IPUs) use memory-aware data layouts to improve cache hit rates for path planning workloads."),

// ── COMPETITIVE: Numerical Optimization ──────────────────────────────────
  q(2001,"Numerical Optimization","competitive","Starter",15,"Why does gradient descent on a non-convex loss surface not guarantee a global minimum?",["Non-convex surfaces have local minima and saddle points where the gradient is zero but optimum is not reached.","Gradient descent always converges to the global minimum given a sufficiently small learning rate.","Non-convex loss surfaces contain only saddle points and no local minima at all.","Gradient descent is mathematically undefined for non-convex objective functions."],0,"Local stationary points are everywhere — gradient = 0 does not mean global optimum.","Without convexity, any point where the gradient vanishes could be a local min, local max, or saddle point; gradient descent follows local descent and cannot escape local minima in general.","Neural network training navigates non-convex loss landscapes using stochastic updates and momentum to escape shallow local minima."),
  q(2002,"Numerical Optimization","competitive","Starter",15,"What property makes quadratic programs efficiently solvable in robot real-time control loops?",["Convex quadratic objectives with linear constraints admit globally optimal solutions via active-set or interior-point methods.","QPs are efficient because they avoid computing any gradients of the objective function.","QPs are efficient only when the Hessian matrix is strictly diagonal.","QPs reduce to linear programs when equality constraints are added to the formulation."],0,"Convex QP = global optimum via KKT — polynomial-time solvable with warm-starting.","The KKT conditions for a convex QP form a linear complementarity problem directly solvable; active-set methods exploit the warm-start structure of successive similar problems.","Whole-body robot controllers solve QPs with hundreds of variables and constraints at 1 kHz using solvers like OSQP and qpOASES."),
  q(2003,"Numerical Optimization","competitive","Starter",15,"Why does Newton's method converge faster than gradient descent near a local minimum?",["The Hessian captures local curvature, scaling steps by inverse curvature for quadratic convergence near the optimum.","The Hessian replaces the gradient entirely, eliminating all first-order information from the update.","Newton's method needs fewer total function evaluations because it skips intermediate iterations.","The Hessian projects the gradient vector onto the feasible constraint set at each step."],0,"Curvature-scaled steps give quadratic convergence — error squares each iteration near the optimum.","Gradient descent ignores curvature, taking uniform steps; Newton's method scales by H^{-1}*grad, taking larger steps in flat curvature directions and smaller steps in steep directions.","Quasi-Newton methods (BFGS, L-BFGS) approximate H^{-1} to achieve super-linear convergence while avoiding the O(n^3) factorisation cost."),
  q(2004,"Numerical Optimization","competitive","Starter",15,"What do the KKT conditions provide at the solution of a constrained optimisation problem?",["Necessary conditions for a local optimum: stationarity, primal feasibility, dual feasibility, and complementary slackness.","Sufficient conditions for global optimality for any smooth optimisation problem whatsoever.","A direct algebraic solution to the primal problem without introducing dual Lagrange variables.","KKT conditions are applicable only to equality-constrained problems with no inequality constraints."],0,"Stationarity + feasibility + complementary slackness = necessary conditions at any constrained optimum.","At a constrained local minimum: grad_f + sum lambda_i*grad_g_i = 0, g_i <= 0, lambda_i >= 0, lambda_i*g_i = 0; for convex problems these are also sufficient.","Robot contact force optimisation checks KKT conditions to verify that the computed contact forces are at the optimum and all constraints are satisfied."),
  q(2005,"Numerical Optimization","competitive","Starter",15,"Why is warm-starting critical for model predictive control on embedded robot hardware?",["The previous solution provides a near-feasible initialisation, dramatically reducing convergence iterations.","Warm-starting mathematically guarantees global optimality of each MPC solution.","Warm-starting allows MPC to skip constraint satisfaction checks on the first iteration.","Warm-starting is equivalent to increasing the prediction horizon length by one step."],0,"Near-feasible init from the previous solution means convergence in 1-3 iterations instead of 20-50.","Adjacent MPC problems are similar; the previous solution shifted by one timestep satisfies constraints approximately, enabling warm-started solvers to converge in a few iterations rather than many.","Without warm-starting, cold-start interior-point methods may take 20-50 iterations, missing hard real-time deadlines on embedded controllers."),
  q(2006,"Numerical Optimization","competitive","Research",20,"Why do interior-point methods have polynomial complexity while simplex can be exponential in the worst case?",["Interior-point follows a central path through the feasible interior with provably O(sqrt(n)) iterations; simplex traverses vertices.","Interior-point methods avoid the feasible set entirely; simplex always stays on the feasible boundary.","Simplex has polynomial average-case complexity; interior-point methods are exponential in practice.","Both have identical worst-case theoretical complexity; differences are only empirical."],0,"Central path: polynomial iteration count; vertex walk: exponentially many vertices in degenerate cases.","Interior-point reduces a primal-dual system at each step with iteration count O(sqrt(n)*log(1/epsilon)); simplex can visit exponentially many vertices in degenerate LP instances.","OSQP and qpOASES implement primal-dual interior-point methods standard in the robot control toolchain for reliable real-time performance."),
  q(2007,"Numerical Optimization","competitive","Research",20,"How does ADMM exploit problem structure for distributed multi-robot optimisation?",["ADMM decomposes the problem into independent subproblems per robot, coordinating via dual variable updates.","ADMM is a gradient method alternating between primal and dual gradient descent steps.","ADMM requires a centralised coordinator that solves the full joint optimisation each iteration.","ADMM converges only for purely quadratic objectives without any inequality constraints."],0,"Decompose → solve locally → update dual variables → consensus — no central solver needed.","ADMM: minimise f(x)+g(z) s.t. Ax+Bz=c; the x-update, z-update, and dual update are each solvable independently, enabling distributed computation across robots.","Multi-robot trajectory planning uses ADMM to allow robots to independently optimise their own trajectories while converging to a consistent joint plan without sharing full state information."),
  q(2008,"Numerical Optimization","competitive","Research",20,"What makes contact-implicit trajectory optimisation fundamentally harder than contact-explicit methods?",["Contact-implicit includes contact modes as optimisation variables, creating non-smooth complementarity constraints.","Contact-implicit methods are simpler because they eliminate discrete mode enumeration entirely.","Contact-explicit must solve mixed-integer programs; contact-implicit avoids any integer variables.","The difficulty is identical; only the mathematical representation of the solution differs."],0,"Complementarity f_n*d = 0 creates non-convex non-smooth constraints — hard to solve reliably.","Contact complementarity conditions: f_n >= 0, d >= 0, f_n*d = 0 create non-smooth constraints; combined with continuous dynamics this creates a mathematical program with complementarity constraints (MPCC).","DIRTREL, CALIPSO, and contact-implicit iLQR address this through relaxation and smooth approximation of complementarity conditions."),
  q(2009,"Numerical Optimization","competitive","Research",20,"Why does iLQR achieve super-linear convergence near the optimal trajectory despite local quadratic approximations?",["Near the optimum, the quadratic approximation is tight; the backward Riccati pass solves local LQR exactly, giving Newton-like convergence.","iLQR converges slowly because it ignores second-order coupling between state and control variables.","Super-linear convergence comes from a line search that doubles the step size at each iteration.","iLQR converges at exactly linear rate; super-linear convergence applies only to full DDP."],0,"Tight local quadratic + exact Riccati = one Newton step per iteration near optimum.","iLQR's backward pass solves the local LQR problem exactly for the quadratic approximation, which is equivalent to one Newton step on the first-order optimality conditions of the trajectory optimisation problem.","Differential Dynamic Programming (DDP) adds second-order state-action coupling terms for even faster convergence at the cost of more computation per backward pass."),
  q(2010,"Numerical Optimization","competitive","Research",20,"How does sum-of-squares (SOS) programming certify global feasibility for polynomial robot planning problems?",["SOS relaxes polynomial non-negativity to an SDP whose feasibility certifies the polynomial has no negative values.","SOS finds the global optimum by factoring the objective polynomial into linear root factors.","SOS applies only to polynomial objectives that are known a priori to be convex.","SOS relaxations are always tight with zero duality gap for any polynomial programme."],0,"SOS-feasibility via SDP certifies p(x) >= 0 globally — provides a rigorous lower bound on the minimum.","A polynomial p(x) >= 0 for all x iff it can be written as a sum of squares of polynomials; checking SOS-feasibility requires solving an SDP, providing a globally valid certificate.","DSOS and SDSOS use cheaper polyhedral relaxations for real-time safety verification in robot motion planning."),
  q(2011,"Numerical Optimization","competitive","Research",20,"What is the Moreau envelope and how does it create a smooth approximation for non-smooth robot optimisation?",["The Moreau envelope infimal-convolves f with a quadratic penalty, creating a differentiable approximation with identical minimisers.","The Moreau envelope adds a hard smoothness constraint that enforces trajectory continuity.","The Moreau envelope converts inequality constraints into equality constraints via a slack variable.","The Moreau envelope is identical to the Lagrangian dual function for convex constrained problems."],0,"M_gamma(x) = inf_y [f(y) + ||x-y||^2/(2*gamma)] — smooth everywhere, same minimisers as f.","The Moreau envelope M_gamma*f(x) = inf_y[f(y) + (1/2*gamma)||x-y||^2] is C1 even when f is non-smooth; its gradient is (x - prox_gamma*f(x))/gamma, enabling smooth gradient descent on non-smooth objectives.","Proximal gradient methods for contact-rich manipulation use Moreau envelopes of contact force constraints to enable smooth optimisation of discontinuous contact problems."),
  q(2012,"Numerical Optimization","competitive","Research",20,"How does Pontryagin's minimum principle specify the structure of optimal control solutions via the Hamiltonian?",["PMP states optimal control minimises H = L + lambda^T*f at each instant; the costate evolves by adjoint equations.","PMP is a finite-difference discretisation of the continuous Hamilton-Jacobi-Bellman equation.","The Hamiltonian in PMP equals the total mechanical energy of the robot system.","PMP applies only to linear time-invariant systems; nonlinear systems require HJB directly."],0,"u* = argmin_u H(x,u,lambda) at each t; lambda satisfies lambda_dot = -partial_H/partial_x.","H(x,u,lambda) = L(x,u) + lambda^T*f(x,u); optimal control minimises H pointwise; the costate lambda evolves backward in time via lambda_dot = -dH/dx, giving necessary conditions for optimality.","Indirect trajectory optimisation methods solve the two-point boundary value problem arising from PMP to find minimum-energy or minimum-time robot trajectories."),
  q(2013,"Numerical Optimization","competitive","Research",20,"Why does the primal-dual interior-point method become numerically ill-conditioned near active constraint boundaries?",["Slack variables approach zero near active constraints, making the KKT system matrix ill-conditioned.","Ill-conditioning only occurs for non-convex optimisation problems near their local minima.","The KKT system matrix remains well-conditioned throughout all interior-point iterations.","Ill-conditioning arises only when the problem has strictly more equality constraints than variables."],0,"Slacks -> 0 near active constraints: KKT matrix has 1/s terms that blow up as s -> 0.","The KKT system includes diagonal terms proportional to 1/s_i (slack inverse); as slacks approach zero near active constraints these terms dominate and the condition number of the KKT matrix grows without bound.","Mehrotra predictor-corrector steps and explicit regularisation of the KKT system mitigate this ill-conditioning in practice."),
  q(2014,"Numerical Optimization","competitive","Research",20,"What advantage does the Frank-Wolfe algorithm provide for robot motion planning under L1-ball constraints?",["Frank-Wolfe linearises the objective and solves a cheap linear program over the constraint set, producing sparse iterates.","Frank-Wolfe is faster than projected gradient because it computes the Hessian at each iteration.","Frank-Wolfe is mathematically equivalent to gradient descent with a fixed predetermined step size.","Frank-Wolfe avoids computing gradients of the objective function at each iteration."],0,"LMO over the L1 ball is cheap (soft-threshold), and iterates are naturally sparse — no projection needed.","At each step: s = argmin_{x in C} grad_f(x_t)^T*x (linear minimisation oracle), then x_{t+1} = (1-gamma)*x_t + gamma*s; the L1-ball LMO is O(n) soft-thresholding and the iterates are automatically sparse.","Sparse waypoint generation for robot trajectories uses Frank-Wolfe to find compact motion representations with few active constraints."),
  q(2015,"Numerical Optimization","competitive","Research",20,"How do chance constraints in stochastic MPC differ from robust constraints and why are they computationally harder?",["Chance constraints require P(g(x,w) <= 0) >= 1-epsilon, coupling the constraint to the full uncertainty distribution.","Chance constraints are identical to robust constraints but with a slightly tighter probability threshold.","Stochastic MPC with chance constraints replaces all constraints with soft quadratic penalty terms.","Chance constraints are computationally easier because they allow more frequent constraint violations."],0,"Robust = worst-case always satisfied; chance = violated at most epsilon probability — very different feasible sets.","Robust: g(x,w) <= 0 for all w in W (deterministic, conservative); chance: P(g(x,w) <= 0) >= 1-epsilon — the feasible set depends on the full distribution of w, requiring scenario sampling or Gaussian approximation.","Autonomous vehicle MPC uses chance constraints to handle uncertain pedestrian trajectory predictions while allowing bounded probability of constraint violation."),

  // ── COMPETITIVE: Reinforcement Learning ──────────────────────────────────
  q(2016,"Reinforcement Learning","competitive","Starter",15,"What distinguishes on-policy from off-policy reinforcement learning?",["On-policy evaluates the current behaviour policy; off-policy learns a target policy different from the data-collection policy.","On-policy methods require an environment model; off-policy methods are always model-free.","Off-policy algorithms always converge faster than on-policy algorithms.","On-policy methods are restricted to discrete action spaces; off-policy handles continuous actions."],0,"Target policy vs behaviour policy — on-policy learns from its own actions; off-policy from any data.","SARSA is on-policy (evaluates the policy generating the data); Q-learning is off-policy (targets the greedy policy regardless of the behaviour policy that collected the experience).","Off-policy learning enables experience replay with data collected by any past policy, dramatically improving sample efficiency."),
  q(2017,"Reinforcement Learning","competitive","Starter",15,"Why does the temporal difference error drive learning in value-based reinforcement learning?",["TD error = r + gamma*V(s') - V(s) measures the discrepancy between estimates and bootstrapped returns without full trajectories.","TD error measures the mean-squared difference between predicted and actual action selections.","TD learning requires complete episodes before any weight update, unlike Monte Carlo methods.","TD error equals the analytical gradient of the policy with respect to the state value function."],0,"Bootstrap target minus current estimate = online signal — no need to wait for episode termination.","TD combines one-step reward with a bootstrapped estimate of future value; this signal is available at every timestep without waiting for episode termination.","Q-learning, DQN, TD3, and SAC all use temporal difference errors as their core learning signal."),
  q(2018,"Reinforcement Learning","competitive","Starter",15,"What is the policy gradient theorem and why is it important for continuous action spaces?",["It provides grad_J(theta) = E[grad_log_pi(a|s) * Q(s,a)], enabling direct gradient ascent on the policy.","It proves all gradient-based policies converge to the globally optimal policy asymptotically.","It converts RL to a supervised learning problem using TD errors as regression targets.","It applies only to deterministic policies and not to stochastic action distributions."],0,"grad_J = E[grad_log_pi * Q] — differentiates expected return without differentiating through the environment.","The theorem avoids differentiating through the environment transition function, making policy gradient tractable for continuous action spaces where Q-learning's argmax is intractable.","REINFORCE, PPO, SAC, and TD3 all build on or extend the policy gradient theorem."),
  q(2019,"Reinforcement Learning","competitive","Starter",15,"What specific problem does the actor-critic architecture solve compared to pure policy gradient methods?",["The critic provides a value-function baseline that reduces policy gradient estimate variance without adding bias.","The actor-critic architecture completely eliminates the need for any value function estimation.","The critic replaces the environment reward signal with a learned auxiliary reward model.","The actor-critic combines model-based planning and model-free policy gradient in one architecture."],0,"Critic as baseline reduces variance of grad_J estimates — lower variance = faster, stabler learning.","REINFORCE uses full Monte Carlo returns with high variance; the critic's value estimate V(s) or Q(s,a) as baseline reduces variance without introducing bias, enabling stable gradient estimation.","A2C, A3C, PPO, and SAC all use actor-critic architectures with various critic formulations."),
  q(2020,"Reinforcement Learning","competitive","Starter",15,"Why does experience replay stabilise DQN training on robot tasks?",["Random sampling of past transitions decorrelates the sequential data, providing approximately i.i.d. training batches.","Experience replay increases the total number of effective environment interactions per wall clock hour.","Experience replay prevents the Q-network from forgetting early experience through catastrophic forgetting.","Experience replay completely eliminates the need for a separate target network in DQN."],0,"Sequential transitions are highly correlated — random sampling breaks correlation and stabilises SGD.","Sequential (s,a,r,s') transitions are strongly correlated; sampling randomly from a large replay buffer approximates i.i.d. data, making stochastic gradient descent stable on neural network value functions.","Prioritised experience replay samples transitions with high TD error more frequently, improving learning efficiency on rare but important transitions."),
  q(2021,"Reinforcement Learning","competitive","Research",20,"Why does the deadly triad (function approximation + bootstrapping + off-policy) cause Q-learning instability?",["The bootstrap target depends on the same approximator being updated; off-policy data creates a divergent fixed-point iteration.","The deadly triad is a purely theoretical concern; DQN with target networks is stable for all tasks.","Bootstrapping is the sole cause of instability; function approximation and off-policy are separately harmless.","The triad causes instability only in continuous state spaces with non-linear function approximators."],0,"Bootstrap from the same approximator + off-policy updates = fixed-point iteration that can diverge.","The update target r + gamma*max_a Q(s',a) uses Q theta being updated; with off-policy data the fixed-point may not exist or may be unstable (Baird's counterexample demonstrates guaranteed divergence).","Target networks in DQN decouple the bootstrap target from the online update, stabilising the fixed-point iteration."),
  q(2022,"Reinforcement Learning","competitive","Research",20,"How does soft RL (maximum entropy RL) change the optimisation objective compared to standard RL?",["Soft RL maximises expected return plus expected policy entropy at each timestep, encouraging exploration.","Soft RL removes the entropy term from the objective to simplify the policy gradient computation.","Maximum entropy RL maximises only entropy while completely ignoring the environment reward signal.","Soft RL is identical to standard RL but uses a different temperature coefficient in the Bellman equation."],0,"Reward + alpha*H(pi) — entropy bonus prevents premature commitment to narrow deterministic policies.","J(pi) = E[sum gamma^t * (r_t + alpha*H(pi(*|s_t)))]; the entropy bonus discourages deterministic policies, maintaining diverse exploration throughout training.","SAC (Soft Actor-Critic) maximises this objective with automatically tuned temperature alpha for sample-efficient robot manipulation learning."),
  q(2023,"Reinforcement Learning","competitive","Research",20,"Why does distributional RL (C51, QR-DQN) outperform standard Q-learning on many robot tasks?",["Distributional RL models the full return distribution, preserving multimodality and enabling risk-sensitive optimisation.","Distributional RL is faster because it requires fewer total environment interactions than Q-learning.","Distributional RL outperforms Q-learning exclusively in sparse-reward environment settings.","Distributional methods eliminate bootstrapping entirely, avoiding the deadly triad instability."],0,"Full distribution vs scalar mean — multimodal returns cannot be represented by their expectation alone.","Standard Q-learning collapses the return distribution to its mean, losing information about variance, multimodality, and tail risks; distributional RL preserves this information for richer representation learning.","Distributional critics improve value estimation quality and feature learning even for tasks without explicit risk sensitivity requirements."),
  q(2024,"Reinforcement Learning","competitive","Research",20,"How does hindsight experience replay (HER) address the sparse reward problem without modifying the reward function?",["HER relabels failed trajectories with the actually achieved goal, creating artificial successes as training data.","HER adds intermediate sub-goal rewards along the trajectory to densify the reward signal.","HER uses a generative model to hallucinate successful trajectories from failed attempts.","HER modifies the discount factor gamma to weight the sparse terminal reward more heavily."],0,"Relabel failures with the achieved goal — every trajectory succeeds at reaching somewhere.","For a trajectory ending at s_T != g_desired, HER creates a new transition with goal g' = s_T and reward 1 (success); this transforms failures into successful demonstrations of reaching a nearby goal.","Multi-goal robot manipulation training with HER + DDPG or SAC converges on tasks where pure RL with sparse 0/1 reward completely fails to learn."),
  q(2025,"Reinforcement Learning","competitive","Research",20,"What theoretical property of the Bellman operator guarantees Q-learning convergence in tabular settings?",["The Bellman optimality operator is a gamma-contraction under L-infinity norm, guaranteeing a unique fixed point Q*.","Q-learning convergence is guaranteed by the replay buffer ensuring sufficient state-action exploration.","The Bellman operator is a contraction mapping only for deterministic MDPs without stochastic transitions.","Convergence is only guaranteed when the learning rate remains constant throughout all training."],0,"Gamma-contraction + Banach fixed-point theorem: unique Q* exists and iterates converge to it.","||TQ1 - TQ2||_inf <= gamma||Q1 - Q2||_inf for gamma < 1; Banach's fixed-point theorem guarantees a unique Q* and convergence of Q-learning with appropriate learning rate scheduling.","Function approximation breaks this contraction property, requiring target networks and gradient clipping to stabilise Q-learning."),
  q(2026,"Reinforcement Learning","competitive","Research",20,"How does GAIL differ from behavioural cloning for robot imitation learning?",["GAIL trains a discriminator to distinguish agent from expert trajectories and uses it as a reward signal for RL.","GAIL directly minimises the L2 distance between agent actions and expert actions at each state.","GAIL is mathematically equivalent to behavioural cloning with additional data augmentation.","GAIL requires a complete known model of the environment dynamics to train the policy."],0,"GAIL matches occupancy measures adversarially; BC regresses to expert actions directly — fundamentally different.","BC minimises E[||pi(s) - pi_E(s)||^2] with compounding distribution shift errors; GAIL minimises the JS divergence between agent and expert state-action occupancy measures via a learned discriminator reward.","GAIL avoids the compounding distribution shift problem that causes BC policies to degrade over long robot manipulation task horizons."),
  q(2027,"Reinforcement Learning","competitive","Research",20,"Why does RLHF require a learned reward model rather than directly using human preference labels as rewards?",["Human preferences are sparse and expensive; a reward model generalises from few comparisons to dense signals.","Human labels are too noisy to be useful; the reward model filters and denoises the labels completely.","Modern RLHF implementations directly use human labels without any reward model.","The reward model converts categorical preference labels into continuous differentiable control signals."],0,"Few expensive preference comparisons generalise to dense training signals via the reward model.","Collecting human preferences on every state-action pair visited during RL training is infeasible; the reward model r_theta(s,a) trained on pairwise comparisons generalises to unseen states.","InstructGPT, Claude, and robot manipulation alignment systems use RLHF to align policy behaviour with human intent."),
  q(2028,"Reinforcement Learning","competitive","Research",20,"What is meta-RL and how does MAML address non-stationary robot deployment environments?",["Meta-RL learns an initialisation that adapts quickly to new MDPs; MAML finds theta such that few gradient steps reach optimality for any task in the distribution.","MAML prevents non-stationarity by using target networks to stabilise the value function.","Meta-RL addresses non-stationarity by averaging gradients across all previously seen environments.","Standard policy gradient handles non-stationarity correctly if the learning rate is small enough."],0,"MAML finds theta_0 such that theta_0 - alpha*grad_L_tau is near-optimal for any task tau — fast adaptation.","MAML trains theta to minimise the post-adaptation loss across a distribution of tasks; at test time, one or a few gradient steps from theta_0 rapidly adapts the policy to the new task or environment.","MAML-based controllers enable robots to rapidly adapt to new object masses, tool geometries, or terrain conditions with minimal real-world data collection."),
  q(2029,"Reinforcement Learning","competitive","Research",20,"Why does double DQN specifically address overestimation bias in standard DQN value targets?",["Double DQN decouples action selection (online network) from action evaluation (target network), removing the max-bias correlation.","Double DQN uses two completely separate replay buffers to reduce variance in target computation.","Double DQN computes the geometric mean of two independent Q-value estimates.","Double DQN is identical to standard DQN but uses twice the target network update frequency."],0,"Decouple selection from evaluation — argmax in online network, evaluation in target network removes the upward bias.","Standard DQN: y = r + gamma*max_a Q_target(s',a) where selection and evaluation both use Q_target, inflating Q due to noise correlation; Double DQN: y = r + gamma*Q_target(s', argmax_a Q_online(s',a)).","Double DQN improves policy performance in robot navigation and manipulation tasks where overestimated Q-values lead to poor action selection."),
  q(2030,"Reinforcement Learning","competitive","Research",20,"What is the fundamental credit assignment challenge in long-horizon robot manipulation tasks?",["Rewards from successful completion may be delayed by hundreds of steps, making gradient signals at early actions vanishingly small.","Rewards always occur immediately after every individual action in manipulation tasks.","Long-horizon manipulation tasks make exploration unnecessary because good strategies are obvious.","Long-horizon tasks eliminate the temporal reasoning requirement from the learning problem."],0,"Reward at step 100 barely reaches step 1 via gamma^99 discounting — early actions get no credit.","A successful grasp or assembly may depend critically on decisions made 50-100 steps earlier; the discounted policy gradient signal gamma^t decays exponentially, making those early decisions receive near-zero credit.","Hierarchical RL, reward shaping, and goal-conditioned learning (HER) all address this delayed credit assignment problem."),

  // ── COMPETITIVE: Foundation Models ───────────────────────────────────────
  q(2031,"Foundation Models","competitive","Starter",15,"Why do LLMs trained on internet text not automatically possess grounded physical understanding?",["Text describes the physical world without embodied sensorimotor experience; spatial and force reasoning are only partially captured.","LLMs lack physical understanding because they are not trained on sufficient quantities of text data.","Physical grounding is absent because LLMs use attention mechanisms instead of convolutional processing.","LLMs actually have complete physical understanding accessible through carefully designed prompts."],0,"Language approximates physics without experiencing it — symbol grounding requires sensorimotor loops.","The symbol grounding problem: words like 'weight' or 'slippery' refer to physical experiences absent from text; a model trained only on descriptions cannot reliably reason about forces, geometry, or contact.","PaLM-E and RT-2 attempt to ground LLMs through joint training on robot sensor-action data alongside language data."),
  q(2032,"Foundation Models","competitive","Starter",15,"What does the neural scaling hypothesis state about large foundation models?",["Model capability improves predictably with scale (parameters, data, compute) following power-law scaling laws.","Scaling beyond a threshold causes capability degradation due to severe overfitting.","Scaling laws apply only to language models and not to vision or robot action models.","Doubling model parameters always exactly doubles model accuracy on any given benchmark."],0,"Log-linear scaling of loss with N, D, and C — predictable capability gains from scaling up.","Kaplan et al. showed cross-entropy loss scales as power laws with model size N, dataset size D, and compute C; this motivated the scaling-up approach leading to GPT-4, Gemini, and robot foundation models.","The hypothesis underpins investment in large robot foundation models like RT-2, Octo, and OpenVLA."),
  q(2033,"Foundation Models","competitive","Starter",15,"What distinguishes in-context learning (ICL) from fine-tuning in foundation models?",["ICL adapts behaviour via examples in the prompt at inference time; fine-tuning updates model weights on task data.","ICL and fine-tuning are mathematically identical except ICL uses a larger effective learning rate.","ICL requires explicit gradient computation through the model; fine-tuning does not use gradients.","ICL only works for classification tasks; fine-tuning is required for generation and control tasks."],0,"ICL: prompt with examples, no weight update; fine-tuning: gradient descent on task data, weights change.","ICL uses the model's in-weights knowledge to process demonstration examples in the context window, producing predictions without any parameter update; fine-tuning explicitly adjusts weights via backpropagation.","Robot task systems use ICL with a few demonstration descriptions to specify new tasks at test time without any retraining."),
  q(2034,"Foundation Models","competitive","Starter",15,"What distinguishes a vision-language-action (VLA) model from a standard vision-language model (VLM)?",["VLAs additionally output continuous or discrete robot actions alongside or instead of text outputs.","VLMs are always larger than VLAs and require significantly more compute at inference time.","VLAs replace the language encoder with a proprioceptive sensor encoder for robot state input.","VLMs output actions implicitly through text descriptions; VLAs output them as explicit control signals."],0,"VLA = VLM + action head: image + language + state -> action vector, not just text output.","VLM: image + text -> text or classification; VLA: image + language instruction + robot state -> action vector at each timestep; the action prediction head bridges perception and low-level robot control.","RT-2, Octo, and OpenVLA are VLA models trained on large-scale robot demonstration datasets across diverse manipulation tasks."),
  q(2035,"Foundation Models","competitive","Starter",15,"Why is chain-of-thought (CoT) prompting effective for multi-step robot task planning with LLMs?",["CoT elicits explicit intermediate reasoning steps, decomposing complex tasks into subgoals and reducing compounding errors.","CoT works because longer generated outputs statistically contain more accurate information.","CoT reduces computational cost by allowing the model to skip full forward passes for simple subtasks.","CoT is only effective for mathematical reasoning tasks and does not benefit spatial planning."],0,"Externalising intermediate steps prevents compounding errors at each sequential reasoning hop.","Without CoT, LLMs must compress multi-step reasoning into a single output generation, accumulating errors; step-by-step reasoning externalises working memory and allows error correction at each step.","SayCan, ProgPrompt, and Code-as-Policies use CoT-style decomposition for grounded robot instruction following."),
  q(2036,"Foundation Models","competitive","Research",20,"Why does catastrophic forgetting challenge fine-tuning foundation models for specific robot manipulation tasks?",["Weight updates for the new task overwrite weights encoding general knowledge from pretraining, destroying prior capabilities.","Catastrophic forgetting selectively affects only attention layer weights, not feedforward blocks.","Fine-tuning prevents forgetting because a lower learning rate prevents large weight modifications.","Catastrophic forgetting is irrelevant if the deployment robot only needs to perform the fine-tuned task."],0,"Neural networks have no separate memory — updating weights for task B overwrites representation for task A.","The gradient updates for new task data modify the same weights that encode general world knowledge from pretraining; the extent of forgetting is proportional to the gradient overlap between tasks.","LoRA, adapter modules, and Elastic Weight Consolidation (EWC) mitigate forgetting by constraining which weights can be modified during fine-tuning."),
  q(2037,"Foundation Models","competitive","Research",20,"How does Low-Rank Adaptation (LoRA) enable parameter-efficient fine-tuning of large robot foundation models?",["LoRA constrains weight updates to a low-rank factorisation delta_W = A*B, reducing trainable parameters by 100-1000x.","LoRA freezes all model weights and adds a completely separate small network head per task.","LoRA quantises all model weights to INT4 precision to reduce memory during fine-tuning.","LoRA applies gradient checkpointing to reduce memory consumption during backpropagation."],0,"delta_W = A*B with rank r << min(d,k) — only 2*r*d parameters instead of d*k.","Instead of updating the full d*k weight matrix, LoRA trains A (shape d*r) and B (shape r*k) with r typically 4-64, reducing trainable parameters 100-1000x while maintaining fine-tuning quality.","RT-2, Octo, and OpenVLA use LoRA to adapt large vision-language foundation models to new robot embodiments and task domains efficiently."),
  q(2038,"Foundation Models","competitive","Research",20,"Why does tokenising robot actions in VLA models create a tension between action precision and vocabulary size?",["Finer action discretisation requires exponentially larger vocabularies that impose computational and representational costs.","Finer tokenisation improves precision because discrete tokens can represent arbitrarily precise values.","The tension applies only to joint-space action representations and not to Cartesian end-effector actions.","Larger vocabularies always improve policy performance by providing more precise action resolution."],0,"6-DOF at 0.001 rad resolution = 10^6 tokens per joint — exponential vocabulary growth.","At 256-bin discretisation per DOF, a 6-DOF arm needs 256^6 ~ 2.8*10^14 joint-space tokens; finer resolution explodes the vocabulary, stressing the softmax output head and increasing inference cost.","Diffusion policy heads and flow-matching decoders generate continuous actions directly, avoiding the tokenisation precision-vocabulary trade-off entirely."),
  q(2039,"Foundation Models","competitive","Research",20,"What is the cross-embodiment generalisation problem and why is it a fundamental challenge for robot foundation models?",["Different robots have heterogeneous morphologies, action spaces, and sensor suites making direct policy transfer infeasible.","Cross-embodiment generalisation is straightforward because all robots share identical joint-space representations.","The problem is purely visual — different cameras capture different image distributions but kinematics are shared.","Cross-embodiment is fully solved by using natural language task instructions as a universal interface."],0,"Morphology + DOF + sensor type + action range all differ — there is no universal robot action space.","A policy trained on a 7-DOF arm cannot directly control a 6-DOF arm, a mobile manipulator, or a biped; action dimensions, joint ranges, and dynamics differ fundamentally across embodiments.","RT-X and Open-X Embodiment aggregate data from 22+ robot embodiments to learn transferable visual-semantic representations that partially generalise across morphologies."),
  q(2040,"Foundation Models","competitive","Research",20,"How does the emergent ability phenomenon complicate robot capability prediction from scaling law extrapolation?",["Emergent abilities appear discontinuously at certain scale thresholds, making extrapolation from smaller models unreliable.","Emergent abilities always follow smooth power-law scaling laws and are readily predictable.","Emergence occurs exclusively in language tasks and never in robot action generation or planning.","Emergent abilities are artefacts of benchmark design and disappear with more carefully designed evaluations."],0,"Discontinuous capability jumps at unpredictable scale thresholds invalidate smooth extrapolation.","Tasks like multi-step reasoning suddenly appear at ~10^22-10^23 FLOP training budgets without any gradual precursor; no smooth extrapolation from smaller models can predict when these transitions occur.","This makes it fundamentally difficult to predict when robot VLA models will acquire qualitatively new capabilities like tool use or multi-step assembly from smaller-scale experiments."),
  q(2041,"Foundation Models","competitive","Research",20,"How does retrieval-augmented generation (RAG) benefit grounded robot task planning?",["RAG retrieves relevant scene-specific knowledge at query time, providing up-to-date context without retraining.","RAG is faster than parametric models because it reduces the number of attention layers needed.","RAG eliminates hallucination entirely by always grounding responses in factually correct retrieved documents.","Pure parametric models always outperform RAG because they have more parameters encoding knowledge."],0,"Retrieve current scene knowledge at runtime — parametric memory is static; RAG is dynamic.","Parametric model knowledge is frozen after training; RAG queries external knowledge bases (environment maps, object databases, task manuals) at inference time, providing task-specific and up-to-date grounding.","Robot task planners use RAG to retrieve object affordances, workspace geometry, and task-specific constraints that were not available during model training."),
  q(2042,"Foundation Models","competitive","Research",20,"What is the world model bottleneck hypothesis and how does latent video prediction address it?",["Robust robot behaviour requires predicting future states; latent video models learn compact predictive world representations.","The bottleneck hypothesis claims model parameter count is the primary performance bottleneck.","Latent video prediction is useful only for data augmentation, not for planning or policy learning.","The world model bottleneck is solved by increasing the language model's context window length."],0,"Without world model predictions, the agent cannot mentally simulate action consequences before acting.","Without a world model, robots cannot simulate the future consequences of their actions; latent video prediction models learn to predict future observation embeddings in a compressed latent space.","Dreamer-V3 and SWIM use learned latent world models for sample-efficient robot control without explicit physics simulation."),
  q(2043,"Foundation Models","competitive","Research",20,"Why does physical consistency of foundation model outputs matter fundamentally more for robotics than language generation?",["Robot actions have physical consequences; inconsistent outputs cause hardware damage or task failure unlike text errors.","Physical consistency matters equally for text generation and robot action generation tasks.","Foundation models naturally produce physically consistent outputs when trained on physics simulation data.","Physical consistency only matters for manipulation tasks and never for navigation or locomotion."],0,"Hallucinating a fact is harmless; outputting a joint command that exceeds hardware limits breaks the robot.","An LLM confabulating a historical date is recoverable; a VLA outputting kinematically infeasible joint angles or forces beyond actuator limits causes immediate hardware damage or task failure.","Physical constraint layers, safety shields, and simulation-in-the-loop validation are used to filter physically inconsistent VLA outputs before execution."),
  q(2044,"Foundation Models","competitive","Research",20,"How does the concept of affordance bridge visual perception and robot action selection in embodied AI?",["Affordances represent action possibilities of objects, directly linking visual perception to feasible action selection.","Affordances are learned exclusively from language descriptions of object physical properties.","Affordance models predict object locations but not the specific robot actions needed to interact with them.","Affordances are equivalent to instance segmentation masks in modern robot perception systems."],0,"Affordances = what can I do with this? — a direct bridge from perception to action possibility.","Gibson's ecological affordance theory: affordances are relational properties between objects and the actor's action capabilities; a cup affords grasping for a robot hand but not for a pincer gripper.","VLA models that predict affordance maps as intermediate representations before selecting actions generalise better to novel objects and unseen scenes."),
  q(2045,"Foundation Models","competitive","Research",20,"What is the alignment tax in RLHF-trained robot foundation models?",["Aligning to human preferences may reduce raw task capability, representing an explicit capability-safety trade-off.","The alignment tax describes the computational overhead of running human preference labelling sessions.","It describes the reduction in inference speed caused by safety filtering layers added post-training.","The alignment tax is the increase in model parameter count required to support RLHF training."],0,"Safer robot policies may be less capable — safety and capability genuinely trade off.","RLHF training constrains the policy to behaviours preferred by humans, which may exclude high-capability but unsafe strategies; InstructGPT showed slight benchmark degradation after RLHF alignment.","Understanding and quantifying the alignment tax is critical for safely deploying capable robot foundation models in real-world industrial environments."),

  // ── COMPETITIVE: Aerial Robotics ─────────────────────────────────────────
  q(2046,"Aerial Robotics","competitive","Starter",15,"Why is a quadrotor considered an underactuated system and what coupling does this create?",["It has 4 inputs controlling 6 DOF; thrust is always body-z aligned, coupling lateral translation to attitude.","Underactuation means the quadrotor has fewer rotor blades than motors in the system.","All multirotors are fully actuated because they can hover at any arbitrary body orientation.","Underactuation decouples yaw control from altitude control allowing independent regulation."],0,"4 thrust inputs, 6 DOF — lateral motion requires tilting the body and changing thrust direction.","A quadrotor has 4 scalar motor inputs but 6-DOF rigid-body motion; thrust always acts along body-z, so lateral acceleration requires tilting the vehicle, creating an inescapable attitude-translation coupling.","Tilt-rotor and omnidirectional multirotors add additional actuation to decouple rotation from translation."),
  q(2047,"Aerial Robotics","competitive","Starter",15,"What is differential flatness of a quadrotor and how does it enable efficient trajectory generation?",["A quadrotor is differentially flat with outputs [x,y,z,psi]; any smooth trajectory in this space uniquely determines all states and inputs.","Differential flatness means the quadrotor can fly any trajectory without changing its attitude.","Differential flatness implies the quadrotor dynamics are linear and time-invariant.","Differential flatness is a property exclusive to fixed-wing aircraft and not multirotors."],0,"Flat outputs [x,y,z,psi] algebraically determine all states and inputs — no ODE integration needed.","Given flat output trajectories x(t), x_dot, x_ddot, and psi(t), all states (v, R, omega) and motor inputs can be computed algebraically without integrating the nonlinear equations of motion.","Minimum-snap trajectory generation exploits differential flatness to plan smooth, dynamically feasible quadrotor paths by optimising the 4th derivatives of flat outputs."),
  q(2048,"Aerial Robotics","competitive","Starter",15,"Why is the cascaded control architecture (position -> velocity -> attitude -> rate) standard for multirotors?",["It exploits timescale separation: inner attitude loops stabilise much faster than outer position loops.","It guarantees globally optimal control by decomposing the nonlinear problem into linear subproblems.","It minimises the number of sensors needed to achieve stable autonomous flight.","The cascaded structure is required only for fixed-wing aircraft and not for multirotor systems."],0,"Attitude bandwidth (~20 Hz) >> position bandwidth (~2 Hz) — inner loops are fast enough to appear static to outer loops.","Attitude dynamics have natural frequencies an order of magnitude higher than position dynamics; the inner attitude loop is effectively static from the perspective of the outer position loop, validating the cascade separation.","PX4, ArduPilot, and Betaflight all implement variants of this cascaded architecture for reliable multirotor control."),
  q(2049,"Aerial Robotics","competitive","Starter",15,"What is ground effect in UAV flight and how does it affect controller performance near landing?",["Ground effect increases rotor thrust efficiency near surfaces via air recirculation, causing unexpected lift increase.","Ground effect refers to electromagnetic interference from ground-based electronics and radio systems.","Ground effect causes rotor blades to stall completely when altitude drops below one metre.","Ground effect decreases aerodynamic drag near the ground, requiring more thrust to maintain altitude."],0,"Recirculating air near surfaces increases thrust efficiency — the vehicle suddenly needs less throttle to hover.","As the UAV descends below approximately one rotor diameter from the surface, the rotor wake recirculates and creates a pressure cushion that increases thrust efficiency by 10-30% for the same throttle input.","Landing controllers must account for the nonlinear thrust-altitude relationship in ground effect to prevent hard landings caused by the sudden lift increase."),
  q(2050,"Aerial Robotics","competitive","Starter",15,"What does motor mixing accomplish in a multirotor autopilot and why is it necessary?",["Motor mixing maps desired total thrust and body torques into individual rotor speed commands based on frame geometry.","Motor mixing maps camera images into rotor-efficiency estimates for each individual motor.","Motor mixing maps battery temperature measurements into GPS altitude correction signals.","Motor mixing maps altitude setpoint errors into individual sensor noise covariance updates."],0,"Desired wrench (thrust + torques) -> individual motor commands via the geometric allocation matrix.","The mixing matrix encodes each rotor's position and spin direction relative to the CoM; it maps the collective thrust and three body torque demands into the four individual motor speed commands.","Every multirotor autopilot implements motor mixing; different frame geometries (X, H, coaxial) require different mixing matrices."),
  q(2051,"Aerial Robotics","competitive","Research",20,"How does minimum-snap trajectory optimisation guarantee dynamically feasible quadrotor trajectories?",["Differential flatness allows snap minimisation in flat output space to directly bound thrust and torques without dynamics integration.","Minimum-snap minimises fuel consumption by constraining the trajectory to constant altitude.","Dynamic feasibility is guaranteed by adding explicit collision avoidance constraints to the QP.","Minimum-snap generates trajectories in joint space and converts them to Cartesian space via FK."],0,"Flatness means flat-space snap bound -> thrust and torque bound — dynamics feasibility comes for free.","Because the quadrotor is differentially flat, bounding the 4th derivative of position (snap) directly bounds the required thrust and angular acceleration; the trajectory is feasible by construction without dynamics simulation.","Mellinger and Kumar (2011) introduced minimum-snap trajectory generation; it remains the standard approach for agile quadrotor motion planning research."),
  q(2052,"Aerial Robotics","competitive","Research",20,"Why do aggressive manoeuvres like flips require nonlinear geometric controllers rather than cascaded PID?",["Cascaded PID relies on timescale separation which breaks down when attitude and position dynamics become tightly coupled.","Aggressive manoeuvres simply require larger PID gains rather than a fundamentally different control architecture.","Cascaded PID handles any manoeuvre provided the feedback gains are tuned sufficiently high.","Nonlinear controllers are only necessary for steady-state hovering, not for dynamic aggressive flight."],0,"Flips involve large attitudes where the linearisation underlying cascaded PID completely fails.","During a full flip, the vehicle operates far from the hover equilibrium where PID is designed; attitude and position dynamics couple on the same timescale, invalidating the cascade's timescale separation assumption.","Lee, Leok, and McClamroch's (2010) geometric controller on SE(3) handles arbitrary attitudes without linearisation or coordinate singularities."),
  q(2053,"Aerial Robotics","competitive","Research",20,"How does the geometric attitude controller on SO(3) avoid singularities in Euler-angle controllers?",["Errors are defined directly on the rotation manifold using the Lie algebra, avoiding gimbal lock entirely.","Geometric controllers use Euler angles but apply them in a carefully chosen non-singular sequence.","SO(3) controllers avoid singularities by constraining vehicle roll angle to within plus or minus 90 degrees.","Geometric controllers eliminate attitude tracking entirely by working exclusively in position space."],0,"Errors on SO(3) are globally well-defined — no coordinate chart, no singularity anywhere on the manifold.","Error rotation R_e = R_d^T * R and angular velocity error omega_e = omega - R^T * R_d * omega_d are defined for all R in SO(3) without coordinate singularities, unlike any Euler angle representation.","Geometric controllers are used on research quadrotors performing full 360-degree rolls, flips, and inverted hover manoeuvres impossible with singularity-limited Euler-based controllers."),
  q(2054,"Aerial Robotics","competitive","Research",20,"How does optical flow time-to-collision (tau) enable obstacle avoidance without estimating absolute depth?",["tau = s/s_dot from radial optical flow gives time to contact without requiring any metric depth estimate.","tau requires stereo depth estimation; monocular optical flow alone is insufficient for tau computation.","tau is computed from the gyroscope angular velocity rather than from camera image measurements.","tau gives metric distance to obstacles rather than time to collision in the general case."],0,"tau = angular_size / angular_size_rate = 1/divergence — collision time from pure optical flow.","As an object approaches, its angular subtended size s grows at rate s_dot; tau = s/s_dot = 1/(divergence) gives time to contact directly from the divergence field in the optical flow image.","Insects use tau-based flight control; event cameras on UAVs enable sub-millisecond tau computation for high-speed obstacle avoidance at flight speeds exceeding 10 m/s."),
  q(2055,"Aerial Robotics","competitive","Research",20,"Why does L1 adaptive control provide robustness guarantees for UAVs with uncertain aerodynamics?",["L1 uses fast adaptation decoupled from the control channel via a low-pass filter, bounding tracking error for matched uncertainty.","L1 adaptive control learns a PID gain schedule offline and applies it during autonomous flight.","L1 provides robustness by increasing the integral gain proportionally during observed disturbances.","L1 control guarantees stability only for linear time-invariant UAV aerodynamic models."],0,"Fast adaptation + low-pass filter = bounded tracking error without the adaptation-stability trade-off.","L1 adaptive architecture: fast adaptation law estimates matched uncertainties; low-pass filter in the control channel ensures stability; the decoupling avoids the adaptation gain-stability trade-off of MRAC.","L1 adaptive control has been flight-tested on fixed-wing and quadrotor platforms for robust handling of icing, gust disturbances, and structural damage."),
  q(2056,"Aerial Robotics","competitive","Research",20,"What specific advantage do event cameras provide for high-speed agile UAV flight research?",["Event cameras output microsecond-timestamped brightness changes asynchronously, enabling sub-millisecond latency perception.","Event cameras provide dense metric depth at every pixel natively without stereo processing.","Event cameras eliminate the need for any inertial measurement during high-speed aggressive flight.","Event cameras guarantee pixel-perfect semantic scene labels at all frame rates and motion speeds."],0,"Asynchronous microsecond-timestamped events enable perception latency impossible with frame cameras.","Event cameras react to brightness changes with microsecond latency without frame synchronisation; at 10 m/s flight speed this enables obstacle detection before a standard 30 Hz camera would have captured a single frame.","Davis240C and Prophesee Metavision event cameras are used on racing drones and research platforms for agile flight at speeds exceeding 20 m/s."),
  q(2057,"Aerial Robotics","competitive","Research",20,"Why is nonlinear MPC increasingly used in advanced UAV research despite its computational cost?",["Nonlinear MPC handles vehicle nonlinearities and state/input constraints beyond the hover linearisation envelope.","Nonlinear MPC eliminates the need for any state estimation or aerodynamic model of the vehicle.","Nonlinear MPC guarantees zero computation time on all embedded flight controller hardware.","Nonlinear MPC converts every underactuated UAV into an equivalent fully actuated system."],0,"Aggressive constrained flight requires nonlinear dynamics reasoning that linear MPC fundamentally cannot provide.","Large angle attitudes, speed-dependent aerodynamics, and obstacle constraints require controllers that reason with the full nonlinear dynamics model; linear MPC linearised about hover fails at high speeds or large attitudes.","Research UAV stacks from ETH Zurich, UPenn GRASP, and CMU use nonlinear MPC for agile constrained flight in cluttered environments."),
  q(2058,"Aerial Robotics","competitive","Research",20,"Why does ICP-based LiDAR odometry require a good initialisation and what failure mode arises without it?",["Without a close initial guess, ICP finds incorrect nearest-neighbour correspondences and converges to a wrong local minimum.","ICP always converges to the unique global minimum regardless of the quality of initialisation.","ICP requires initialisation only for 2D scan matching; 3D point cloud ICP is globally convergent.","Without initialisation ICP takes more iterations but converges to the same correct solution."],0,"Wrong correspondences -> wrong local minimum: ICP is not globally convergent.","ICP alternates between nearest-neighbour correspondence and minimising their distance; with a distant initialisation, incorrect correspondences form a spurious local minimum that ICP converges to instead of the correct alignment.","Normal distributions transform (NDT) and GICP use smoother cost surfaces that are more robust to poor initialisation, and are preferred in LiDAR odometry systems like LOAM and LIO-SAM."),
  q(2059,"Aerial Robotics","competitive","Research",20,"How does neural inertial navigation reduce accumulated position drift compared to classical dead-reckoning?",["Neural networks predict velocity or displacement directly from raw IMU windows, learning to implicitly cancel sensor biases.","Neural inertial navigation replaces the IMU sensor entirely with a camera for improved accuracy.","It integrates accelerometer data using higher-precision double-precision floating-point arithmetic.","Neural inertial navigation is identical to classical integration but implemented on GPU hardware."],0,"Learned bias compensation breaks the t^2 drift growth inherent in classical double integration.","Classical dead-reckoning p = double_integral(a_measured) has drift growing as t^2 due to fixed bias; neural networks trained on diverse IMU trajectories learn to predict velocity increments while cancelling dataset-consistent bias patterns.","TLIO, RONIN, and AirIMU demonstrate 5-10x drift reduction versus classical integration in GPS-denied indoor UAV navigation."),
  q(2060,"Aerial Robotics","competitive","Research",20,"How does perception-aware trajectory planning improve state estimation performance for autonomous UAVs?",["It selects trajectories that improve visual feature observability and state estimation quality, not just reaching the goal.","Control actions are always independent of the quality of visual sensing during flight.","Perception-aware planning means removing dynamics constraints from the trajectory optimiser.","Perception-aware planning only matters when GPS is fully available as a reference signal."],0,"Motion that keeps good features in view improves estimation — planning and perception are coupled.","The chosen trajectory affects which features are visible, how well they can be tracked, and how informative IMU preintegration is; perception-aware planners maximise Fisher information along the trajectory.","Research at ETH Zurich and GRASP Lab demonstrated that perception-aware paths significantly reduce VIO drift compared to purely geometric shortest-path trajectories."),

  // ── COMPETITIVE: Underwater Robotics ─────────────────────────────────────
  q(2061,"Underwater Robotics","competitive","Starter",15,"Why do Doppler Velocity Logs (DVL) serve as the primary velocity reference for AUVs rather than IMU integration?",["DVL measures velocity via Doppler shift of acoustic beams, providing bounded error; IMU integration has unbounded drift.","DVL is preferred because its sampling rate is higher than any available IMU sensor.","DVL measures acceleration directly and then integrates like an IMU to get velocity.","DVL is only used when GPS is available to provide external corrections to its measurements."],0,"Bounded DVL velocity error vs unbounded IMU double-integration drift — no comparison for long missions.","DVL Doppler measurement error is bounded by beam geometry and acoustic noise; double-integrating IMU accelerometer data has drift growing as t^2 due to bias, making it unusable for long-duration navigation.","AUV navigation filters fuse DVL velocity measurements with IMU attitude estimates for accurate dead-reckoning over multi-hour missions."),
  q(2062,"Underwater Robotics","competitive","Starter",15,"What is long baseline (LBL) acoustic positioning and why does it achieve higher accuracy than USBL?",["LBL triangulates from multiple seabed transponders with known positions; the long baseline reduces geometric dilution.","LBL uses a single transducer on the ship; USBL uses multiple seabed transponder nodes.","USBL always achieves higher positioning accuracy because it uses phase-difference measurements.","LBL and USBL provide identical accuracy levels; they differ only in operational cost."],0,"Multiple transponders on the seabed give well-conditioned triangulation geometry — lower GDOP.","USBL uses a single transducer array on the ship for bearing and range (accuracy degrades with depth); LBL uses 3+ seabed transponders for triangulation with geometry-independent accuracy.","Scientific AUV surveys at depths exceeding 1000 m use LBL to achieve centimetre-level positioning accuracy for precise seafloor mapping."),
  q(2063,"Underwater Robotics","competitive","Starter",15,"What makes acoustic multipath propagation degrade underwater communication and navigation?",["Sound reflects off boundaries and thermal layers, arriving via multiple delayed paths causing ISI and range ambiguity.","Multipath propagation averages multiple reflections to improve range measurement accuracy.","Acoustic multipath only occurs in shallow water and completely disappears below 100 m depth.","Multipath affects optical sensors but not acoustic sensors in the underwater environment."],0,"Multiple delayed arrivals = inter-symbol interference in comms and ghost echoes in ranging.","Each reflected path adds a delayed, attenuated copy of the transmitted signal; in communications this causes inter-symbol interference; in ranging it creates ghost echoes that bias time-of-flight distance estimates.","OFDM-based underwater acoustic modems and matched-filter equalizers are used to mitigate multipath in acoustic data links."),
  q(2064,"Underwater Robotics","competitive","Starter",15,"Why is hydrodynamic drag especially significant in underwater robot dynamics compared to aerial robots?",["Water is approximately 800 times denser than air, making drag and added-mass forces dominant in underwater dynamics.","Hydrodynamic drag is negligible underwater compared to the aerodynamic drag on aerial vehicles.","Drag only affects acoustic sensor performance and does not influence thruster-driven motion dynamics.","Drag disappears entirely once an AUV achieves neutral buoyancy in the water column."],0,"Water density ~800x air: drag and added mass are huge — dominate the dynamics equations.","AUV dynamics: M_RB*a + M_A*a_r + D(v_r)*v_r = tau; added mass M_A (water accelerated with the hull) and drag D can each be comparable to or exceed M_RB itself.","Controllers designed for nominal AUV models can fail badly if drag and added mass are not accurately identified and included in the model."),
  q(2065,"Underwater Robotics","competitive","Starter",15,"What is the most significant challenge for optical vision systems in underwater robot perception?",["Light scattering and wavelength-dependent absorption degrade contrast, colour accuracy, and effective visibility range.","Images underwater are inherently sharper than in air due to the higher refractive index of water.","Underwater scenes eliminate the need for camera calibration because water acts as a flat optical medium.","Water guarantees uniform illumination throughout the scene, removing lighting variation challenges."],0,"Scattering + red-channel absorption + backscatter = degraded contrast, colour, and visibility.","Red light is absorbed exponentially within a few metres; scattering adds a haze (backscatter) proportional to the water turbidity; effective visibility can be reduced to less than a metre in turbid coastal water.","WaterSLAM and SeaThru use physics-based underwater image formation models to reverse these effects before feature extraction."),
  q(2066,"Underwater Robotics","competitive","Research",20,"Why does terrain-relative navigation (TRN) provide better long-duration accuracy than pure inertial/DVL dead-reckoning?",["TRN correlates onboard sonar with stored bathymetric databases, providing absolute position fixes that bound drift over time.","TRN receives GPS corrections every hour from the surface to periodically reset DVL drift.","TRN provides superior accuracy only in shallow water where sonar returns are spatially dense.","TRN completely replaces DVL, eliminating velocity measurement error from the navigation solution."],0,"Map-matching provides absolute position fixes — no matter how long the mission, drift is bounded.","Dead-reckoning drift grows monotonically with mission duration; TRN correlates measured bathymetry against a stored chart to generate absolute position estimates that reset the accumulated error.","MBARI's SLAM-based TRN system enables AUVs to resurvey exactly the same seafloor transects on repeated dives months apart without GPS."),
  q(2067,"Underwater Robotics","competitive","Research",20,"Why is the underwater acoustic channel fundamentally bandwidth-limited compared to radio-frequency communication in air?",["Sound propagates at ~1500 m/s causing severe Doppler for moving AUVs, and usable bandwidth is only a few kHz.","The underwater acoustic channel supports higher bandwidth than RF because water is a denser medium.","Acoustic communication is unaffected by Doppler because the slow sound speed renders it negligible.","The primary challenge is attenuation only; Doppler and bandwidth limitations are minor in practice."],0,"Sound speed 1500 m/s vs 3e8 m/s for RF: severe Doppler + bandwidth limited to kHz vs GHz.","At 10 kHz carrier frequency, a 1 m/s AUV motion causes 6.7 Hz Doppler shift (0.067% of carrier); total usable bandwidth is ~5 kHz vs GHz for RF, resulting in kilobits-per-second data rates versus gigabits.","MIMO-OFDM and Doppler-pre-equalisation modems achieve up to 10 kbps in benign shallow-water acoustic channels."),
  q(2068,"Underwater Robotics","competitive","Research",20,"How does buoyancy-driven glider propulsion achieve superior energy efficiency over thruster-driven AUVs?",["Gliders pump oil to change buoyancy, converting potential energy to horizontal motion at near-zero propulsive power.","Gliders are more efficient because they use lighter lithium batteries than thruster-driven AUVs.","Thruster AUVs are actually more efficient at low speeds; gliders are only efficient at high speeds.","Gliders avoid drag entirely by travelling in a straight horizontal line at constant depth."],0,"Pump oil -> change density -> glide: propulsive power is near zero; only the pump uses energy.","Glider propulsion: buoyancy engine pumps oil between internal and external bladders; kinetic energy comes from gravitational potential energy converted via the sawtooth depth profile; propulsive power P_thrust ~ 0.","Seaglider and Slocum gliders achieve endurance exceeding 6-12 months on a single battery charge; thruster AUVs last hours to days."),
  q(2069,"Underwater Robotics","competitive","Research",20,"Why does underwater SLAM remain an active research problem despite decades of work on general SLAM algorithms?",["GPS-denied conditions combined with sparse, noisy, environment-dependent sensing make standard approaches degrade rapidly.","Underwater vehicles already achieve perfect localisation using acoustic positioning systems alone.","Mapping is trivial underwater because seafloor scenes are completely static and fully observable.","SLAM is unnecessary once a depth sensor is installed because depth provides full localisation."],0,"GPS-denied + sonar ambiguity + water-column distortion + featureless terrain = unsolved problem.","Standard SLAM methods assume robust feature detection; underwater, sonar returns are ambiguous, optical visibility is limited, currents cause dynamics model errors, and terrain may be featureless.","Recent underwater SLAM research focuses on sonar-based place recognition, physics-aware image formation models, and uncertainty-aware multi-sensor fusion."),
  q(2070,"Underwater Robotics","competitive","Research",20,"How does model predictive path integral (MPPI) control benefit AUV trajectory optimisation in dynamic ocean currents?",["MPPI uses parallel GPU sampling of trajectory rollouts to estimate optimal control without gradient computation.","MPPI is preferred because it requires strictly fewer trajectory samples than any other sampling method.","MPPI provides guaranteed global optimality for all nonlinear AUV dynamic models.","MPPI replaces the AUV dynamic model with a neural network learned entirely from operational data."],0,"Gradient-free GPU-parallel sampling handles non-smooth stochastic currents that gradient methods cannot.","Ocean current fields are non-differentiable, stochastic, and spatially varying; MPPI samples K parallel trajectory rollouts on GPU, evaluates their costs, and computes a weighted average control update without any gradient.","MPPI enables real-time AUV replanning at 10-20 Hz in the presence of turbulent tidal currents that would violate the differentiability assumptions of gradient-based MPC methods."),
  q(2071,"Underwater Robotics","competitive","Research",20,"What limits the spatial resolution of underwater acoustic imaging cameras compared to optical cameras?",["The acoustic wavelength at typical sonar frequencies (100 kHz-1 MHz) is millimetres, not micrometres like optical light.","Acoustic cameras achieve resolution comparable to optical cameras at operational depth.","Resolution is limited only by transducer array physical size and not by the acoustic wavelength.","Acoustic cameras cannot form 2D spatial images and provide only 1D range profiles."],0,"Diffraction limit = lambda * R / D: acoustic lambda ~mm vs optical lambda ~um — 1000x worse resolution.","At 1 MHz, wavelength lambda = 1.5 mm; diffraction-limited resolution ~lambda*R/D ~ 30 mm at R=2m, D=0.1m aperture; optical cameras achieve sub-millimetre resolution at the same range.","Forward-looking sonar (BlueView, Tritech) is used for close-range obstacle detection and inspection where turbidity prevents optical imaging."),
  q(2072,"Underwater Robotics","competitive","Research",20,"How does cooperative acoustic localisation improve positioning accuracy beyond single-AUV dead-reckoning?",["Peer-to-peer acoustic ranging creates inter-vehicle constraints that jointly reduce collective positioning uncertainty.","Cooperative localisation improves vehicle speed but does not reduce positioning uncertainty.","Cooperative localisation requires all AUVs to simultaneously surface for GPS updates.","Cooperative localisation works only when all vehicles start from exactly the same known initial position."],0,"Inter-vehicle acoustic ranges add geometric constraints — collective position uncertainty is smaller than individual.","Each pairwise acoustic range measurement between vehicles adds a constraint linking their positions; with geometrically diverse vehicle arrangements, this joint constrained estimation is significantly more accurate than any individual dead-reckoning.","WHOI REMUS vehicles use cooperative acoustic positioning in surveys where single-vehicle DVL-based dead-reckoning is insufficient for the required track spacing accuracy."),
  q(2073,"Underwater Robotics","competitive","Research",20,"What makes underwater visual odometry fundamentally harder than ground or aerial visual odometry?",["Backscatter, wavelength-dependent absorption, lack of texture, and dynamic marine life combine to degrade standard VO pipelines.","Underwater VO is actually easier because slow AUV speeds produce very small inter-frame motions.","The primary challenge is computational; underwater cameras have lower resolution than standard cameras.","Underwater VO is equivalent to ground VO because water is optically similar to air at short ranges."],0,"Backscatter + red absorption + low texture + dynamic scene: standard VO features fail or track poorly.","Red channel attenuates exponentially within metres; backscatter adds multiplicative noise proportional to turbidity; sandy seafloors have minimal texture; fish and particles create false feature matches.","CLAHE pre-processing, dark-channel dehazing, and physics-based image restoration are applied before feature extraction for reliable underwater visual odometry."),
  q(2074,"Underwater Robotics","competitive","Research",20,"Why does the constant-velocity kinematic model fail for AUV trajectory prediction in ocean current fields?",["It ignores added mass, hydrodynamic drag, and current disturbance forces that dominate AUV dynamics.","The constant-velocity model fails only in turbulent shallow water but works in deep open ocean.","It fails because AUVs never actually move at constant speed in any operational environment.","A simpler single-integrator model is preferred over the constant-velocity model for real-time MPC."],0,"Added mass M_A, drag D(v), and current tau_c are all absent from the constant-velocity model.","The 6-DOF SNAME maneuvering model: (M_RB + M_A)*a + D(v_r)*v_r + g(eta) = tau + tau_current; all three additional terms are large and configuration-dependent, making constant-velocity predictions substantially inaccurate.","System identification experiments in calm water tanks estimate M_A and D(v) parameters for use in mission planning and trajectory tracking controllers."),
  q(2075,"Underwater Robotics","competitive","Research",20,"How does tightly coupled multi-sensor fusion address the fundamental limitations of individual underwater sensors?",["No single underwater sensor covers all conditions; tight fusion combines IMU, DVL, depth, sonar, and vision with consistent uncertainty.","Every underwater sensor is individually sufficient for reliable navigation in all deployment conditions.","Multi-sensor fusion eliminates the need for any vehicle dynamic model in the navigation filter.","Multi-sensor fusion guarantees successful loop closure at every timestep of the mission."],0,"Each sensor has a distinct failure mode — tight fusion covers each sensor's weakness with another's strength.","IMU: high rate, drifts; DVL: bounded velocity error, fails near seabed or surface; depth: precise vertical but no horizontal; sonar: good range, ambiguous bearing; tight fusion via EKF or factor graph covers each failure mode.","Research AUVs like Sentry and Nereid Hybrid use tightly coupled multi-sensor navigation filters achieving centimetre-level accuracy over hour-long seafloor surveys."),

  // ── COMPETITIVE: Autonomous Driving ──────────────────────────────────────
  q(2076,"Autonomous Driving","competitive","Starter",15,"What information does an HD map contain that a standard navigation map lacks?",["Centimetre-level lane geometry, road markings, traffic light positions, and semantic road attributes.","Standard navigation data stored at higher image resolution and finer zoom levels.","Only GPS coordinates of all road intersections and junctions.","Real-time dynamic obstacle positions generated by the vehicle sensors."],0,"Lane-level geometry + semantic attributes + cm accuracy — fundamentally different from navigation maps.","Standard maps: road network connectivity and routing information. HD maps: precise lane geometry (polylines), sign semantics, surface type, speed limits, and traffic light positions used for sub-lane localisation.","Waymo, Cruise, and Mobileye maintain proprietary HD maps of their operational design domains that are continuously updated from fleet data."),
  q(2077,"Autonomous Driving","competitive","Starter",15,"What is the bicycle kinematic model and why is it used in autonomous vehicle trajectory planning?",["The bicycle model approximates the vehicle as two wheels (front/rear axle), relating steering to curvature for efficient planning.","The bicycle model describes only actual two-wheeled vehicles; four-wheel vehicles require a unicycle model.","The bicycle model incorporates tyre slip dynamics for accurate high-speed trajectory planning.","The bicycle model is used exclusively for computing braking distances, not for turning trajectories."],0,"kappa = tan(delta)/L — two-wheel kinematic approximation is simple, accurate at low speed, and differentiable.","Curvature kappa = tan(delta)/L (wheelbase L, front steering angle delta); this kinematic model enables efficient trajectory optimisation and MPC controller design for low-speed autonomous vehicle motion.","High-speed planning transitions to Pacejka dynamic tyre models that include lateral slip forces not captured by the kinematic bicycle model."),
  q(2078,"Autonomous Driving","competitive","Starter",15,"Why is multi-sensor fusion essential rather than optional in self-driving perception systems?",["Different sensors provide complementary modalities and failure modes; no single sensor is reliable across all conditions.","A single high-resolution LiDAR already dominates all conditions and makes other sensors redundant.","Multi-sensor fusion removes the need for any state estimation or calibration in the perception stack.","Sensor fusion guarantees zero-latency obstacle detection decisions in every operational scenario."],0,"Cameras = semantics, LiDAR = geometry, radar = velocity+weather — each covers the others' blind spots.","Cameras fail in low light and glare; LiDAR degrades in heavy rain, snow, and fog; radar lacks resolution; GNSS fails in tunnels and urban canyons; fusing all provides complementary coverage.","No commercial Level 4+ autonomous driving system relies on a single sensor modality."),
  q(2079,"Autonomous Driving","competitive","Starter",15,"Why is safety validation fundamentally hard for autonomous driving systems?",["The long tail of rare safety-critical scenarios cannot be exhaustively covered by any finite test campaign.","Traffic scenarios are simple and highly repetitive, making comprehensive testing straightforward.","Validation only requires a few short closed-course evaluations to certify system safety.","Simulation automatically proves safety in all deployment conditions by complete coverage."],0,"The long tail of rare events is infinite — you cannot exhaustively test what you cannot enumerate.","Driving systems encounter an unbounded distribution of scenarios; rare events (debris on road, unusual pedestrian behaviour, sensor failure) are safety-critical but statistically infrequent and difficult to enumerate.","Scenario generation, simulation, formal verification, and adversarial testing all partially address this but no complete solution exists yet."),
  q(2080,"Autonomous Driving","competitive","Starter",15,"What is the key insight of the Frenet frame representation for autonomous driving trajectory planning?",["The Frenet frame decouples longitudinal progress (s) from lateral deviation (d), reducing 2D planning to two 1D problems.","Frenet coordinates are mathematically identical to Cartesian coordinates with a constant rotation applied.","The Frenet frame representation only applies to straight road segments with zero curvature.","Frenet coordinates eliminate the need for any reference path in the trajectory planning formulation."],0,"s-d decomposition: speed control and lane keeping become two independent 1D optimisations.","In Frenet: s = arc length along road reference, d = lateral offset; longitudinal speed planning and lateral lane-keeping/lane-change planning decompose naturally into independent polynomial optimisation problems.","Waymo, Motional, and most industry trajectory planners use Frenet-based trajectory parameterisation for structured road driving."),
  q(2081,"Autonomous Driving","competitive","Research",20,"Why does distributional shift remain the fundamental unsolved challenge for autonomous driving perception?",["The long tail of rare scenarios cannot be exhaustively covered in training data, causing failures in novel conditions.","Distributional shift is solved by training on sufficiently large and diverse datasets.","Perception failures are primarily caused by sensor hardware faults, not algorithmic distributional shift.","Larger neural network models always generalise better and solve distributional shift automatically."],0,"Training distribution never equals deployment distribution for rare events — neural nets have no OOD detector.","D_train != D_deploy for all tail events; neural perception models assign high confidence to misclassified OOD inputs and have no native mechanism to detect when they are operating outside their training distribution.","Conformal prediction, uncertainty quantification, and open-set recognition partially address this but no complete solution exists for the full long tail."),
  q(2082,"Autonomous Driving","competitive","Research",20,"How does bird's-eye view (BEV) feature transformation improve 3D object detection compared to perspective image detection?",["BEV transforms perspective features to a metric top-down grid, providing consistent geometric scale for detection.","BEV detection eliminates depth estimation by projecting all objects onto the ground plane.","BEV features are simply perspective image features rotated 90 degrees around the image horizontal axis.","BEV transformation requires LiDAR depth; cameras alone cannot produce any BEV representation."],0,"Metric top-down space unifies geometry across cameras and LiDAR — detection in BEV is scale-consistent.","Perspective images encode depth implicitly with projective ambiguity; BEV transformation (via LSS depth distribution or BEVFormer cross-attention) lifts features to 3D metric space, enabling accurate distance estimation.","BEVFusion, BEVFormer, and CenterPoint all operate in BEV space for multi-sensor 3D detection and tracking."),
  q(2083,"Autonomous Driving","competitive","Research",20,"What is behavioural cloning covariate shift and how does DAgger resolve it?",["BC encounters states not in expert data due to its own errors; DAgger queries the expert at states the learner visits.","Covariate shift means input image distribution changes due to camera exposure differences at test time.","DAgger addresses covariate shift by augmenting training data with random noise perturbations.","Behavioural cloning has no covariate shift if the expert demonstrations cover a sufficiently diverse state space."],0,"BC deviates -> novel state -> wrong action -> more deviation: compound error. DAgger iteratively covers learner states.","BC trains on D_expert; at test time, any error leads to novel states outside D_expert where the cloned policy has no reliable supervision, causing compounding deviations; DAgger iteratively adds expert labels at states visited by the learner.","NVIDIA DAVE and recent end-to-end driving systems use DAgger-inspired online learning or data augmentation to mitigate covariate shift."),
  q(2084,"Autonomous Driving","competitive","Research",20,"Why do transformer-based motion prediction models capture multi-agent interactions more effectively than LSTM-based models?",["Transformers compute self-attention across all agents simultaneously; LSTMs process each agent independently without direct interaction.","Transformer models are preferred only because they scale to larger parameter counts.","LSTMs capture longer temporal context; transformers only model instantaneous spatial interactions.","Transformers always predict deterministic trajectories; LSTMs always predict multimodal distributions."],0,"Global self-attention across all agents at once vs sequential per-agent encoding — interaction complexity matters.","LSTM prediction: encode each agent's history independently -> decode; Transformer: cross-attend between all agents, map polylines, and past motion -> joint conditional multimodal future predictions.","MTR (Motion Transformer) and Waymo's Womd-LLM achieve state-of-the-art on the Waymo Open Motion Dataset using transformer-based multi-agent motion prediction."),
  q(2085,"Autonomous Driving","competitive","Research",20,"What is the fundamental limitation of the predict-then-plan paradigm for autonomous driving in dense traffic?",["Prediction assumes other agents are independent of the ego vehicle plan, missing reactive interaction coupling.","The paradigm is limited only by the accuracy of the prediction model used.","Prediction before planning is suboptimal only because planning can improve prediction accuracy.","The limitation is computational: joint prediction and planning is computationally intractable."],0,"Other agents react to what ego does — predict-then-plan ignores this coupling completely.","If ego plans to brake, following vehicles react differently than if ego accelerates; predict-then-plan generates predictions unconditional on ego's intent, creating plans that are optimal against incorrect conditional predictions.","Conditional prediction models (MTR++) and game-theoretic planning (MPDM, DiMA) model this ego-agent coupling explicitly."),
  q(2086,"Autonomous Driving","competitive","Research",20,"Why do occupancy network representations outperform object-list detectors for safety-critical autonomy?",["Occupancy networks model free and occupied space without class hypotheses, detecting any obstacle including unknown classes.","Occupancy networks are computationally cheaper than object-list detectors for all scenario types.","Object-list detectors outperform occupancy networks whenever the number of objects is large.","Occupancy networks require LiDAR depth input; camera-only systems must use object-list detectors."],0,"Unknown classes exist — occupancy marks them occupied regardless; object detectors completely miss them.","A fallen tree trunk, unusual construction barrier, or never-before-seen object category is invisible to class-specific detectors; occupancy networks mark the space as occupied regardless of semantic class.","Tesla's occupancy network and Waymo's 3D occupancy prediction handle out-of-vocabulary obstacles that class-specific detectors cannot detect."),
  q(2087,"Autonomous Driving","competitive","Research",20,"Why do contingency planning approaches improve safety in interactive autonomous driving scenarios?",["Contingency planners simultaneously optimise trajectories for each agent behaviour hypothesis, maintaining feasible fallbacks.","Contingency planning is always slower and provides no measurable safety improvement.","Single-trajectory planners already account for agent uncertainty through deterministic worst-case margins.","Contingency planning is equivalent to always planning for the worst-case agent trajectory."],0,"Multiple hypotheses -> multiple feasible trajectories -> commit only when uncertainty resolves — safer under ambiguity.","If another vehicle has 70% probability of yielding and 30% of cutting in, a contingency planner maintains both trajectories feasible; the vehicle executes the appropriate one when the agent's intent becomes clear.","Risk-POMDP and contingent MPC formalise contingency planning for autonomous driving at urban intersections."),
  q(2088,"Autonomous Driving","competitive","Research",20,"How does responsibility-sensitive safety (RSS) provide formal collision prevention guarantees?",["RSS defines physics-based safe distance rules that, if followed by ego, provably prevent ego from being the proximate collision cause.","RSS statistically bounds collision probability below 10^{-6} per mile using Monte Carlo methods.","RSS replaces the entire motion planner with a formal verification algorithm.","RSS guarantees zero probability of collision under all possible traffic scenarios."],0,"Physics-based invariants provably prevent ego-fault collisions regardless of other agents' behaviour.","RSS defines proper responses to right-of-way violations; the formal proof shows that if ego follows these responses, ego cannot be the proximate cause of any collision regardless of other agents' actions.","Intel/Mobileye's RSS is integrated as a safety supervisor layer in commercial ADAS systems to provide formal safety guarantees."),
  q(2089,"Autonomous Driving","competitive","Research",20,"Why is closed-loop evaluation emphasised over open-loop metrics in autonomous driving research?",["Open-loop metrics cannot capture decision-feedback interaction where ego behaviour changes future scenarios.","Open-loop perception metrics fully determine safety and planning quality in practice.","Closed-loop evaluation removes the need for any simulation infrastructure or benchmark suite.","Closed-loop evaluation only matters for very low-speed parking manoeuvres."],0,"Ego behaviour affects what scenarios arise next — open-loop metrics miss this causal feedback loop entirely.","Driving is a sequential control problem; an open-loop evaluation gives the policy the ground-truth scene but this breaks the causal chain where ego decisions change how other agents behave in future timesteps.","CARLA Leaderboard, nuPlan, and Waymax all emphasise reactive closed-loop evaluation over static open-loop prediction benchmarks."),
  q(2090,"Autonomous Driving","competitive","Research",20,"How does end-to-end driving research challenge traditional modular pipeline design?",["End-to-end learning jointly optimises all components from sensors to control, potentially avoiding modular interface errors.","End-to-end driving eliminates training data requirements because driving is a deterministic task.","End-to-end methods always provide better interpretability than modular perception-planning pipelines.","End-to-end means the vehicle output is text descriptions rather than explicit control signals."],0,"Joint optimisation from pixels to steering avoids compounding errors at each modular interface.","Modular pipelines accumulate errors at each interface (perception -> prediction -> planning -> control); end-to-end learning jointly optimises the full mapping, potentially discovering more efficient internal representations.","UniAD, TCP, and SparseDrive explore end-to-end differentiable driving while maintaining interpretable intermediate representations for debugging."),

  // ── COMPETITIVE: Legged Locomotion ───────────────────────────────────────
  q(2091,"Legged Locomotion","competitive","Starter",15,"What is the Zero Moment Point (ZMP) and how is it used to ensure dynamic stability of bipeds?",["ZMP is the ground point where net gravitational and inertial moments have zero horizontal component; keeping ZMP inside the support polygon ensures stability.","ZMP is the point directly below the robot centre of mass regardless of body dynamics.","ZMP balance requires the robot to be completely stationary with zero velocity.","ZMP equals the centre of pressure only for massless legs with point contact."],0,"ZMP inside support polygon = dynamically stable — the robot will not tip regardless of velocity.","From Newton-Euler dynamics, ZMP = (sum m_i*(r_i x (g - a_i)))_xy / (sum m_i*(g_z - a_iz)); if ZMP exits the support polygon boundary the robot topples.","ASIMO, HRP series, and ATLAS use ZMP preview control to pre-compute ground reaction forces ensuring the ZMP stays inside the support polygon."),
  q(2092,"Legged Locomotion","competitive","Starter",15,"What distinguishes a static gait from a dynamic gait in legged locomotion?",["Static gait: CoM projection stays inside the support polygon at all instants; dynamic gait: CoM may exit with inertia maintaining balance.","Static gaits require fewer legs than dynamic gaits to maintain stability during locomotion.","Dynamic gaits always achieve faster locomotion speeds than static gaits for any legged robot.","Static gaits are used exclusively for quadrupeds; dynamic gaits are used exclusively for bipeds."],0,"Static = freeze-stable at any instant; dynamic = inertia maintains balance when CoM exits support polygon.","Static gaits (hexapod tripod) are stable if frozen at any moment; dynamic gaits (biped walking, quadruped trot) rely on inertia and controlled falling to maintain balance through foot placement.","Boston Dynamics Spot uses dynamic trot and bound gaits; deliberate slow industrial hexapods use static crawl gaits for maximum stability."),
  q(2093,"Legged Locomotion","competitive","Starter",15,"What is the spring-loaded inverted pendulum (SLIP) model and why is it used as a locomotion template?",["SLIP models a runner as a point mass on a massless spring leg, capturing energy storage and return dynamics minimally.","SLIP is a full 3D model incorporating all individual link joint dynamics for accurate simulation.","SLIP applies only to bipedal runners; quadrupedal locomotion requires a different template model.","SLIP models are used exclusively for analysis and cannot inform any controller design."],0,"Point mass + spring leg = essential energy mechanics of running in a two-parameter model.","SLIP exhibits self-stable running gaits; real biological and robotic runners exploit leg compliance in ways that SLIP captures with minimal parameters.","MIT Cheetah, Cassie, and Atlas controllers are anchored to SLIP dynamics through virtual leg spring compliance."),
  q(2094,"Legged Locomotion","competitive","Starter",15,"What is the role of centroidal angular momentum in legged robot balance control?",["Centroidal angular momentum represents whole-body rotational momentum about the CoM; regulating it prevents uncontrolled spinning.","Centroidal angular momentum is always exactly zero for any statically balanced robot posture.","Centroidal angular momentum is only used to compute the ZMP for biped walking controllers.","Centroidal angular momentum equals the sum of all individual joint angular velocities."],0,"Uncontrolled angular momentum spins the body — momentum-aware control explicitly regulates this.","During foot lift or contact transitions, angular momentum built up in links can spin the entire body; centroidal angular momentum L = sum(I_i*omega_i + r_i x m_i*v_i) must be explicitly managed.","Atlas whole-body controller explicitly minimises centroidal angular momentum rate to prevent body rotation during arm and leg movements."),
  q(2095,"Legged Locomotion","competitive","Starter",15,"Why do legged robots with multiple simultaneous contacts require QP-based contact force distribution?",["Multiple contacts create statically indeterminate force distributions; QP optimises forces subject to friction and normal constraints.","Contact forces are uniquely determined by Newton's laws for any number of simultaneous contacts.","Force distribution optimisation is only needed when there are strictly more than six contact points.","Legged robots are designed to avoid any simultaneous multi-contact phases in their gaits."],0,"n > 6 contacts -> infinite valid force distributions -> optimise for minimum torques within friction cones.","With more than 6 total contact force components, Newton-Euler constraints are under-determined; QP finds the force distribution minimising joint torques while satisfying friction cone, normal force, and wrench balance constraints.","ANYmal, MIT Cheetah, and Spot whole-body controllers solve contact force QPs at 1 kHz to achieve stable locomotion on rough terrain."),
  q(2096,"Legged Locomotion","competitive","Research",20,"How does centroidal MPC enable real-time whole-body motion planning for quadrupedal robots?",["Centroidal MPC optimises CoM and contact forces using the compact 6-DOF centroidal model; a WBC tracks the plan at joint level.","Centroidal MPC solves the full articulated multibody dynamics problem directly in real time.","The centroidal model is used only for offline trajectory design and not in any real-time system.","Centroidal MPC directly outputs joint torque commands without any lower-level controller."],0,"Fast centroidal planning (6 DOF) + whole-body IK tracking: hierarchical real-time control.","Centroidal model captures aggregate linear and angular momentum; MPC optimises contact force trajectories over a short horizon (~0.5 s) at 100-400 Hz; a whole-body inverse dynamics controller tracks the centroidal plan at joint level.","MIT Mini Cheetah and ANYmal demonstrated dynamic stair climbing and rough terrain locomotion using centroidal MPC in peer-reviewed publications."),
  q(2097,"Legged Locomotion","competitive","Research",20,"Why does domain randomisation in RL-based locomotion training produce better hardware robustness than model-based control?",["Domain randomisation exposes the policy to diverse dynamics, learning robust strategies that generalise beyond nominal parameters.","RL is more robust simply because neural network policies have more parameters than model-based controllers.","RL outperforms model-based controllers only on completely flat terrain with known contact properties.","RL policies require perfect state estimation; model-based controllers tolerate more sensor noise."],0,"Trained on thousands of dynamics variations -> the real world is just one more variation seen at test time.","By randomising mass, friction, terrain roughness, motor delays, and sensor noise during training, the RL policy learns strategies robust to all these variations, effectively performing implicit worst-case robust control.","ANYmal, Cassie, and MIT Cheetah achieved successful hardware transfer via RL with domain randomisation, including locomotion over previously unseen outdoor terrain."),
  q(2098,"Legged Locomotion","competitive","Research",20,"What makes contact-implicit trajectory optimisation for legged locomotion computationally intractable in the general case?",["Complementarity constraints for contact create a non-smooth MPCC with combinatorial mode sequences and many local minima.","Contact-implicit TO is simpler because it eliminates discrete contact mode enumeration from the problem.","Contact-implicit TO always converges to globally optimal periodic gait trajectories.","The computational challenge is solely the cost of computing the full articulated-body inertia matrix."],0,"f_n >= 0, d >= 0, f_n*d = 0 is non-smooth non-convex + mode sequences are combinatorial.","Contact complementarity conditions create mathematical programs with complementarity constraints (MPCC); combined with n-link dynamics and multiple contact points, the problem has many local minima and non-smooth gradient structure.","DIRTREL, CALIPSO, and contact-implicit iLQG use relaxed complementarity penalties and trajectory warm-starting to find locally good solutions reliably."),
  q(2099,"Legged Locomotion","competitive","Research",20,"How do series elastic actuators (SEA) improve legged robot locomotion energy efficiency?",["SEA's spring element stores impact energy during landing and returns it during push-off, reducing net electrical energy per step.","SEA improves efficiency by mechanically reducing joint friction at all operating speeds.","SEA actuators are more energy-efficient only at locomotion speeds exceeding 5 m/s.","SEA reduces control bandwidth requirements but has no effect on energy consumption."],0,"Spring stores impact energy -> returns it at push-off: electrical energy only needed for net work.","In running, kinetic energy at touchdown is stored in the spring as elastic potential energy; it is released during push-off, reducing the electrical energy the motor must supply.","ANYmal uses ANYdrive SEA joints; published measurements show ~20% reduction in electrical energy per step compared to stiff-actuated alternatives at walking speeds."),
  q(2100,"Legged Locomotion","competitive","Research",20,"What is the key insight of the Raibert stepping controller for dynamically stable running?",["Place each foot at the SLIP neutral point plus a proportional correction to CoM velocity error to centre the gait each step.","Raibert's controller solves the full SLIP ODE dynamics online for each individual step.","The controller requires a precomputed lookup table of all possible speed-step-length combinations.","Raibert's stepping rule applies exclusively to quadrupedal bounding and no other gait pattern."],0,"Neutral point + k_v*(v - v*) = self-correcting step placement — simple, robust, elegant.","Neutral point x_n is where the SLIP model would return exactly to initial conditions; correction k_v*(v - v*) adds a displacement proportional to velocity error each step, providing passive orbital stability.","BigDog, MIT Cheetah, and MABEL all use variants of Raibert-inspired stepping to achieve robust dynamic running with simple control laws."),
  q(2101,"Legged Locomotion","competitive","Research",20,"How does hybrid zero dynamics (HZD) enable provably stable bipedal walking via virtual constraints?",["Virtual constraints enforce output functions to zero via feedback, rendering invariant a lower-dimensional zero surface with analysable orbits.","Virtual constraints are physical compliant springs mechanically implemented in the robot joints.","HZD applies exclusively to holonomically constrained robots and not to underactuated bipeds.","Virtual constraints specify joint angle references directly without requiring any feedback control."],0,"y = h(q) = 0 enforced by I/O linearisation -> hybrid zero manifold -> provable orbit stability on it.","Choosing smooth outputs y = h(q) and enforcing y = 0 via I/O linearisation renders a lower-dimensional hybrid zero surface invariant; stability of the hybrid limit cycle on this surface implies stability of the full 3D walking system.","DURUS, RABBIT, and Cassie walking controllers use HZD-based gait design with formal stability proofs."),
  q(2102,"Legged Locomotion","competitive","Research",20,"How does polyhedral friction cone linearisation enable real-time QP-based legged robot force control?",["Linearising the friction cone as a polyhedral pyramid converts the SOCP into a standard QP solvable at 1 kHz.","Polyhedral linearisation simplifies the kinematic model, not the contact force optimisation problem.","The contact wrench cone is already polyhedral, requiring no linearisation for QP formulation.","QP-based force control requires the exact second-order cone friction constraint without approximation."],0,"||f_t|| <= mu*f_n (SOCP) approximated as linear facets -> QP instead of SOCP: 10-100x faster.","True friction cone: ||f_t|| <= mu*f_n is a second-order cone constraint; linearising it as 4-8 half-planes converts the SOCP to a QP, which is solvable at 1 kHz on embedded hardware where SOCPs may only run at 100 Hz.","MIT Cheetah, ANYmal, and Boston Dynamics Spot all use linearised friction cone QPs in their onboard whole-body controllers."),
  q(2103,"Legged Locomotion","competitive","Research",20,"What limits model-based footstep planners on unstructured outdoor terrain compared to learned planners?",["Model-based planners require accurate terrain contact models; learning generalises from experience beyond the model's scope.","Model-based planners always outperform learned planners on all outdoor terrain types.","Learned footstep planners require complete 3D terrain maps unlike model-based planners.","The limitation is computational; model-based planners are too slow for real-time outdoor planning."],0,"Mud, grass, rocks, and ice have contact properties no rigid-body model captures accurately.","Uneven outdoor terrain creates contact dynamics (soil deformation, variable friction, elastic substrate) that rigid-body models with Coulomb friction fundamentally cannot capture; learned policies absorb these effects implicitly from diverse simulation.","Boston Dynamics Spot uses model-based planning for nominal terrain and learned terrain adaptation modules for challenging outdoor surfaces."),
  q(2104,"Legged Locomotion","competitive","Research",20,"How does gait emergence in RL-trained locomotion controllers differ from explicitly programmed model-based gaits?",["RL discovers trot, bound, and gallop as emergent reward-maximising solutions without explicit gait programming.","RL can only discover walking gaits; all other gaits must be explicitly programmed.","Emergent RL gaits are always less energy-efficient than analytically designed SLIP-based gaits.","RL-discovered gaits are identical to analytically derived SLIP template gaits."],0,"Reward optimisation discovers biologically natural gait patterns nobody programmed — they emerge spontaneously.","Trained with speed and energy efficiency rewards, RL policies spontaneously transition between walk, trot, bound, and gallop at biologically appropriate speeds without any explicit gait prescription.","DeepMind's locomotion work and ETH Zurich ANYmal controllers exhibit natural gait transitions that closely match biological observations in dogs and cats."),
  q(2105,"Legged Locomotion","competitive","Research",20,"What is the fundamental passivity-based advantage for legged robots interacting with uncertain ground contact?",["Passive robots have inherent stability with any passive environment by passivity composition, regardless of ground stiffness.","Passivity-based control eliminates the need for any feedback sensing during contact interactions.","Passive control is only stable for quasi-static locomotion and fails for dynamic running.","Passivity guarantees stability only when the ground contact is perfectly rigid and known."],0,"Passive robot + passive environment = stable interaction by passivity composition — no contact model needed.","If the robot exhibits passivity (V_dot <= u^T*y) and the environment is also passive (as physical contact always is), their interconnection is stable by passivity composition theorem, regardless of the specific contact model.","Variable impedance controllers on Atlas and Valkyrie exploit passivity to achieve robust stable contact across diverse terrain and object properties."),

  // ── COMPETITIVE: Motion Planning ─────────────────────────────────────────
  q(2106,"Motion Planning","competitive","Starter",15,"What is resolution completeness and how is it weaker than exact completeness in motion planning?",["Resolution complete finds a path if one exists at the discretisation used; exact complete always finds a path if one exists.","Resolution completeness is stronger because it provides a deterministic guarantee independent of any parameter.","Resolution completeness applies only to grid-based planners; exact completeness applies to all planners.","Both completeness notions guarantee finding a path in finite time if one exists."],0,"Resolution complete = guaranteed at grid scale; exact complete = guaranteed at any scale.","Exact completeness guarantees finding a path for any continuous configuration space; resolution completeness only guarantees finding a path representable at the chosen discretisation resolution.","A* on a coarse grid is resolution complete but might miss narrow passages smaller than one grid cell."),
  q(2107,"Motion Planning","competitive","Starter",15,"Why does A* guarantee finding the optimal path when the heuristic is admissible?",["An admissible heuristic never overestimates true cost; A* expands nodes in f = g + h order, reaching the goal optimally first.","A* is optimal only when the heuristic is identically zero (reducing it to Dijkstra's algorithm).","Admissible heuristics guarantee optimality only for graph-based discrete planning problems.","A* finds the optimal path only if the heuristic is also consistent (monotone) not just admissible."],0,"h <= h* means f = g + h never overestimates the total cost — goal is expanded optimally first.","With admissible h, no overestimate biases expansion order; when the goal is first popped from the open set, its g-value is the optimal cost because all paths with lower f have been explored.","Euclidean distance is admissible for holonomic robots in obstacle-free Euclidean space."),
  q(2108,"Motion Planning","competitive","Starter",15,"What is the key computational advantage of RRT over grid-based planners for high-dimensional robot arms?",["RRT samples and extends a tree avoiding explicit discretisation of the exponentially large C-space.","RRT is faster than A* because it uses a hash table rather than a priority queue data structure.","RRT avoids collision checking by assuming the robot operates in a convex obstacle-free environment.","RRT is faster than A* only for planning problems with fewer than three degrees of freedom."],0,"Sampling avoids the 10^10 or more grid nodes needed for a 10-DOF robot — feasible where grids are not.","A 10-DOF robot with 100 cells/DOF needs 10^20 grid nodes; RRT grows a sparse tree by sampling, needing only ~10,000 nodes for most manipulation problems.","RRT and its variants are the dominant approach for manipulation planning in MoveIt! and OMPL."),
  q(2109,"Motion Planning","competitive","Starter",15,"What asymptotic optimality property does RRT* provide that standard RRT lacks?",["RRT* rewires the tree for optimal paths; as sample count approaches infinity the solution converges to optimal.","RRT* finds the optimal path in finite time given a fixed predetermined number of random samples.","RRT* provides asymptotic optimality only for holonomic systems without differential constraints.","RRT* requires a consistent admissible heuristic to achieve asymptotic optimality."],0,"Rewiring + infinite samples = optimal path in the limit — RRT without rewiring never improves its path quality.","At each new sample, RRT* considers all nearby nodes within a shrinking radius as potential parents, rewiring to the one giving the lowest cost; this enables monotonic improvement toward the optimal path.","For 7-DOF manipulation, 10,000-50,000 RRT* samples typically find near-optimal collision-free paths."),
  q(2110,"Motion Planning","competitive","Starter",15,"Why is PRM preferred over RRT for multi-query planning in a static robot workspace?",["PRM builds the roadmap once amortising construction cost across many queries each answered in O(log n).","PRM is faster than RRT for any single planning query regardless of environment complexity.","PRM avoids collision checking by sampling only valid free-configuration-space nodes.","PRM always guarantees finding the globally shortest path for any query it answers."],0,"Build once amortise over many queries — single robot doing hundreds of pick-and-place operations.","RRT builds a new tree from scratch for every query (O(n) construction per query); PRM builds the roadmap once (O(n^2) construction), after which each query costs only O(log n) for nearest-neighbour lookup and graph search.","Warehouse manipulation robots use PRMs precomputed for their static cell layout to answer thousands of queries per shift."),
  q(2111,"Motion Planning","competitive","Research",20,"How does the narrow passage problem limit sampling-based planners and what bridge sampling does to address it?",["Narrow passages have tiny probability measure; bridge sampling explicitly generates samples near passage centres.","Narrow passages are handled by simply increasing total sample count proportionally to passage size.","The narrow passage problem only affects PRM and never affects RRT or any tree-based planner.","Narrow passages are only problematic for high-DOF robots with more than six degrees of freedom."],0,"Probability of uniform sample inside passage ~ volume/C-space volume -> exponential samples needed.","If passage has measure epsilon and total C-space has measure V, the probability of a uniform sample landing inside is epsilon/V ~ 0; bridge sampling generates midpoints between random collision pairs, biasing sampling toward passage centres.","OBPRM and Visibility-based PRM achieve 10-100x speedup on narrow-passage manipulation problems compared to uniform sampling."),
  q(2112,"Motion Planning","competitive","Research",20,"What is kinodynamic planning and why does it require forward simulation rather than straight-line C-space interpolation?",["Kinodynamic planning respects velocity and acceleration bounds; connecting states requires integrating differential equations forward.","Kinodynamic planning uses inverse kinematics to algebraically connect any two C-space states.","Forward simulation is only required when the robot has more than four independently controlled actuators.","Kinodynamic constraints can always be converted to holonomic constraints via coordinate transformation."],0,"Nonholonomic constraints: can't connect (x1,y1,theta1) to (x2,y2,theta2) in a straight line for a car.","For a Dubins car with constraint y_dot/x_dot = tan(theta), connecting two states via a straight C-space path would violate the nonholonomic constraint; forward simulation of admissible control inputs is required.","SST*, kinodynamic RRT*, and trajectory optimisation address planning for systems with differential motion constraints."),
  q(2113,"Motion Planning","competitive","Research",20,"How does BIT* improve convergence speed over RRT* while maintaining asymptotic optimality?",["BIT* uses heuristic pruning combined with batch implicit sampling to focus computation on solution-improving samples.","BIT* uses a larger nearest-neighbour radius than RRT* to find better rewiring candidates.","BIT* reduces the effective dimensionality of the search space by projecting to a lower-dimensional manifold.","BIT* replaces random sampling with quasi-random Halton sequences for better coverage."],0,"Prune non-improving samples with h + g >= c_best, then process remaining edges in f-value order.","BIT* maintains a batch of implicit RRT* samples; samples with f = g + h >= c_current_best cannot improve the solution and are pruned; remaining edges are processed in order of f-value, combining A*-style heuristic guidance with RRT* rewiring.","BIT* achieves RRT*-quality solutions with 10-100x fewer vertex expansions on typical motion planning benchmarks."),
  q(2114,"Motion Planning","competitive","Research",20,"Why does trajectory optimisation converge to locally optimal solutions that depend heavily on initialisation?",["The non-convex NLP from obstacle avoidance constraints has multiple local minima trapping gradient methods.","Trajectory optimisation always finds globally optimal solutions for smooth differentiable cost functions.","Local optima arise only in kinodynamic systems; pure geometric trajectory planning is always convex.","Trajectory optimisation with obstacle avoidance constraints is always a convex programming problem."],0,"Obstacles create non-convex feasible sets — gradient methods cannot escape the nearest local minimum.","Obstacle avoidance: d(q(t), obstacle) >= r creates non-convex constraints; gradient-based methods (TrajOpt, CHOMP, GPMP2) converge to whichever local minimum their initialisation falls into.","Combining sampling-based path planning (for feasible initialisation) with trajectory optimisation (for smooth locally optimal path) is the standard hybrid approach."),
  q(2115,"Motion Planning","competitive","Research",20,"What is a signed distance field (SDF) and why is it preferred for differentiable collision avoidance in trajectory optimisation?",["SDF stores signed distance to the nearest obstacle surface everywhere; smooth gradients enable differentiable collision costs.","SDF is preferred because it requires less memory than triangle mesh representations of obstacles.","SDF cannot accurately represent concave obstacle geometries in the robot workspace.","SDF is only applicable to 2D planning environments; 3D obstacles require mesh representations."],0,"Smooth everywhere differentiable distance -> gradient of SDF points away from nearest obstacle surface.","SDF(x) = +dist if free, -dist if occupied; gradient nabla*SDF(x) always points away from the nearest surface and has unit magnitude (Eikonal equation), providing a clean differentiable collision avoidance cost.","TrajOpt, CHOMP, and GPMP2 all use SDF-based collision costs for smooth differentiable arm trajectory optimisation in 3D obstacle fields."),
  q(2116,"Motion Planning","competitive","Research",20,"How does CHOMP's functional gradient formulation differ from standard parameter-space gradient optimisation?",["CHOMP minimises a functional over trajectories via functional gradient descent in the trajectory space.","CHOMP optimises only the start and end endpoint positions of the trajectory path.","CHOMP is a sampling-based method that evaluates trajectory cost through forward simulation.","CHOMP uses the L2 norm of joint torques as its primary trajectory optimisation objective."],0,"Functional gradient descent on the space of trajectories, not parameter vectors — optimise the curve itself.","CHOMP objective U[q] = integral[c_obs(q(t)) + (1/2)||q_dot||^2]dt; functional gradient deltaU/deltaq gives the steepest descent direction in the space of trajectory functions, combining obstacle avoidance and smoothness.","CHOMP and GPMP2 produce smooth, collision-free 7-DOF arm trajectories directly from an initial straight-line path through obstacle fields."),
  q(2117,"Motion Planning","competitive","Research",20,"What is the key insight of the informed RRT* algorithm that accelerates convergence?",["Informed RRT* samples only from the prolate hyperspheroid of all states that could possibly improve the current solution.","Informed RRT* uses a heuristic to prioritise which existing tree nodes to rewire first.","Informed RRT* restricts all samples to the convex hull of the current best path.","Informed sampling only activates after the very first feasible solution has been discovered."],0,"The improving set {x: d(start,x)+d(x,goal) <= c*} is an ellipse — sample only inside it.","Any state that could possibly improve a path of cost c* must satisfy d(x_start,x) + d(x,x_goal) <= c*; this defines a prolate hyperspheroid; sampling only inside it wastes no samples on non-improving states.","Informed RRT* converges to the optimum 10-100x faster than RRT* on standard manipulation planning benchmarks."),
  q(2118,"Motion Planning","competitive","Research",20,"How does Gaussian process motion planning (GPMP2) unify trajectory representation and optimisation probabilistically?",["GPMP2 models the trajectory as a sample from a GP prior and finds the MAP trajectory via factor graph inference.","GPMP2 uses GPs only for obstacle field modelling, not for trajectory parameterisation.","GPMP2 is a sampling-based planner that draws trajectory candidates from a GP prior distribution.","The GP prior in GPMP2 directly encodes the robot's articulated-body dynamic model."],0,"GP prior over trajectories + obstacle factors -> MAP inference via factor graph = probabilistic trajectory optimisation.","The GP prior encodes smooth kinodynamically consistent trajectories; obstacle and constraint factors encode costs; iSAM2-style incremental factor graph inference finds the MAP trajectory efficiently.","GPMP2 achieves real-time 7-DOF arm planning with uncertainty-aware collision avoidance at replanning rates suitable for dynamic environments."),
  q(2119,"Motion Planning","competitive","Research",20,"Why does maintaining topologically diverse path sets improve robustness in robot manipulation planning?",["Different homotopy classes represent qualitatively different obstacle avoidance strategies enabling immediate fallback.","All paths between the same endpoints are topologically identical for any robot planning problem.","Topological path classes only matter for 2D mobile robot navigation in planar environments.","Different homotopy class paths have identical cost and safety properties by geometric symmetry."],0,"Different topology = different obstacle avoidance strategy — if one path is blocked, another class provides a fallback.","If a robot's primary path (left of obstacle) becomes blocked by a newly detected obstacle, a pre-computed path in a different homotopy class (right of obstacle) provides immediate re-routing without replanning from scratch.","Homotopy-aware PRMs and topological roadmap methods maintain diverse path options in cluttered manipulation workspaces."),
  q(2120,"Motion Planning","competitive","Research",20,"How does the cell decomposition approach differ from sampling-based methods in completeness guarantees?",["Exact cell decomposition provides deterministic completeness by explicitly representing the full free C-space topology.","Cell decomposition provides only probabilistic completeness; sampling provides deterministic completeness.","Cell decomposition is incomplete because it cannot represent narrow passages in the free space.","Cell decomposition requires random samples to fill each cell with valid representative configurations."],0,"Explicit free-space topology -> deterministic completeness; sampling -> probabilistic completeness only.","Exact decomposition: partition C_free into cells and compute the connectivity graph explicitly — finds a path iff one exists at any scale. Sampling: finds a path with probability approaching 1 as samples approach infinity but not guaranteed in finite time.","2D navigation stacks use approximate cell decomposition (occupancy grid + A*) providing resolution completeness for structured environments."),

]; // ← END OF QUESTION_BANK

// ── utilities ────────────────────────────────────────────────────────────────
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
function buildPack(mode, realm) {
  return QUESTION_BANK.filter(item => item.mode === mode && item.realm === realm);
}

// ── sound ────────────────────────────────────────────────────────────────────
function useSound() {
  const ctx = useRef(null);
  const nodes = useRef([]);
  const active = useRef(false);

  function stop() {
    nodes.current.forEach(n => { try { n.stop(); } catch(e) {} });
    nodes.current = [];
    active.current = false;
  }

  function calm() {
    if (active.current) return;
    try {
      if (!ctx.current) ctx.current = new (window.AudioContext || window.webkitAudioContext)();
      const ac = ctx.current;
      active.current = true;
      const buf = ac.createBuffer(1, ac.sampleRate * 4, ac.sampleRate);
      const d = buf.getChannelData(0);
      for (let i = 0; i < d.length; i++) d[i] = Math.random() * 2 - 1;
      const src = ac.createBufferSource(); src.buffer = buf; src.loop = true;
      const flt = ac.createBiquadFilter(); flt.type = "lowpass"; flt.frequency.value = 400;
      const g = ac.createGain(); g.gain.value = 0.03;
      src.connect(flt); flt.connect(g); g.connect(ac.destination); src.start();
      nodes.current.push(src);
      [[110, 0.01], [220, 0.007], [55, 0.012]].forEach(([freq, gain]) => {
        const o = ac.createOscillator(); const og = ac.createGain();
        o.type = "sine"; o.frequency.value = freq; og.gain.value = gain;
        o.connect(og); og.connect(ac.destination); o.start();
        nodes.current.push(o);
      });
    } catch(e) {}
  }

  function competitive() {
    if (active.current) return;
    try {
      if (!ctx.current) ctx.current = new (window.AudioContext || window.webkitAudioContext)();
      const ac = ctx.current;
      active.current = true;
      const buf = ac.createBuffer(1, ac.sampleRate * 4, ac.sampleRate);
      const d = buf.getChannelData(0);
      for (let i = 0; i < d.length; i++) d[i] = Math.random() * 2 - 1;
      const src = ac.createBufferSource(); src.buffer = buf; src.loop = true;
      const flt = ac.createBiquadFilter(); flt.type = "lowpass"; flt.frequency.value = 400;
      const g = ac.createGain(); g.gain.value = 0.03;
      src.connect(flt); flt.connect(g); g.connect(ac.destination); src.start();
      nodes.current.push(src);
      [[110, 0.01], [220, 0.007], [55, 0.012]].forEach(([freq, gain]) => {
        const o = ac.createOscillator(); const og = ac.createGain();
        o.type = "sine"; o.frequency.value = freq; og.gain.value = gain;
        o.connect(og); og.connect(ac.destination); o.start();
        nodes.current.push(o);
      });
    } catch(e) {}
  }

  useEffect(() => () => stop(), []);
  return { calm, competitive, stop };
}

// ── toggle ────────────────────────────────────────────────────────────────────
function Toggle({ value, onChange, left, lv, right, rv, comp }) {
  return (
    <div className={`inline-flex rounded-2xl border p-1 ${comp ? "border-blue-300 bg-white" : "border-green-200 bg-white/80"}`}>
      {[{l: left, v: lv}, {l: right, v: rv}].map(({l, v}) => (
        <button key={v} onClick={() => onChange(v)}
          className={`rounded-xl px-3 py-2 text-sm font-semibold transition-all ${
            value === v
              ? (comp ? "bg-blue-600 text-white" : "bg-emerald-600 text-white")
              : (comp ? "text-slate-600 hover:bg-blue-50" : "text-slate-600 hover:bg-green-50")
          }`}>{l}</button>
      ))}
    </div>
  );
}

// ── main app ──────────────────────────────────────────────────────────────────
export default function App() {
  const [screen, setScreen] = useState("home");
  const [mode, setMode] = useState("calm");
  const [uiMode, setUiMode] = useState("normal");
  const [ri, setRi] = useState(0);
  const [qi, setQi] = useState(0);
  const [sel, setSel] = useState(null);
  const [hint, setHint] = useState(false);
  const [explain, setExplain] = useState(false);
  const [score, setScore] = useState(0);
  const [answered, setAnswered] = useState([]);
  const [saved, setSaved] = useState([]);
  const [search, setSearch] = useState("");
  const [muted, setMuted] = useState(false);
  const snd = useSound();

  const comp = mode === "competitive";
  const realms = comp ? COMPETITIVE_REALMS : CALM_REALMS;
  const realm = realms[ri];
  const questions = realm ? buildPack(mode, realm.name) : [];
  const curQ = questions[qi] || null;

  const opts = useMemo(() => {
    if (!curQ) return [];
    return shuffleArray(curQ.options.map((t, i) => ({ id: `${curQ.id}-${i}`, text: t, correct: i === curQ.answer })));
  }, [curQ?.id]);

  const acc = answered.length > 0 ? Math.round(answered.filter(a => a.correct).length / answered.length * 100) : 0;
  const prog = questions.length > 0 ? ((qi + (explain ? 1 : 0)) / questions.length) * 100 : 0;

  const T = comp ? {
    bg: "bg-gradient-to-br from-slate-50 via-blue-50 to-cyan-50",
    card: "border-blue-300 bg-white shadow-[0_14px_48px_rgba(37,99,235,0.15)]",
    panel: "border-blue-200 bg-blue-50",
    btn: "bg-blue-600 hover:bg-blue-500 text-white",
    acc: "text-blue-600",
    badge: "bg-blue-50 text-blue-700 border border-blue-300",
    bar: "from-blue-600 via-cyan-500 to-blue-400",
    prog: "bg-blue-600",
    h: "text-slate-900",
    sub: "text-slate-500",
    correct: "border-emerald-400 bg-emerald-50",
    wrong: "border-rose-300 bg-rose-50",
    selB: "border-blue-500 bg-blue-50",
    idle: "border-blue-200 bg-white hover:bg-blue-50",
    exit: "border-blue-300 text-blue-700 hover:bg-blue-50",
    body: "text-slate-800",
    muted: "text-slate-600",
  } : {
    bg: "bg-gradient-to-br from-slate-50 via-green-50 to-teal-50",
    card: "border-emerald-100 bg-white/95 shadow-[0_14px_48px_rgba(16,185,129,0.08)]",
    panel: "border-emerald-100 bg-emerald-50/70",
    btn: "bg-emerald-600 hover:bg-emerald-500 text-white",
    acc: "text-emerald-700",
    badge: "bg-emerald-50 text-emerald-700 border border-emerald-200",
    bar: "from-emerald-500 via-teal-400 to-cyan-400",
    prog: "bg-emerald-500",
    h: "text-slate-900",
    sub: "text-slate-500",
    correct: "border-emerald-400 bg-emerald-50",
    wrong: "border-rose-300 bg-rose-50",
    selB: "border-emerald-400 bg-emerald-50",
    idle: "border-emerald-100 bg-white hover:bg-emerald-50/60",
    exit: "border-emerald-200 text-slate-600 hover:bg-emerald-50",
    body: "text-slate-800",
    muted: "text-slate-600",
  };

  function resetQ() { setSel(null); setHint(false); setExplain(false); }

  function startMode(m, idx = 0) {
    setMode(m); setRi(idx); setQi(0); setScore(0); setAnswered([]); resetQ(); setScreen("play");
    if (!muted) { snd.stop(); setTimeout(() => m === "calm" ? snd.calm() : snd.competitive(), 300); }
  }

  function openRealm(m, idx) {
    setMode(m); setRi(idx); setQi(0); resetQ(); setScreen("play");
    if (!muted) { snd.stop(); setTimeout(() => m === "calm" ? snd.calm() : snd.competitive(), 300); }
  }

  function submit() {
    if (sel === null || explain || !curQ) return;
    const correct = !!opts[sel]?.correct;
    if (correct) setScore(s => s + curQ.points);
    setAnswered(a => [...a, { id: curQ.id, correct }]);
    setExplain(true);
  }

  function toggleSave() {
    if (!curQ) return;
    setSaved(s => s.includes(curQ.id) ? s.filter(id => id !== curQ.id) : [...s, curQ.id]);
  }

  function next() {
    if (!curQ) return;
    if (qi + 1 < questions.length) { setQi(i => i + 1); resetQ(); return; }
    if (ri + 1 < realms.length) { setScreen("done"); return; }
    setScreen("result"); snd.stop();
  }

  function continueRealm() {
    if (ri + 1 >= realms.length) { setScreen("result"); snd.stop(); return; }
    setRi(i => i + 1); setQi(0); resetQ(); setScreen("play");
  }

  function goHome() { setScreen("home"); snd.stop(); }

  function toggleMute() {
    if (muted) {
      setMuted(false);
      if (screen === "play") setTimeout(() => mode === "calm" ? snd.calm() : snd.competitive(), 100);
    } else { setMuted(true); snd.stop(); }
  }

  const fCalm = CALM_REALMS.filter(r => !search || r.name.toLowerCase().includes(search.toLowerCase()) || r.description.toLowerCase().includes(search.toLowerCase()));
  const fComp = COMPETITIVE_REALMS.filter(r => !search || r.name.toLowerCase().includes(search.toLowerCase()) || r.description.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className={`min-h-screen p-4 md:p-6 ${T.bg} transition-all duration-700`}>
      <div className="max-w-7xl mx-auto space-y-5">

        {/* HEADER */}
        <motion.div initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}
          className={`flex flex-wrap items-center justify-between gap-4 rounded-[28px] border px-5 py-4 ${T.card}`}>
          <div>
            <div className={`inline-flex items-center gap-2 rounded-full border px-3 py-1 text-xs font-bold uppercase tracking-widest ${T.badge}`}>
              {comp ? "⚡ COMPETITIVE" : "🌿 CALM"} — Physical AI Quiz
            </div>
            <h1 className={`mt-2 text-3xl md:text-4xl font-black tracking-tight ${T.h}`}>Physical AI — Mission Possible</h1>
            <p className={`mt-1 text-sm ${T.sub}`}>{comp ? "High-stakes research questions. Prove your mastery." : "Build deep foundations. Learn without pressure."}</p>
          </div>
          <div className="flex flex-wrap items-center gap-3">
            <button onClick={toggleMute} className={`rounded-2xl px-3 py-2 text-sm font-medium border transition-all ${T.exit}`}>{muted ? "🔇 Unmute" : "🔊 Mute"}</button>
          </div>
        </motion.div>

        {/* HOME */}
        {screen === "home" && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
            <div className="grid lg:grid-cols-2 gap-5">
              <motion.div whileHover={{ y: -4 }} onClick={() => startMode("calm")}
                className="rounded-[28px] border border-emerald-100 bg-white/95 shadow-lg overflow-hidden cursor-pointer">
                <div className="h-2 bg-gradient-to-r from-emerald-400 via-teal-400 to-cyan-400" />
                <div className="p-7 space-y-4">
                  <div className="text-4xl">🌿</div>
                  <h2 className="text-2xl md:text-3xl font-black text-slate-900">Calm Mode</h2>
                  <p className="text-slate-600 leading-relaxed">10 foundational realms. 15 questions each covering kinematics to computation — no pressure, pure learning.</p>
                  <div className="flex flex-wrap gap-2">
                    {CALM_REALMS.slice(0,5).map(r => <span key={r.name} className="px-2 py-1 rounded-full bg-emerald-50 text-emerald-700 text-xs font-semibold border border-emerald-200">{r.icon} {r.name}</span>)}
                    <span className="px-2 py-1 rounded-full bg-slate-100 text-slate-500 text-xs font-semibold">+5 more</span>
                  </div>
                  <button className="mt-2 rounded-2xl px-6 py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-bold transition-all w-full">Start Calm Mode 🌱</button>
                </div>
              </motion.div>

              <motion.div whileHover={{ y: -4 }} onClick={() => startMode("competitive")}
                className="rounded-[28px] border border-blue-300 bg-white shadow-[0_14px_48px_rgba(37,99,235,0.18)] overflow-hidden cursor-pointer">
                <div className="h-2 bg-gradient-to-r from-blue-600 via-cyan-500 to-blue-400" />
                <div className="p-7 space-y-4">
                  <div className="text-4xl">⚡</div>
                  <h2 className="text-2xl md:text-3xl font-black text-slate-900">Competitive Mode</h2>
                  <p className="text-slate-600 leading-relaxed">8 research-level realms. 15 questions each — RL, optimization, foundation models and beyond.</p>
                  <div className="flex flex-wrap gap-2">
                    {COMPETITIVE_REALMS.slice(0,5).map(r => <span key={r.name} className="px-2 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-semibold border border-blue-200">{r.icon} {r.name}</span>)}
                    <span className="px-2 py-1 rounded-full bg-slate-100 text-slate-500 text-xs font-semibold">+3 more</span>
                  </div>
                  <button className="mt-2 rounded-2xl px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white font-bold transition-all w-full">Enter Competitive Mode ⚡</button>
                </div>
              </motion.div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {[
                { label: "Total Questions", value: QUESTION_BANK.length, icon: "📚" },
                { label: "Calm Realms", value: CALM_REALMS.length, icon: "🌿" },
                { label: "Competitive Realms", value: COMPETITIVE_REALMS.length, icon: "⚡" },
                { label: "Max Points", value: QUESTION_BANK.reduce((s, q) => s + q.points, 0), icon: "🏆" },
              ].map(s => (
                <div key={s.label} className={`rounded-2xl border p-4 text-center ${T.card}`}>
                  <div className="text-2xl mb-1">{s.icon}</div>
                  <div className={`text-3xl font-black ${T.acc}`}>{s.value}</div>
                  <div className={`text-xs mt-1 ${T.sub}`}>{s.label}</div>
                </div>
              ))}
            </div>

            <div className={`rounded-[28px] border p-6 space-y-5 ${T.card}`}>
              <div className="flex flex-wrap items-center justify-between gap-3">
                <h2 className={`text-2xl font-black ${T.h}`}>Browse Realms</h2>
                <Input value={search} onChange={e => setSearch(e.target.value)} placeholder="🔍 Search topic..."
                  className={`max-w-xs rounded-2xl text-sm border ${comp ? "border-red-900/40 bg-black/60 text-red-100 placeholder:text-red-400/40" : "border-emerald-100 bg-white text-slate-900 placeholder:text-slate-400"}`} />
              </div>

              <div>
                <div className="flex items-center gap-2 mb-3">
                  <span className="px-3 py-1 rounded-full bg-emerald-50 text-emerald-700 text-xs font-bold border border-emerald-200">🌿 Calm Mode</span>
                  <span className="text-sm text-slate-500">15 questions each</span>
                </div>
                <div className="grid sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-3">
                  {fCalm.map((r, i) => (
                    <motion.button whileHover={{ y: -3, scale: 1.02 }} whileTap={{ scale: 0.98 }}
                      key={r.name} onClick={() => openRealm("calm", CALM_REALMS.indexOf(r))}
                      className="rounded-[20px] border border-emerald-100 bg-white hover:bg-emerald-50 p-4 text-left shadow-md transition-all">
                      <div className="h-1 rounded-full bg-gradient-to-r from-emerald-500 to-teal-400 mb-3" />
                      <div className="text-xl mb-1">{r.icon}</div>
                      <div className="font-bold text-slate-900 text-sm">{r.name}</div>
                      <div className="text-xs text-slate-500 mt-1 leading-relaxed line-clamp-2">{r.description}</div>
                      <div className="mt-2 text-xs font-semibold text-emerald-600">15 questions →</div>
                    </motion.button>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex items-center gap-2 mb-3">
                  <span className="px-3 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-bold border border-blue-200">⚡ Competitive Mode</span>
                  <span className="text-sm text-slate-500">15 questions each</span>
                </div>
                <div className="grid sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                  {fComp.map((r, i) => (
                    <motion.button whileHover={{ y: -3, scale: 1.02 }} whileTap={{ scale: 0.98 }}
                      key={r.name} onClick={() => openRealm("competitive", COMPETITIVE_REALMS.indexOf(r))}
                      className="rounded-[20px] border border-blue-200 bg-white hover:bg-blue-50 p-4 text-left shadow-md transition-all">
                      <div className="h-1 rounded-full bg-gradient-to-r from-blue-600 to-cyan-400 mb-3" />
                      <div className="text-xl mb-1">{r.icon}</div>
                      <div className="font-bold text-slate-900 text-sm">{r.name}</div>
                      <div className="text-xs text-slate-500 mt-1 leading-relaxed line-clamp-2">{r.description}</div>
                      <div className="mt-2 text-xs font-semibold text-blue-600">15 questions →</div>
                    </motion.button>
                  ))}
                </div>
              </div>
            </div>
          </motion.div>
        )}

        {/* PLAY */}
        {screen === "play" && curQ && (
          <div className="grid xl:grid-cols-[1.1fr_0.9fr] gap-5 items-start">
            <Card className={`rounded-[32px] border overflow-hidden ${T.card}`}>
              <div className={`h-2 bg-gradient-to-r ${T.bar}`} />
              <CardContent className="p-5 md:p-7 space-y-5">
                <div className="flex flex-wrap items-center justify-between gap-3">
                  <div className="flex flex-wrap items-center gap-2">
                    <span className={`px-2.5 py-1 rounded-full text-xs font-bold ${T.badge}`}>{curQ.realm}</span>
                    <span className={`px-2.5 py-1 rounded-full text-xs font-bold ${T.badge}`}>{curQ.difficulty}</span>
                    <span className={`px-2.5 py-1 rounded-full text-xs font-bold ${T.badge}`}>Q{qi + 1}/{questions.length}</span>
                    <span className={`text-xs font-bold ${T.acc}`}>{curQ.points} pts</span>
                  </div>
                  <button onClick={goHome} className={`rounded-xl px-3 py-1.5 text-xs font-semibold border transition-all ${T.exit}`}>← Exit</button>
                </div>

                <div className="space-y-1">
                  <div className={`flex justify-between text-xs font-bold ${T.sub}`}><span>Progress</span><span>{Math.round(prog)}%</span></div>
                  <Progress value={prog} className="h-2.5 rounded-full" color={T.prog} />
                </div>

                <AnimatePresence mode="wait">
                  <motion.div key={curQ.id} initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} transition={{ duration: 0.25 }} className="space-y-4">
                    <div className={`rounded-[24px] border p-5 ${T.panel}`}>
                      <div className={`text-xs font-bold uppercase tracking-widest mb-2 ${T.acc}`}>Question</div>
                      <h2 className={`text-xl md:text-2xl font-black leading-snug ${T.h}`}>{curQ.prompt}</h2>
                    </div>

                    <div className="grid gap-2.5">
                      {opts.map((opt, i) => {
                        const isC = explain && opt.correct;
                        const isW = explain && sel === i && !opt.correct;
                        return (
                          <motion.button key={opt.id} whileHover={!explain ? { scale: 1.01 } : {}} whileTap={!explain ? { scale: 0.99 } : {}}
                            onClick={() => !explain && setSel(i)}
                            className={`rounded-[20px] border px-4 py-3.5 text-left transition-all duration-200 ${isC ? T.correct : isW ? T.wrong : sel === i ? T.selB : T.idle}`}>
                            <div className="flex items-start gap-3">
                              <div className={`mt-0.5 h-8 w-8 rounded-full border-2 flex-shrink-0 flex items-center justify-center text-xs font-black ${
                                isC ? "border-emerald-400 text-emerald-400" :
                                isW ? "border-red-400 text-red-400" :
                                sel === i ? (comp ? "border-red-500 text-red-400" : "border-emerald-500 text-emerald-600") :
                                (comp ? "border-red-900/40 text-red-400/50" : "border-slate-200 text-slate-500")
                              }`}>{String.fromCharCode(65 + i)}</div>
                              <span className="leading-relaxed text-sm md:text-base text-slate-900 font-medium">{opt.text}</span>
                              {isC && <span className="ml-auto text-emerald-500 text-lg flex-shrink-0">✓</span>}
                              {isW && <span className="ml-auto text-red-400 text-lg flex-shrink-0">✗</span>}
                            </div>
                          </motion.button>
                        );
                      })}
                    </div>

                    <div className="flex flex-wrap gap-2">
                      <motion.button whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }}
                        onClick={submit} disabled={sel === null || explain}
                        className={`rounded-2xl px-5 py-2.5 font-bold text-sm disabled:opacity-40 ${T.btn}`}>Submit Answer</motion.button>
                      <button onClick={() => setHint(h => !h)} className={`rounded-2xl px-4 py-2.5 font-semibold text-sm border ${T.exit}`}>{hint ? "Hide Hint" : "💡 Hint"}</button>
                      <button onClick={toggleSave} className={`rounded-2xl px-4 py-2.5 font-semibold text-sm border ${T.exit}`}>{saved.includes(curQ.id) ? "⭐ Saved" : "☆ Save"}</button>
                    </div>

                    {hint && (
                      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className={`rounded-[20px] border p-4 ${T.panel}`}>
                        <div className={`text-xs font-bold uppercase tracking-widest mb-1 ${T.acc}`}>Hint</div>
                        <p className="text-sm leading-relaxed text-slate-900">{curQ.hint}</p>
                      </motion.div>
                    )}

                    {explain && (
                      <motion.div initial={{ opacity: 0, y: 12 }} animate={{ opacity: 1, y: 0 }} className="space-y-3">
                        <div className="rounded-[20px] border border-emerald-400/30 bg-emerald-900/20 p-4">
                          <div className="text-xs font-bold uppercase tracking-widest text-emerald-400 mb-1">Explanation</div>
                          <p className="text-sm leading-relaxed text-slate-900">{curQ.explain}</p>
                        </div>
                        <div className={`rounded-[20px] border p-4 ${T.panel}`}>
                          <div className={`text-xs font-bold uppercase tracking-widest mb-1 ${T.acc}`}>Example</div>
                          <p className="text-sm leading-relaxed text-slate-900">{curQ.example}</p>
                        </div>
                        <motion.button whileHover={{ scale: 1.02 }} whileTap={{ scale: 0.98 }}
                          onClick={next} className={`rounded-2xl px-6 py-3 font-bold w-full ${T.btn}`}>Next Question →</motion.button>
                      </motion.div>
                    )}
                  </motion.div>
                </AnimatePresence>
              </CardContent>
            </Card>

            <div className="space-y-4">
              <div className={`rounded-[28px] border p-5 space-y-4 ${T.card}`}>
                <h3 className={`text-lg font-black ${T.h}`}>Session</h3>
                <div className="grid grid-cols-2 gap-3">
                  {[{ l: "Score", v: score }, { l: "Accuracy", v: `${acc}%` }, { l: "Answered", v: answered.length }, { l: "Saved", v: saved.length }].map(s => (
                    <div key={s.l} className={`rounded-2xl border p-3 text-center ${T.panel}`}>
                      <div className={`text-xs font-bold uppercase tracking-wider ${T.sub}`}>{s.l}</div>
                      <div className={`text-2xl font-black mt-1 ${T.acc}`}>{s.v}</div>
                    </div>
                  ))}
                </div>
                <div className={`rounded-2xl border p-3 ${T.panel}`}>
                  <div className={`text-xs font-bold uppercase ${T.sub}`}>Realm</div>
                  <div className={`font-bold mt-1 ${T.acc}`}>{realm?.icon} {realm?.name}</div>
                </div>
                <div className={`rounded-2xl border p-3 ${T.panel}`}>
                  <div className={`text-xs font-bold uppercase ${T.sub}`}>Mode</div>
                  <div className={`font-bold mt-1 ${T.acc}`}>{comp ? "⚡ Competitive" : "🌿 Calm"}</div>
                </div>
              </div>
              <div className={`rounded-[28px] border p-5 ${T.card}`}>
                <h3 className={`text-lg font-black mb-3 ${T.h}`}>Tips</h3>
                <div className="space-y-2">
                  {[
                    comp ? "Research-level — think theoretically, not by elimination." : "Take your time — deep understanding matters.",
                    "Use the hint if you are stuck before submitting.",
                    "Save cards you want to review later.",
                    comp ? "15 questions per realm: 5 Starter + 10 Research." : "Questions increase in depth across the realm.",
                  ].map((t, i) => (
                    <div key={i} className={`rounded-xl border p-2.5 text-xs leading-relaxed ${T.panel} ${T.muted}`}>{t}</div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* REALM DONE */}
        {screen === "done" && (
          <div className="max-w-3xl mx-auto">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className={`rounded-[32px] border overflow-hidden ${T.card}`}>
              <div className={`h-2 bg-gradient-to-r ${T.bar}`} />
              <div className="p-8 space-y-6 text-center">
                <div className="text-6xl">{comp ? "⚡" : "🌿"}</div>
                <div>
                  <div className={`text-xs font-bold uppercase tracking-widest ${T.acc}`}>Realm Complete</div>
                  <h2 className={`mt-2 text-3xl font-black ${T.h}`}>{realm?.name} ✓</h2>
                </div>
                <div className="grid grid-cols-3 gap-4">
                  {[{ l: "Score", v: score }, { l: "Accuracy", v: `${acc}%` }, { l: "Up Next", v: realms[ri + 1]?.name || "Results" }].map(s => (
                    <div key={s.l} className={`rounded-2xl border p-4 ${T.panel}`}>
                      <div className={`text-xs font-bold ${T.sub}`}>{s.l}</div>
                      <div className={`text-xl font-black mt-1 ${T.acc}`}>{s.v}</div>
                    </div>
                  ))}
                </div>
                <motion.button whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }}
                  onClick={continueRealm} className={`rounded-2xl px-8 py-3 font-bold text-lg w-full ${T.btn}`}>
                  Continue → {realms[ri + 1]?.name || "See Results"}
                </motion.button>
              </div>
            </motion.div>
          </div>
        )}

        {/* RESULT */}
        {screen === "result" && (
          <div className="max-w-3xl mx-auto">
            <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className={`rounded-[32px] border overflow-hidden ${T.card}`}>
              <div className={`h-2 bg-gradient-to-r ${T.bar}`} />
              <div className="p-8 space-y-6 text-center">
                <div className="text-6xl">{comp ? "🏆" : "🌟"}</div>
                <div>
                  <h2 className={`text-3xl font-black ${T.h}`}>Session Complete!</h2>
                  <p className={`mt-1 text-sm ${T.sub}`}>You finished {comp ? "Competitive" : "Calm"} Mode</p>
                </div>
                <div className="grid grid-cols-3 gap-4">
                  {[{ l: "Final Score", v: score }, { l: "Accuracy", v: `${acc}%` }, { l: "Saved Cards", v: saved.length }].map(s => (
                    <div key={s.l} className={`rounded-2xl border p-5 ${T.panel}`}>
                      <div className={`text-xs font-bold ${T.sub}`}>{s.l}</div>
                      <div className={`text-3xl font-black mt-1 ${T.acc}`}>{s.v}</div>
                    </div>
                  ))}
                </div>
                <div className={`rounded-2xl border p-4 text-sm leading-relaxed ${T.panel} ${T.muted}`}>
                  {comp ? "Outstanding. Research-level mastery takes time — review saved cards and push your score higher." : "Great work! Revisit saved cards to consolidate understanding and try Competitive Mode when ready."}
                </div>
                <div className="flex flex-wrap gap-3 justify-center">
                  <motion.button whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }}
                    onClick={() => startMode(mode)} className={`rounded-2xl px-6 py-3 font-bold ${T.btn}`}>Replay {comp ? "Competitive" : "Calm"} Mode</motion.button>
                  <motion.button whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }}
                    onClick={() => startMode(comp ? "calm" : "competitive")} className={`rounded-2xl px-6 py-3 font-bold border ${T.exit}`}>Switch to {comp ? "Calm 🌿" : "Competitive ⚡"}</motion.button>
                  <motion.button whileHover={{ scale: 1.03 }} whileTap={{ scale: 0.97 }}
                    onClick={goHome} className={`rounded-2xl px-6 py-3 font-bold border ${T.exit}`}>Home</motion.button>
                </div>
              </div>
            </motion.div>
          </div>
        )}

      </div>
    </div>
  );
}




